    const withSection14Confirm = (
      response,
      action
    ) => {
      const hadWindow =
        typeof window !== "undefined";

      const previousConfirm =
        hadWindow
          ? window.confirm
          : null;

      let confirmMessage = "";

      const confirmMock = (message) => {
        confirmMessage =
          String(message || "");

        return response;
      };

      if (hadWindow) {
        window.confirm = confirmMock;
      } else {
        globalThis.window = {
          confirm: confirmMock
        };
      }

      try {
        action();
      } finally {
        if (hadWindow) {
          window.confirm =
            previousConfirm;
        } else {
          delete globalThis.window;
        }
      }

      return confirmMessage;
    };

