// =====================================================
// CHARACTER CREATOR SECTION 5 — CREATOR STATE / DRAFT MANAGEMENT
// =====================================================

  const C = {
    screen: null,
    actionBar: null,
    grid: null,
    subtitle: null,
    status: null,

    newButton: null,
    saveButton: null,
    saveAsNewButton: null,
    copyJsonButton: null,
    exportJsonButton: null,
    importJsonInput: null,

    nameInput: null,
    raceInput: null,
    classInput: null,
    levelInput: null,
    imageInput: null,

    acInput: null,
    maxHpInput: null,
    currentHpInput: null,
    speedInput: null,

    strInput: null,
    dexInput: null,
    conInput: null,
    intInput: null,
    wisInput: null,
    chaInput: null,

    notesInput: null,
    libraryList: null
  };

  const creatorState = {
    viewMode: "library",
    currentStepId: "basics",
    currentStepIndex: 0,
    currentCharacterId: null,
    draft: createEmptyCharacter(),
    dirty: false,
    isSaving: false,
    busyAction: "",
    statusMessage: "Character creator foundation ready.",
    multiclassAddStatus: {
      message: "",
      tone: "warning"
    },
    pendingContainerRemovalId: "",
    openContainerId: "",
    showContainedItems: false,

    characterCache: [],
    characterRoomCode: null,
    characterUnsubscribe: null,

    roomClassCache: [],
    classRoomCode: null,
    classUnsubscribe: null,

    roomSpeciesCache: [],
    roomBackgroundCache: []
  };

  let characterSheetView = null;

  const DRAFT_AUTOSAVE_DEBOUNCE_MS = 600;

  const draftPersistenceRuntime = {
    timerId: null,
    targets: null
  };

  const CHARACTER_BUSY_ACTIONS = new Set([
    "new-character",
    "edit-character",
    "duplicate-character",
    "delete-character",
    "save-character",
    "finalize-character",
    "save-copy",
    "create-linked-token",
    "import-json-file",
    "import-json-text",
    "upload-portrait"
  ]);

  const CHARACTER_SAVE_BUSY_ACTIONS =
    new Set([
      "save-character",
      "finalize-character",
      "save-copy"
    ]);

  function getCharacterBusyLabel(
    action = creatorState.busyAction
  ) {
    switch (action) {
      case "new-character":
        return "Starting a new character";

      case "edit-character":
        return "Opening character";

      case "duplicate-character":
        return "Duplicating character";

      case "delete-character":
        return "Deleting character";

      case "save-copy":
        return "Saving character copy";

      case "finalize-character":
        return "Finalizing character";

      case "create-linked-token":
        return "Creating linked token";

      case "import-json-file":
      case "import-json-text":
        return "Importing character";

      case "upload-portrait":
        return "Uploading portrait";

      case "save-character":
      default:
        return "Saving character";
    }
  }

  function isCharacterCreatorBusy() {
    return Boolean(
      creatorState.busyAction ||
      creatorState.isSaving
    );
  }

  function isCharacterBusyAction(action) {
    return CHARACTER_BUSY_ACTIONS.has(
      String(action || "").trim()
    );
  }

  function blockCharacterBusyAction(action) {
    if (
      !isCharacterCreatorBusy() ||
      !isCharacterBusyAction(action)
    ) {
      return false;
    }

    setStatus(
      `${getCharacterBusyLabel()} is already in progress.`
    );

    if (typeof document !== "undefined") {
      renderCreatorView();
    }

    return true;
  }

  function beginCharacterBusyAction(action) {
    const cleanAction =
      String(action || "").trim();

    if (blockCharacterBusyAction(cleanAction)) {
      return false;
    }

    creatorState.busyAction =
      cleanAction;

    creatorState.isSaving =
      CHARACTER_SAVE_BUSY_ACTIONS.has(
        cleanAction
      );

    setStatus(
      `${getCharacterBusyLabel(cleanAction)}...`
    );

    if (typeof document !== "undefined") {
      renderCreatorView();
    }

    return true;
  }

  function endCharacterBusyAction(action) {
    const cleanAction =
      String(action || "").trim();

    if (
      !cleanAction ||
      creatorState.busyAction === cleanAction
    ) {
      creatorState.busyAction = "";
    }

    if (
      !creatorState.busyAction ||
      CHARACTER_SAVE_BUSY_ACTIONS.has(
        cleanAction
      )
    ) {
      creatorState.isSaving = false;
    }

    if (typeof document !== "undefined") {
      renderCreatorView();
    }
  }

  function refreshElements() {
    C.screen = $("characterCreatorScreen");

    C.actionBar = C.screen
      ? C.screen.querySelector(".creatorActionBar")
      : null;

    C.grid = C.screen
      ? C.screen.querySelector(".creatorFullGrid")
      : null;

    C.subtitle = C.screen
      ? C.screen.querySelector(".creatorTopBar .small")
      : null;

    C.status = $("characterCreatorStatus");

    C.newButton = $("newCharacterButton");
    C.saveButton = $("saveCharacterButton");
    C.saveAsNewButton = $("saveAsNewCharacterButton");
    C.copyJsonButton = $("copyCharacterJsonButton");
    C.exportJsonButton = $("exportCharacterJsonButton");
    C.importJsonInput = $("importCharacterJsonInput");

    C.nameInput = $("characterNameInput");
    C.raceInput = $("characterRaceInput");
    C.classInput = $("characterClassInput");
    C.levelInput = $("characterLevelInput");
    C.imageInput = $("characterImageUploadInput");

    C.acInput = $("characterAcInput");
    C.maxHpInput = $("characterMaxHpInput");
    C.currentHpInput = $("characterCurrentHpInput");
    C.speedInput = $("characterSpeedInput");

    C.strInput = $("characterStrInput");
    C.dexInput = $("characterDexInput");
    C.conInput = $("characterConInput");
    C.intInput = $("characterIntInput");
    C.wisInput = $("characterWisInput");
    C.chaInput = $("characterChaInput");

    C.notesInput = $("characterNotesInput");
    C.libraryList = $("characterLibraryList");
  }

  function setStatus(message) {
    creatorState.statusMessage = String(message || "");

    if (typeof document === "undefined") {
      return;
    }

    refreshElements();

    if (C.status) {
      C.status.textContent = creatorState.statusMessage;
    }
  }

  function makeSafeId(value, fallback = "custom") {
    const clean = String(value || fallback)
      .trim()
      .toLowerCase()
      .replace(/[^a-z0-9]+/g, "-")
      .replace(/^-+|-+$/g, "");

    return clean || fallback;
  }

  function makeSafeFileName(name) {
    return String(name || "character")
      .trim()
      .replace(/[^a-z0-9_-]/gi, "_")
      .replace(/_+/g, "_")
      .slice(0, 80) || "character";
  }

  function normalizeClassTemplate(
    rawClass,
    fallbackSource = "template"
  ) {
    const raw = rawClass || {};
    const name = cleanString(
      raw.name,
      "Custom Class"
    );
    const classId = makeSafeId(
      raw.id || name,
      "custom-class"
    );

    const skillChoices =
      raw.skillChoices ||
      {};

    return {
      schemaVersion: CLASS_SCHEMA_VERSION,
      ...getLegacy2014Metadata("class", classId, raw),

      id: classId,

      docId: raw.docId || null,
      name,

      source: cleanString(
        raw.source,
        fallbackSource
      ),

      summary: cleanString(
        raw.summary ||
        raw.description,
        "No summary yet."
      ),

      hitDie: cleanString(
        raw.hitDie,
        "d8"
      ),

      primaryAbilities: cleanArray(
        raw.primaryAbilities
      ),

      savingThrows: cleanArray(
        raw.savingThrows
      ),

      armorProficiencies: cleanArray(
        raw.armorProficiencies
      ),

      weaponProficiencies: cleanArray(
        raw.weaponProficiencies
      ),

      toolProficiencies: cleanArray(
        raw.toolProficiencies
      ),

      skillChoices: {
        choose: Math.max(
          0,
          Math.round(
            safeNumber(
              skillChoices.choose,
              0
            )
          )
        ),

        from: cleanArray(
          skillChoices.from
        )
      },

      multiclassPrerequisites:
        raw.multiclassPrerequisites &&
        typeof raw.multiclassPrerequisites === "object" &&
        !Array.isArray(raw.multiclassPrerequisites)
          ? cloneData(raw.multiclassPrerequisites)
          : {
              all: [],
              any: []
            },

      multiclassProficiencies:
        raw.multiclassProficiencies &&
        typeof raw.multiclassProficiencies === "object" &&
        !Array.isArray(raw.multiclassProficiencies)
          ? cloneData(raw.multiclassProficiencies)
          : {},

      subclassLevel: Math.max(
        1,
        Math.round(
          safeNumber(
            raw.subclassLevel,
            3
          )
        )
      ),

      spellcastingProgression:
        cleanString(
          raw.spellcastingProgression ||
          raw.progressionType,
          "none"
        ),

      progressionType:
        cleanString(
          raw.progressionType ||
          raw.spellcastingProgression,
          "none"
        ),

      spellcastingAbility:
        cleanString(
          raw.spellcastingAbility
        ),

      spellPreparation:
        cleanString(
          raw.spellPreparation,
          "none"
        ),

      cantripsKnown:
        raw.cantripsKnown &&
        typeof raw.cantripsKnown === "object" &&
        !Array.isArray(raw.cantripsKnown)
          ? cloneData(raw.cantripsKnown)
          : {},

      spellsKnown:
        raw.spellsKnown &&
        typeof raw.spellsKnown === "object" &&
        !Array.isArray(raw.spellsKnown)
          ? cloneData(raw.spellsKnown)
          : {},

      preparedSpellsFormula:
        raw.preparedSpellsFormula &&
        typeof raw.preparedSpellsFormula === "object" &&
        !Array.isArray(raw.preparedSpellsFormula)
          ? cloneData(raw.preparedSpellsFormula)
          : null,

      infusionsKnownByLevel:
        raw.infusionsKnownByLevel &&
        typeof raw.infusionsKnownByLevel === "object"
          ? cloneData(raw.infusionsKnownByLevel)
          : {},

      infusedItemsByLevel:
        raw.infusedItemsByLevel &&
        typeof raw.infusedItemsByLevel === "object"
          ? cloneData(raw.infusedItemsByLevel)
          : {},

      infusions:
        Array.isArray(raw.infusions)
          ? cloneData(raw.infusions)
          : [],

      levels:
        raw.levels &&
        typeof raw.levels === "object" &&
        !Array.isArray(raw.levels)
          ? cloneData(raw.levels)
          : {
              1: {
                proficiencyBonus: 2,
                features: []
              }
            },

      subclasses:
        Array.isArray(raw.subclasses)
          ? cloneData(raw.subclasses)
          : []
    };
  }

  function getAllClassTemplates() {
    const classMap = new Map();

    DEFAULT_CLASS_TEMPLATES.forEach((classData) => {
      const normalized = normalizeClassTemplate(
        classData,
        "template"
      );

      classMap.set(
        normalized.id,
        normalized
      );
    });

    creatorState.roomClassCache.forEach((classData) => {
      if (!isActiveRulesetEntry(classData)) {
        return;
      }

      const normalized = normalizeClassTemplate(
        classData,
        "homebrew"
      );

      classMap.set(
        normalized.id,
        normalized
      );
    });

    const primaryClass = getPrimaryClassEntry(
      creatorState.draft
    );

    if (
      primaryClass?.templateSnapshot &&
      isActiveRulesetEntry(primaryClass.templateSnapshot) &&
      !classMap.has(primaryClass.classId)
    ) {
      const normalized = normalizeClassTemplate(
        primaryClass.templateSnapshot,
        "character"
      );

      classMap.set(
        normalized.id,
        normalized
      );
    }

    return Array.from(classMap.values())
      .sort((a, b) => {
        if (
          a.source === "template" &&
          b.source !== "template"
        ) {
          return -1;
        }

        if (
          a.source !== "template" &&
          b.source === "template"
        ) {
          return 1;
        }

        return a.name.localeCompare(b.name);
      });
  }

  function getSelectedClassTemplate() {
    const primaryClass = getPrimaryClassEntry(
      creatorState.draft
    );

    if (
      !primaryClass ||
      (
        !cleanString(primaryClass.classId) &&
        !cleanString(primaryClass.className) &&
        !primaryClass.templateSnapshot
      )
    ) {
      return null;
    }

    const allClasses = getAllClassTemplates();

    return (
      allClasses.find((classData) => {
        return classData.id === primaryClass?.classId;
      }) ||

      allClasses.find((classData) => {
        return classData.name === primaryClass?.className;
      }) ||
      null
    );
  }

  function isMulticlassDraft(
    character = creatorState.draft
  ) {
    return (
      Array.isArray(
        character
          ?.classProgression
          ?.classes
      ) &&
      character
        .classProgression
        .classes
        .length > 1
    );
  }

  const MULTICLASS_PREREQUISITES =
    Object.freeze({
      artificer: Object.freeze([
        Object.freeze({ ability: "int", minimum: 13 })
      ]),
      barbarian: Object.freeze([
        Object.freeze({ ability: "str", minimum: 13 })
      ]),
      bard: Object.freeze([
        Object.freeze({ ability: "cha", minimum: 13 })
      ]),
      cleric: Object.freeze([
        Object.freeze({ ability: "wis", minimum: 13 })
      ]),
      druid: Object.freeze([
        Object.freeze({ ability: "wis", minimum: 13 })
      ]),
      fighter: Object.freeze([
        Object.freeze({
          any: Object.freeze([
            Object.freeze({ ability: "str", minimum: 13 }),
            Object.freeze({ ability: "dex", minimum: 13 })
          ])
        })
      ]),
      monk: Object.freeze([
        Object.freeze({ ability: "dex", minimum: 13 }),
        Object.freeze({ ability: "wis", minimum: 13 })
      ]),
      paladin: Object.freeze([
        Object.freeze({ ability: "str", minimum: 13 }),
        Object.freeze({ ability: "cha", minimum: 13 })
      ]),
      ranger: Object.freeze([
        Object.freeze({ ability: "dex", minimum: 13 }),
        Object.freeze({ ability: "wis", minimum: 13 })
      ]),
      rogue: Object.freeze([
        Object.freeze({ ability: "dex", minimum: 13 })
      ]),
      sorcerer: Object.freeze([
        Object.freeze({ ability: "cha", minimum: 13 })
      ]),
      warlock: Object.freeze([
        Object.freeze({ ability: "cha", minimum: 13 })
      ]),
      wizard: Object.freeze([
        Object.freeze({ ability: "int", minimum: 13 })
      ])
    });

  const MULTICLASS_PROFICIENCY_GRANTS =
    Object.freeze({
      artificer: Object.freeze({
        armor: Object.freeze([
          "Light Armor",
          "Medium Armor",
          "Shields"
        ]),
        weapons: Object.freeze([]),
        tools: Object.freeze([
          "Thieves' Tools",
          "Tinker's Tools"
        ])
      }),
      barbarian: Object.freeze({
        armor: Object.freeze([
          "Shields"
        ]),
        weapons: Object.freeze([
          "Simple Weapons",
          "Martial Weapons"
        ]),
        tools: Object.freeze([])
      }),
      bard: Object.freeze({
        armor: Object.freeze([
          "Light Armor"
        ]),
        weapons: Object.freeze([]),
        tools: Object.freeze([]),
        skillChoices: Object.freeze({
          choose: 1
        }),
        toolChoices: Object.freeze({
          choose: 1,
          label: "musical instrument"
        })
      }),
      cleric: Object.freeze({
        armor: Object.freeze([
          "Light Armor",
          "Medium Armor",
          "Shields"
        ]),
        weapons: Object.freeze([]),
        tools: Object.freeze([])
      }),
      druid: Object.freeze({
        armor: Object.freeze([
          "Light Armor",
          "Medium Armor",
          "Shields"
        ]),
        weapons: Object.freeze([]),
        tools: Object.freeze([])
      }),
      fighter: Object.freeze({
        armor: Object.freeze([
          "Light Armor",
          "Medium Armor",
          "Shields"
        ]),
        weapons: Object.freeze([
          "Simple Weapons",
          "Martial Weapons"
        ]),
        tools: Object.freeze([])
      }),
      monk: Object.freeze({
        armor: Object.freeze([]),
        weapons: Object.freeze([
          "Simple Weapons",
          "Shortswords"
        ]),
        tools: Object.freeze([])
      }),
      paladin: Object.freeze({
        armor: Object.freeze([
          "Light Armor",
          "Medium Armor",
          "Shields"
        ]),
        weapons: Object.freeze([
          "Simple Weapons",
          "Martial Weapons"
        ]),
        tools: Object.freeze([])
      }),
      ranger: Object.freeze({
        armor: Object.freeze([
          "Light Armor",
          "Medium Armor",
          "Shields"
        ]),
        weapons: Object.freeze([
          "Simple Weapons",
          "Martial Weapons"
        ]),
        tools: Object.freeze([]),
        skillChoices: Object.freeze({
          choose: 1
        })
      }),
      rogue: Object.freeze({
        armor: Object.freeze([
          "Light Armor"
        ]),
        weapons: Object.freeze([]),
        tools: Object.freeze([
          "Thieves' Tools"
        ]),
        skillChoices: Object.freeze({
          choose: 1
        })
      }),
      sorcerer: Object.freeze({
        armor: Object.freeze([]),
        weapons: Object.freeze([]),
        tools: Object.freeze([])
      }),
      warlock: Object.freeze({
        armor: Object.freeze([
          "Light Armor"
        ]),
        weapons: Object.freeze([
          "Simple Weapons"
        ]),
        tools: Object.freeze([])
      }),
      wizard: Object.freeze({
        armor: Object.freeze([]),
        weapons: Object.freeze([]),
        tools: Object.freeze([])
      })
    });

  function getMulticlassPrerequisiteRequirements(
    classId,
    template
  ) {
    const configured =
      template?.multiclassPrerequisites &&
      typeof template.multiclassPrerequisites === "object" &&
      !Array.isArray(template.multiclassPrerequisites)
        ? template.multiclassPrerequisites
        : {};

    const all = Array.isArray(configured.all)
      ? configured.all.filter(Boolean)
      : [];

    const any = Array.isArray(configured.any)
      ? configured.any.filter(Boolean)
      : [];

    const requirements = [
      ...all,
      ...(any.length
        ? [{ any }]
        : [])
    ];

    return requirements.length
      ? requirements
      : MULTICLASS_PREREQUISITES[classId] || [];
  }

  function getMulticlassClassId(
    classEntryOrId
  ) {
    if (typeof classEntryOrId === "string") {
      return makeSafeId(
        classEntryOrId,
        ""
      );
    }

    const template =
      resolveClassTemplateForEntry(
        classEntryOrId
      );

    return makeSafeId(
      classEntryOrId?.classId ||
      template?.id ||
      classEntryOrId?.className,
      ""
    );
  }

  function formatMulticlassRequirementItem(
    item
  ) {
    const abilityName =
      getSection13AbilityName(
        item?.ability
      );

    return `${abilityName} ${Math.max(
      1,
      Math.round(
        safeNumber(
          item?.minimum,
          13
        )
      )
    )}`;
  }

  function getMulticlassRequirementLabel(
    requirement
  ) {
    if (Array.isArray(requirement?.any)) {
      return requirement.any
        .map(formatMulticlassRequirementItem)
        .join(" or ");
    }

    return formatMulticlassRequirementItem(
      requirement
    );
  }

  function isMulticlassRequirementMet(
    requirement,
    character = creatorState.draft
  ) {
    const meetsItem = (item) => {
      return (
        getAbilityScore(
          character,
          item?.ability
        ) >=
        Math.max(
          1,
          Math.round(
            safeNumber(
              item?.minimum,
              13
            )
          )
        )
      );
    };

    if (Array.isArray(requirement?.any)) {
      return requirement.any.some(
        meetsItem
      );
    }

    return meetsItem(requirement);
  }

  function getMulticlassPrerequisiteResultForClass(
    classEntryOrId,
    character = creatorState.draft
  ) {
    const classId =
      getMulticlassClassId(
        classEntryOrId
      );

    const template =
      typeof classEntryOrId === "string"
        ? getAllClassTemplates().find((entry) => {
            return entry.id === classId;
          })
        : resolveClassTemplateForEntry(
            classEntryOrId
          );

    const className =
      safeDisplayString(
        template?.name,
        classId || "Class"
      );

    const requirements =
      getMulticlassPrerequisiteRequirements(
        classId,
        template
      );

    if (!requirements.length) {
      return {
        classId,
        className,
        met: true,
        label:
          "No listed multiclass prerequisite",
        failed: []
      };
    }

    const failed =
      requirements.filter((requirement) => {
        return !isMulticlassRequirementMet(
          requirement,
          character
        );
      });

    return {
      classId,
      className,
      met: failed.length === 0,
      label:
        requirements
          .map(getMulticlassRequirementLabel)
          .join(" and "),
      failed
    };
  }

  function getMulticlassPrerequisiteResults(
    character = creatorState.draft,
    extraClassId = ""
  ) {
    const seen = new Set();
    const entries = [
      ...getCharacterClassEntries(
        character
      ),
      cleanString(extraClassId)
    ].filter(Boolean);

    return entries
      .map((entry) => {
        const classId =
          getMulticlassClassId(entry);

        if (
          !classId ||
          seen.has(classId)
        ) {
          return null;
        }

        seen.add(classId);

        return getMulticlassPrerequisiteResultForClass(
          entry,
          character
        );
      })
      .filter(Boolean);
  }

  function formatMulticlassPrerequisiteFailure(
    result
  ) {
    return `${result.className} requires ${result.label}`;
  }

  function getMulticlassProficiencyRule(
    classEntry
  ) {
    const classId =
      getMulticlassClassId(
        classEntry
      );

    const template =
      resolveClassTemplateForEntry(
        classEntry
      );

    const configured =
      template?.multiclassProficiencies &&
      typeof template.multiclassProficiencies === "object" &&
      !Array.isArray(template.multiclassProficiencies)
        ? template.multiclassProficiencies
        : null;

    if (
      configured &&
      Object.keys(configured).length
    ) {
      return {
        armor: cleanArray(
          configured.armor ||
          configured.armorProficiencies
        ),
        weapons: cleanArray(
          configured.weapons ||
          configured.weaponProficiencies
        ),
        tools: cleanArray(
          configured.tools ||
          configured.toolProficiencies
        ),
        skillChoices: {
          choose: Math.max(
            0,
            Math.round(
              safeNumber(
                configured.skillChoices?.choose,
                0
              )
            )
          ),
          from: cleanArray(
            configured.skillChoices?.from
          )
        },
        toolChoices: {
          choose: Math.max(
            0,
            Math.round(
              safeNumber(
                configured.toolChoices?.choose,
                0
              )
            )
          ),
          label: cleanString(
            configured.toolChoices?.label,
            "tool proficiency"
          ),
          from: cleanArray(
            configured.toolChoices?.from
          )
        }
      };
    }

    return (
      MULTICLASS_PROFICIENCY_GRANTS[
        classId
      ] || {
        armor: [],
        weapons: [],
        tools: []
      }
    );
  }

  function getMulticlassSummaryEntries(
    character = creatorState.draft
  ) {
    return getCharacterClassEntries(character)
      .map((classEntry, index) => {
        const template =
          resolveClassTemplateForEntry(
            classEntry
          );

        const className =
          safeDisplayString(
            classEntry?.className,
            safeDisplayString(
              template?.name,
              `Class ${index + 1}`
            )
          );

        return {
          classEntry,
          template,
          className,
          classLevel:
            Math.max(
              0,
              Math.round(
                safeNumber(
                  classEntry?.level,
                  0
                )
              )
            ),
          subclassName:
            safeDisplayString(
              classEntry?.subclassName,
              ""
            ),
          hitDie: formatClassEntryHitDie(
            classEntry,
            template
          ),
          source:
            safeDisplayString(
              classEntry?.source,
              safeDisplayString(
                template?.source,
                "character"
              )
            ),
          primaryAbilities:
            formatSection12List(
              template?.primaryAbilities ||
              classEntry?.primaryAbilities
            ) ||
            "Not specified",
          savingThrows:
            formatSection12List(
              template?.savingThrows ||
              classEntry?.savingThrows
            ) ||
            "Not specified",
          subclassLevel:
            Math.max(
              1,
              Math.round(
                safeNumber(
                  template?.subclassLevel ||
                  classEntry?.subclassLevel,
                  3
                )
              )
            )
        };
      });
  }

  function formatMulticlassStoredChoiceKey(key) {
    const labels = {
      classFeatures: "Class Features",
      fightingStyle: "Fighting Style",
      skillProficiencyIds: "Skill Proficiencies",
      spellbook: "Spellbook",
      toolProficiencyChoices: "Tool Proficiencies"
    };

    if (labels[key]) {
      return labels[key];
    }

    const spaced = cleanString(key)
      .replace(/Ids$/i, "")
      .replace(/([a-z0-9])([A-Z])/g, "$1 $2")
      .replace(/[-_]+/g, " ")
      .trim();

    return spaced
      ? `${spaced.charAt(0).toUpperCase()}${spaced.slice(1)}`
      : "Choice";
  }

  function formatMulticlassStoredChoiceValue(value) {
    if (Array.isArray(value)) {
      return value
        .map((item) => {
          return formatMulticlassStoredChoiceValue(
            item
          );
        })
        .filter(Boolean)
        .join(", ");
    }

    if (
      value &&
      typeof value === "object"
    ) {
      return Object.entries(value)
        .filter(([key]) => {
          return ![
            "subclassSnapshot",
            "templateSnapshot",
            "classSnapshot"
          ].includes(key);
        })
        .map(([key, entryValue]) => {
          const formattedValue =
            formatMulticlassStoredChoiceValue(
              entryValue
            );

          return formattedValue
            ? `${formatMulticlassStoredChoiceKey(key)}: ${formattedValue}`
            : "";
        })
        .filter((text) => {
          return cleanString(text);
        })
        .join("; ");
    }

    return safeDisplayString(value, "");
  }

  function renderMulticlassStoredChoices(
    classEntry
  ) {
    const groups = [
      [
        "Choices",
        classEntry?.choices
      ],
      [
        "Level Choices",
        classEntry?.levelChoices
      ],
      [
        "Selections",
        classEntry?.selections
      ],
      [
        "Class Features",
        classEntry?.features
      ]
    ].map(([label, value]) => {
      return [
        label,
        formatMulticlassStoredChoiceValue(
          value
        )
      ];
    }).filter(([, value]) => {
      return cleanString(value);
    });

    if (!groups.length) {
      return "";
    }

    return `
      <p>
        <b>Stored Class Choices:</b>
      </p>

      <ul>
        ${groups
          .map(([label, formattedValue]) => {
            return `
              <li>
                ${escapeHtml(label)}:
                ${escapeHtml(
                  formattedValue
                )}
              </li>
            `;
          })
          .join("")}
      </ul>
    `;
  }

  function renderMulticlassReadOnlyNotice(
    contextLabel = "class and level"
  ) {
    return `
      <div class="hg-character-warning">
        <b>Multiclass editing:</b>
        Use the class progression controls to update ${escapeHtml(contextLabel)}.
        Full class-feature choice automation is still limited.
      </div>
    `;
  }

  function adjustSelectedFeatResource(resourceId, delta) {
    const resources = Array.isArray(
      creatorState.draft.featMechanics?.resources
    )
      ? creatorState.draft.featMechanics.resources
      : [];
    const resourceEntry = resources.find((entry) => {
      return entry.id === cleanString(resourceId);
    });

    if (!resourceEntry) {
      return false;
    }

    resourceEntry.currentUses = Math.max(
      0,
      Math.min(
        safeNumber(resourceEntry.maximumUses, 0),
        safeNumber(resourceEntry.currentUses, 0) +
          Math.sign(safeNumber(delta, 0))
      )
    );
    applyCompatibilityAliases(creatorState.draft);
    markDraftChanged();

    return true;
  }

  function adjustSelectedClassResource(resourceId, delta) {
    const resources = Array.isArray(
      creatorState.draft.classMechanics?.resources
    )
      ? creatorState.draft.classMechanics.resources
      : [];
    const resourceEntry = resources.find((entry) => {
      return entry.id === cleanString(resourceId);
    });

    if (
      !resourceEntry ||
      resourceEntry.maximumUses === null
    ) {
      return false;
    }

    resourceEntry.currentUses = Math.max(
      0,
      Math.min(
        safeNumber(resourceEntry.maximumUses, 0),
        safeNumber(resourceEntry.currentUses, 0) +
          Math.sign(safeNumber(delta, 0))
      )
    );
    applyCompatibilityAliases(creatorState.draft);
    markDraftChanged();

    return true;
  }

  function toggleSection12RageState(resourceId) {
    const resources = Array.isArray(
      creatorState.draft.classMechanics?.resources
    )
      ? creatorState.draft.classMechanics.resources
      : [];
    const rageResource = resources.find((entry) => {
      return (
        entry.id === cleanString(resourceId) &&
        entry.canonicalId === "rage"
      );
    });

    if (!rageResource) {
      return false;
    }

    creatorState.draft.combat.classFeatureStates = {
      ...(creatorState.draft.combat.classFeatureStates || {})
    };

    const currentlyActive =
      creatorState.draft.combat
        .classFeatureStates.rageActive === true;

    if (
      !currentlyActive &&
      rageResource.maximumUses !== null &&
      safeNumber(rageResource.currentUses, 0) <= 0
    ) {
      return false;
    }

    if (
      !currentlyActive &&
      rageResource.maximumUses !== null
    ) {
      rageResource.currentUses = Math.max(
        0,
        safeNumber(rageResource.currentUses, 0) - 1
      );
    }

    creatorState.draft.combat
      .classFeatureStates.rageActive =
        !currentlyActive;

    applySelectedClassFeatureMechanics();
    applyCompatibilityAliases(creatorState.draft);
    markDraftChanged();

    return true;
  }

  function getSection12SpellSlotUsageState(
    character = creatorState.draft
  ) {
    character.magic = character.magic || {};
    character.magic.slotUsage =
      character.magic.slotUsage &&
      typeof character.magic.slotUsage === "object"
        ? character.magic.slotUsage
        : { normal: {}, pact: 0 };
    character.magic.slotUsage.normal =
      character.magic.slotUsage.normal &&
      typeof character.magic.slotUsage.normal === "object"
        ? character.magic.slotUsage.normal
        : {};

    const normal = Object.fromEntries(
      Object.entries(character.magic.slots || {})
        .filter(([level, maximum]) => {
          return safeNumber(level, 0) > 0 && safeNumber(maximum, 0) > 0;
        })
        .map(([level, maximum]) => {
          const cleanMaximum = Math.max(0, safeNumber(maximum, 0));
          const used = Math.min(
            cleanMaximum,
            Math.max(
              0,
              safeNumber(
                character.magic.slotUsage.normal[level],
                0
              )
            )
          );
          character.magic.slotUsage.normal[level] = used;

          return [level, {
            level: safeNumber(level, 0),
            maximum: cleanMaximum,
            used,
            remaining: cleanMaximum - used
          }];
        })
    );
    const pactMaximum = Math.max(
      0,
      safeNumber(character.magic.pactMagic?.slots, 0)
    );
    const pactUsed = Math.min(
      pactMaximum,
      Math.max(
        0,
        safeNumber(character.magic.slotUsage.pact, 0)
      )
    );
    character.magic.slotUsage.pact = pactUsed;

    return {
      normal,
      pact: {
        level: Math.max(
          0,
          safeNumber(character.magic.pactMagic?.slotLevel, 0)
        ),
        maximum: pactMaximum,
        used: pactUsed,
        remaining: pactMaximum - pactUsed
      }
    };
  }

  function adjustSection12SpellSlotUsage(
    kind,
    level,
    delta
  ) {
    const state = getSection12SpellSlotUsageState();
    const change = Math.sign(safeNumber(delta, 0));

    if (kind === "pact") {
      if (!state.pact.maximum) {
        return false;
      }

      creatorState.draft.magic.slotUsage.pact = Math.max(
        0,
        Math.min(
          state.pact.maximum,
          state.pact.used + change
        )
      );
    } else {
      const slot = state.normal[String(level)];

      if (!slot) {
        return false;
      }

      creatorState.draft.magic.slotUsage.normal[String(level)] =
        Math.max(
          0,
          Math.min(
            slot.maximum,
            slot.used + change
          )
        );
    }

    applyCompatibilityAliases(creatorState.draft);
    markDraftChanged();
    return true;
  }

  function renderSection12DivineSmiteSlotUsage(
    character,
    options = {}
  ) {
    const readonly =
      options.readonly === true;
    const hasDivineSmite = (
      Array.isArray(character?.classMechanics?.combatProfiles)
        ? character.classMechanics.combatProfiles
        : []
    ).some((profile) => profile.type === "divineSmite");

    if (!hasDivineSmite) {
      return "";
    }

    const usage = getSection12SpellSlotUsageState(character);
    const normalSlots = Object.values(usage.normal);
    const slotCards = [
      ...normalSlots.map((slot) => ({
        kind: "normal",
        level: slot.level,
        label: `Level ${slot.level} slot`,
        maximum: slot.maximum,
        used: slot.used,
        remaining: slot.remaining
      })),
      ...(
        usage.pact.maximum > 0
          ? [{
              kind: "pact",
              level: usage.pact.level,
              label: `Pact slot (level ${usage.pact.level})`,
              maximum: usage.pact.maximum,
              used: usage.pact.used,
              remaining: usage.pact.remaining
            }]
          : []
      )
    ];

    if (!slotCards.length) {
      return `<p class="small">Divine Smite is available, but this character currently has no spell slots to spend.</p>`;
    }

    return `
      <h4>Divine Smite Slot Usage</h4>
      <div class="hg-character-choice-grid">
        ${slotCards.map((slot) => {
          const smiteDice = Math.min(5, slot.level + 1);

          return `
            <article class="hg-character-choice-card">
              <h3>${escapeHtml(slot.label)}</h3>
              <p class="small">
                Remaining ${slot.remaining} / ${slot.maximum}
                <br>Smite damage: ${smiteDice}d8${smiteDice < 5 ? "" : " (maximum before creature-type bonus)"}
              </p>
              ${readonly
                ? ""
                : `
                  <div class="hg-character-inline-actions">
                    <button
                      type="button"
                      data-cc-action="adjust-divine-smite-slot"
                      data-slot-kind="${slot.kind}"
                      data-slot-level="${slot.level}"
                      data-delta="1"
                      ${slot.remaining <= 0 ? "disabled" : ""}
                    >Spend for Smite</button>
                    <button
                      type="button"
                      data-cc-action="adjust-divine-smite-slot"
                      data-slot-kind="${slot.kind}"
                      data-slot-level="${slot.level}"
                      data-delta="-1"
                      ${slot.used <= 0 ? "disabled" : ""}
                    >Restore Slot</button>
                  </div>
                `}
            </article>
          `;
        }).join("")}
      </div>
    `;
  }

  function formatSelectedClassMechanicEffect(effect) {
    if (!effect) {
      return "";
    }

    if (effect.summary) {
      return effect.summary;
    }

    if (effect.type === "sneakAttack") {
      return `Sneak Attack ${getProgressionValueByLevel(
        effect.diceByLevel,
        effect.classLevel,
        "1d6"
      )}, once per turn with an eligible finesse or ranged attack.`;
    }

    if (effect.type === "rage") {
      return `Rage adds +${getProgressionValueByLevel(
        effect.damageBonusByLevel,
        effect.classLevel,
        2
      )} Strength-melee damage and grants its recorded resistances while its restrictions are met.`;
    }

    if (effect.type === "martialArts") {
      return `Martial Arts die ${getProgressionValueByLevel(
        effect.dieByLevel,
        effect.classLevel,
        "d4"
      )}; eligible attacks may use Dexterity.`;
    }

    if (effect.type === "wildShape") {
      return `Wild Shape maximum CR ${getProgressionValueByLevel(
        effect.maxCrByLevel,
        effect.classLevel,
        "1/4"
      )}; duration ${Math.max(
        1,
        Math.floor(safeNumber(effect.classLevel, 2) / 2)
      )} hour(s).`;
    }

    if (effect.type === "divineSmite") {
      return "Divine Smite spends one spell slot after an eligible melee weapon hit; damage scales with slot level.";
    }

    if (effect.type === "metamagic") {
      return "Selected Metamagic options spend Sorcery Points using their listed costs.";
    }

    if (effect.type === "maneuverSaveDc") {
      const abilityModifier = Math.max(
        calculateAbilityModifier(
          getAbilityScore(creatorState.draft, "str")
        ),
        calculateAbilityModifier(
          getAbilityScore(creatorState.draft, "dex")
        )
      );
      return `Maneuver save DC ${8 + getCharacterProficiencyBonus(creatorState.draft) + abilityModifier}.`;
    }

    if (effect.type === "armorClassFormula") {
      const abilities = uniqueCleanArray(
        effect.abilities
      ).map((ability) => {
        return String(ability).toUpperCase();
      });

      return `${effect.featureName}: ${safeNumber(effect.base, 10)}${abilities.length ? ` + ${abilities.join(" + ")}` : ""}. Select this formula separately; unarmored formulas do not stack.`;
    }

    return cleanString(
      effect.option
        ? `${effect.featureName}: ${effect.option}`
        : effect.featureName
    );
  }

  function renderSelectedClassMechanicsSummary(
    character = creatorState.draft,
    options = {}
  ) {
    const readonly =
      options.readonly === true;
    const mechanics = character?.classMechanics || {};
    const resources = Array.isArray(mechanics.resources)
      ? mechanics.resources
      : [];
    const effectLines = [
      ...(Array.isArray(mechanics.combatProfiles)
        ? mechanics.combatProfiles
        : []),
      ...(Array.isArray(mechanics.passiveEffects)
        ? mechanics.passiveEffects
        : []),
      ...(Array.isArray(mechanics.attackModifiers)
        ? mechanics.attackModifiers
        : []),
      ...(Array.isArray(mechanics.armorClassModifiers)
        ? mechanics.armorClassModifiers
        : []),
      ...(Array.isArray(mechanics.armorClassFormulas)
        ? mechanics.armorClassFormulas
        : []),
      ...(Array.isArray(mechanics.spellModifiers)
        ? mechanics.spellModifiers
        : [])
    ]
      .map(formatSelectedClassMechanicEffect)
      .filter(Boolean)
      .filter((line, index, values) => {
        return values.indexOf(line) === index;
      });
    const restrictionEntries = Array.isArray(mechanics.restrictions)
      ? mechanics.restrictions
      : [];
    const restrictions = restrictionEntries.map((entry) => {
      const labels = {
        cannotCastSpells: "Cannot cast spells while this state is active",
        cannotConcentrate: "Cannot concentrate on spells while this state is active"
      };
      const label = labels[entry.restriction] || entry.restriction;
      return entry.active === true
        ? `ACTIVE: ${label}`
        : label;
    });
    const attacksPerAction = Math.max(
      1,
      safeNumber(
        mechanics.attackAction?.attacks,
        1
      )
    );
    const attackActionLine = attacksPerAction > 1
      ? `Attacks per Attack action: ${attacksPerAction}. Extra Attack features do not stack; the highest available version is used.`
      : "";

    if (
      !resources.length &&
      !effectLines.length &&
      !attackActionLine &&
      !restrictions.length
    ) {
      return "";
    }

    return `
      <h3>Class Feature Mechanics</h3>
      ${resources.length
        ? `
          <div class="hg-character-choice-grid">
            ${resources.map((resourceEntry) => {
              const unlimited = resourceEntry.maximumUses === null;

              return `
                <article class="hg-character-choice-card">
                  <h3>${escapeHtml(resourceEntry.name)}</h3>
                  <p class="small">
                    ${escapeHtml(resourceEntry.className)}
                    ${resourceEntry.shared ? "<br>Shared multiclass pool" : ""}
                    ${resourceEntry.die ? `<br>Die: ${escapeHtml(resourceEntry.die)}` : ""}
                    ${resourceEntry.recharge ? `<br>Recharges: ${escapeHtml(formatSection12Recharge(resourceEntry.recharge))}` : ""}
                  </p>
                  <div class="hg-character-current-choice">
                    <b>Available:</b>
                    ${unlimited
                      ? "Unlimited"
                      : `${safeNumber(resourceEntry.currentUses, 0)} / ${safeNumber(resourceEntry.maximumUses, 0)}`}
                    ${unlimited || readonly
                      ? ""
                      : `
                        <div class="hg-character-inline-actions">
                          <button
                            type="button"
                            data-cc-action="adjust-class-resource"
                            data-resource-id="${escapeHtml(resourceEntry.id)}"
                            data-delta="-1"
                            ${safeNumber(resourceEntry.currentUses, 0) <= 0 ? "disabled" : ""}
                          >Spend</button>
                          <button
                            type="button"
                            data-cc-action="adjust-class-resource"
                            data-resource-id="${escapeHtml(resourceEntry.id)}"
                            data-delta="1"
                            ${safeNumber(resourceEntry.currentUses, 0) >= safeNumber(resourceEntry.maximumUses, 0) ? "disabled" : ""}
                          >Restore</button>
                        </div>
                      `}
                  </div>
                  ${
                    resourceEntry.canonicalId === "rage" &&
                    !readonly
                      ? `
                        <div class="hg-character-inline-actions">
                          <button
                            type="button"
                            data-cc-action="toggle-rage-state"
                            data-resource-id="${escapeHtml(resourceEntry.id)}"
                            ${
                              character?.combat?.classFeatureStates?.rageActive === true ||
                              safeNumber(resourceEntry.currentUses, 0) > 0
                                ? ""
                                : "disabled"
                            }
                          >${
                            character?.combat?.classFeatureStates?.rageActive === true
                              ? "End Rage"
                              : "Begin Rage (spend 1)"
                          }</button>
                        </div>
                      `
                      : ""
                  }
                </article>
              `;
            }).join("")}
          </div>
        `
        : ""}

      ${renderSection12DivineSmiteSlotUsage(
        character,
        options
      )}

      ${mechanics.spellcastingBlocked
        ? `
          <div class="hg-character-warning">
            <b>Spellcasting blocked:</b> Rage is active. End Rage before casting or concentrating on a spell.
          </div>
        `
        : ""}

      ${attackActionLine || effectLines.length
        ? `
          <ul class="small">
            ${attackActionLine ? `<li>${escapeHtml(attackActionLine)}</li>` : ""}
            ${effectLines.map((line) => `<li>${escapeHtml(line)}</li>`).join("")}
          </ul>
        `
        : ""}
      ${restrictions.length
        ? `<p class="small"><b>Conditional restrictions:</b> ${escapeHtml(restrictions.join("; "))}</p>`
        : ""}
    `;
  }

  function renderSelectedFeatSummary(
    character = creatorState.draft,
    options = {}
  ) {
    const readonly =
      options.readonly === true;
    const instances = getSelectedDefaultFeatInstances(character);
    const resources = Array.isArray(character?.featMechanics?.resources)
      ? character.featMechanics.resources
      : [];

    if (!instances.length) {
      return "";
    }

    return `
      <h3>Feats</h3>
      <div class="hg-character-choice-grid">
        ${instances.map((instance) => {
          const featResources = resources.filter((entry) => {
            return entry.id.startsWith(`${instance.id}:`);
          });
          const choiceSummaries = (Array.isArray(instance.feat.choices)
            ? instance.feat.choices
            : []
          ).map((featChoice) => {
            const values = uniqueCleanArray(
              instance.featChoices?.[featChoice.id]
            ).map((value) => {
              return DEFAULT_SPELLS.find((spell) => spell.id === value)?.name || value;
            });

            return values.length
              ? `${featChoice.label || featChoice.id}: ${values.join(", ")}`
              : "";
          }).filter(Boolean);

          return `
            <article class="hg-character-choice-card">
              <h3>${escapeHtml(instance.feat.name)}</h3>
              <p>
                ${escapeHtml(instance.feat.summary || "")}
                <br><span class="small">${escapeHtml(instance.feat.description || "")}</span>
              </p>

              ${choiceSummaries.length
                ? `<ul class="small">${choiceSummaries.map((summary) => {
                    return `<li>${escapeHtml(summary)}</li>`;
                  }).join("")}</ul>`
                : ""}

              ${featResources.map((resourceEntry) => {
                return `
                  <div class="hg-character-current-choice">
                    <b>${escapeHtml(resourceEntry.name)}:</b>
                    ${safeNumber(resourceEntry.currentUses, 0)} /
                    ${safeNumber(resourceEntry.maximumUses, 0)}
                    <br><span class="small">Recharges: ${escapeHtml(resourceEntry.recharge)}</span>
                    ${readonly
                      ? ""
                      : `
                        <div class="hg-character-inline-actions">
                          <button
                            type="button"
                            data-cc-action="adjust-feat-resource"
                            data-resource-id="${escapeHtml(resourceEntry.id)}"
                            data-delta="-1"
                            ${safeNumber(resourceEntry.currentUses, 0) <= 0 ? "disabled" : ""}
                          >Spend</button>
                          <button
                            type="button"
                            data-cc-action="adjust-feat-resource"
                            data-resource-id="${escapeHtml(resourceEntry.id)}"
                            data-delta="1"
                            ${safeNumber(resourceEntry.currentUses, 0) >= safeNumber(resourceEntry.maximumUses, 0) ? "disabled" : ""}
                          >Restore</button>
                        </div>
                      `}
                  </div>
                `;
              }).join("")}
            </article>
          `;
        }).join("")}
      </div>
    `;
  }

  function renderMulticlassClassSummary(
    character = creatorState.draft
  ) {
    const entries =
      getMulticlassSummaryEntries(character);

    if (entries.length <= 1) {
      return "";
    }

    const totalLevel =
      entries.reduce(
        (sum, entry) => {
          return sum + entry.classLevel;
        },
        0
      );

    const classSplit = entries
      .map((entry) => {
        return `${entry.className} ${entry.classLevel}`;
      })
      .join(" / ");

    const proficiencyBonus =
      getGenericProficiencyBonus(
        totalLevel || 1
      );

    return `
      <h3>Multiclass Summary</h3>

      <div class="hg-character-current-choice">
        <b>Total Character Level:</b>
        ${clampLevel(
          character
            ?.classProgression
            ?.totalLevel ||
          totalLevel ||
          1
        )}

        <br>

        <b>Class Split:</b>
        ${escapeHtml(classSplit)}

        <br>

        <b>Proficiency Bonus:</b>
        +${proficiencyBonus}
      </div>

      <div class="hg-character-choice-grid">
        ${entries
          .map((entry, index) => {
            const prerequisiteResult =
              getMulticlassPrerequisiteResultForClass(
                entry.classEntry,
                character
              );

            const proficiencySummary =
              formatClassEntryProficiencySummary(
                entry.classEntry,
                index,
                character
              );

            const isStartingClass =
              isStartingClassEntry(
                entry.classEntry,
                character,
                index
              );

            return `
              <article class="hg-character-choice-card">
                <h3>
                  ${escapeHtml(entry.className)}
                  ${entry.classLevel}
                  ${
                    entry.subclassName
                      ? ` &mdash; ${escapeHtml(entry.subclassName)}`
                      : ""
                  }
                </h3>

                <p>
                  <b>Subclass:</b>
                  ${escapeHtml(
                    entry.subclassName ||
                    (
                      entry.classLevel >= entry.subclassLevel
                        ? "Not selected"
                        : `Unlocks at level ${entry.subclassLevel}`
                    )
                  )}

                  <br>

                  <b>Hit Die:</b>
                  ${escapeHtml(entry.hitDie)}

                  <br>

                  <b>Primary Abilities:</b>
                  ${escapeHtml(
                    entry.primaryAbilities
                  )}

                  <br>

                  <b>Proficiency Source:</b>
                  ${escapeHtml(
                    isStartingClass
                      ? "Starting class (includes saving throws)"
                      : "Multiclass grant (no saving throws)"
                  )}

                  <br>

                  <b>Granted Proficiencies:</b>
                  ${escapeHtml(proficiencySummary)}

                  <br>

                  <b>Multiclass Prerequisite:</b>
                  ${escapeHtml(prerequisiteResult.label)}
                  ${prerequisiteResult.met ? "&#10003;" : "&#9888;"}

                  <br>

                  <b>Subclass Unlock:</b>
                  Level ${entry.subclassLevel}

                  <br>

                  <b>Source:</b>
                  ${escapeHtml(entry.source)}
                </p>

                ${renderMulticlassStoredChoices(
                  entry.classEntry
                )}
              </article>
            `;
          })
          .join("")}
      </div>
    `;
  }

  function renderMulticlassAdvancementChoiceSummary(
    character = creatorState.draft
  ) {
    const slots =
      getUnlockedFeatChoiceSlots(
        character
      );

    if (!slots.length) {
      return "";
    }

    return `
      <h3>ASI / Feat Choices</h3>

      <div class="hg-character-choice-grid">
        ${slots
          .map((slot) => {
            const feat =
              DEFAULT_FEATS.find((entry) => {
                return entry.id === slot.selectedFeatId;
              });

            const selection =
              slot.selectedMode === "feat"
                ? feat?.name || slot.selectedFeatId || "Pending feat selection"
                : slot.selectedMode === "asi"
                  ? "Ability Score Improvement"
                  : "Pending ASI or feat choice";
            const featChoiceSummary = feat
              ? (Array.isArray(feat.choices) ? feat.choices : [])
                  .map((featChoice) => {
                    const values = uniqueCleanArray(
                      slot.featChoices?.[featChoice.id]
                    ).map((value) => {
                      return DEFAULT_SPELLS.find((spell) => spell.id === value)?.name || value;
                    });

                    return values.length
                      ? `${featChoice.label || featChoice.id}: ${values.join(", ")}`
                      : "";
                  })
                  .filter(Boolean)
              : [];

            return `
              <article class="hg-character-choice-card">
                <h3>
                  ${escapeHtml(slot.className)} level ${slot.classLevel}
                </h3>

                <p>
                  <b>Choice:</b>
                  ${escapeHtml(selection)}
                  ${feat
                    ? `
                      <br>${escapeHtml(feat.summary || "")}
                      <br><span class="small">${escapeHtml(feat.description || "")}</span>
                    `
                    : ""}
                </p>

                ${featChoiceSummary.length
                  ? `
                    <ul class="small">
                      ${featChoiceSummary.map((summary) => {
                        return `<li>${escapeHtml(summary)}</li>`;
                      }).join("")}
                    </ul>
                  `
                  : ""}
              </article>
            `;
          })
          .join("")}
      </div>
    `;
  }

  function renderMulticlassLevelBreakdown(
    character = creatorState.draft,
    options = {}
  ) {
    const readonly =
      options.readonly === true;
    const records =
      getCharacterLevelHitDieRecords(character);

    if (records.length <= 1) {
      return "";
    }

    const classLevelCounts = {};

    const levelRecords =
      records.map((record, index) => {
        const classKey =
          record.classEntryId ||
          record.classId ||
          record.className ||
          "class";

        classLevelCounts[classKey] =
          (classLevelCounts[classKey] || 0) + 1;

        return {
          ...record,
          classLevel:
            record.classLevel ||
            classLevelCounts[classKey],
          levelIndex: index
        };
      });

    const levelOrderSummary =
      levelRecords
        .map((record) => {
          return `${
            record.className ||
            "Class"
          } ${record.classLevel}`;
        })
        .join(", ");

    const levelRows =
      levelRecords
        .map((record) => {
          return `
            <div class="hg-character-level-order-row">
              <div class="hg-character-level-order-label">
                <span>
                  Character Level ${record.characterLevel}
                </span>

                <strong>
                  ${escapeHtml(
                    record.className ||
                    "Class"
                  )}
                  ${record.classLevel}
                </strong>

                <span>
                  ${escapeHtml(
                    record.hitDie ||
                    "d8"
                  )}
                </span>
              </div>

              <div class="hg-character-level-order-actions">
                <button
                  type="button"
                  data-cc-action="move-character-level-order"
                  data-level-index="${record.levelIndex}"
                  data-delta="-1"
                  ${record.levelIndex <= 0 ? "disabled" : ""}
                >
                  Move Earlier
                </button>

                <button
                  type="button"
                  data-cc-action="move-character-level-order"
                  data-level-index="${record.levelIndex}"
                  data-delta="1"
                  ${record.levelIndex >= records.length - 1 ? "disabled" : ""}
                >
                  Move Later
                </button>
              </div>
            </div>
          `;
        })
        .join("");

    return `
      <h3>Level-by-Level Class Order</h3>

      <div class="hg-character-current-choice">
        <b>Level order:</b>
        ${escapeHtml(levelOrderSummary)}

        <br>

        <span class="small">
          Advanced: this controls HP and hit dice when multiclassing. Most players do not need to change it.
        </span>
      </div>

      ${
        readonly
          ? ""
          : `
            <details class="hg-character-level-order-details">
              <summary>Show Advanced Level Order</summary>

              <div class="hg-character-level-order-rows">
                ${levelRows}
              </div>
            </details>
          `
      }
    `;
  }

  function getClassIndexForLevelRecord(
    levelRecord,
    character = creatorState.draft
  ) {
    const classEntries =
      getClassProgressionEntries(
        character
      );

    const recordEntryId = cleanString(
      levelRecord?.classEntryId ||
        levelRecord?.entryId
    );
    const recordClassId = makeSafeId(
      levelRecord?.classId ||
        levelRecord?.className,
      ""
    );

    return classEntries.findIndex(
      (classEntry, index) => {
        const key =
          getClassProgressionEntryKey(
            classEntry,
            index
          );

        return (
          key === recordEntryId ||
          makeSafeId(
            classEntry.classId ||
            classEntry.className,
            ""
          ) === recordClassId
        );
      }
    );
  }

  function getLatestLevelUpContext(
    character = creatorState.draft
  ) {
    const records =
      getCharacterLevelHitDieRecords(
        character
      );

    const levelRecord =
      records[records.length - 1] ||
      null;

    if (!levelRecord) {
      return null;
    }

    const classIndex =
      Math.max(
        0,
        getClassIndexForLevelRecord(
          levelRecord,
          character
        )
      );

    const classEntry =
      getClassEntryAtIndex(
        classIndex,
        character
      );

    const template =
      resolveClassTemplateForEntry(
        classEntry
      );

    if (!classEntry || !template) {
      return null;
    }

    const classFeatures =
      collectSection12FeaturesForClassEntry(
        classEntry,
        classIndex
      ).filter((feature) => {
        return (
          Math.round(
            safeNumber(feature.level, 0)
          ) === levelRecord.classLevel
        );
      });

    const subclassOptions =
      (
        Array.isArray(template.subclasses)
          ? template.subclasses
          : []
      ).map((subclass) => {
        return normalizeSection12Subclass(
          subclass,
          template.source || "template"
        );
      });

    const subclassLevel =
      Math.max(
        1,
        Math.round(
          safeNumber(
            template.subclassLevel ||
            classEntry.subclassLevel,
            3
          )
        )
      );

    const asiSlot =
      getUnlockedFeatChoiceSlots(
        character
      ).find((slot) => {
        return (
          cleanString(slot.classEntryId) ===
            getClassProgressionEntryKey(
              classEntry,
              classIndex
            ) &&
          safeNumber(slot.classLevel, 0) ===
            levelRecord.classLevel
        );
      }) ||
      null;

    return {
      levelRecord,
      classIndex,
      classEntry,
      template,
      classFeatures,
      subclassOptions,
      subclassLevel,
      asiSlot
    };
  }

  function renderLatestLevelSubclassUnlock(
    context
  ) {
    if (
      !context ||
      !context.subclassOptions.length ||
      context.levelRecord.classLevel !==
        context.subclassLevel
    ) {
      return "";
    }

    const selectedSubclass =
      getClassEntrySubclassTemplate(
        context.classEntry
      );

    const label =
      context.template.subclassLabel ||
      selectedSubclass?.subclassLabel ||
      "Subclass";

    return `
      <article class="hg-character-choice-card ${selectedSubclass ? "selected" : ""}">
        <h3>
          Latest Level Unlock: ${escapeHtml(label)}
          ${context.levelRecord.classLevel === context.subclassLevel ? "Unlocked" : "Choice"}
        </h3>

        <p>
          ${escapeHtml(context.template.name)}
          chooses ${escapeHtml(label)} at class level
          ${context.subclassLevel}.

          ${
            selectedSubclass
              ? `<br><b>Selected:</b> ${escapeHtml(selectedSubclass.name)}`
              : `<br><b>Status:</b> Pending choice.`
          }
        </p>

        <p class="small">
          Choose or change this selection in Class Progression.
        </p>
      </article>
    `;
  }

  function renderLatestLevelAsiUnlock(
    context
  ) {
    const slot =
      context?.asiSlot;

    if (!slot) {
      return "";
    }

    const feat =
      DEFAULT_FEATS.find((entry) => {
        return entry.id === slot.selectedFeatId;
      });

    const status =
      slot.selectedMode === "feat"
        ? `Feat selected: ${feat?.name || slot.selectedFeatId || "None"}`
        : slot.selectedMode === "asi"
          ? "Ability Score Improvement selected."
          : "Pending ASI or feat choice.";
    const slotFeature = {
      id: slot.id,
      name: "Ability Score Improvement",
      level: slot.classLevel,
      optionSource: "asiOrFeat"
    };

    return `
      <article class="hg-character-choice-card ${slot.selectedMode ? "selected" : ""}">
        <h3>ASI / Feat Unlocked</h3>

        <p>
          ${escapeHtml(slot.label)}

          <br>

          <b>Status:</b>
          ${escapeHtml(status)}
        </p>

        ${renderSection12AsiChoice(slotFeature)}
      </article>
    `;
  }

  function renderLatestLevelFeatureUnlocks(
    context
  ) {
    if (!context) {
      return "";
    }

    const featureCards =
      context.classFeatures
        .map((feature) => {
          return `
            <article class="hg-character-choice-card">
              <h3>
                ${escapeHtml(feature.name)}
              </h3>

              <p class="small">
                ${escapeHtml(
                  feature.summary ||
                  feature.description ||
                  "No description provided."
                )}
              </p>

              ${renderSection12FeatureMechanics(feature)}
            </article>
          `;
        })
        .join("");

    return `
      <div class="hg-character-choice-grid">
        ${featureCards ||
          `
            <div class="hg-character-placeholder">
              No class features are recorded for this exact level.
            </div>
          `}
      </div>
    `;
  }

  function renderLatestLevelUnlockSummary(
    character = creatorState.draft
  ) {
    const context =
      getLatestLevelUpContext(
        character
      );

    if (!context) {
      return "";
    }

    return `
      <hr>

      <h3>Latest Level Unlock</h3>

      <div class="hg-character-current-choice">
        <b>Character Level ${context.levelRecord.characterLevel}:</b>
        ${escapeHtml(context.levelRecord.className || "Class")}
        class level ${context.levelRecord.classLevel}

        <br>

        These are the features and choices tied to the latest
        level in the current level order.
      </div>

      <div class="hg-character-choice-grid">
        ${renderLatestLevelSubclassUnlock(context)}
        ${renderLatestLevelAsiUnlock(context)}
      </div>

      <h3>Features Gained at This Class Level</h3>

      ${renderLatestLevelFeatureUnlocks(context)}
    `;
  }

  function getDefaultLevelUpClassIndex(
    character = creatorState.draft
  ) {
    const classes =
      getClassProgressionEntries(
        character
      );

    const levelOrder =
      normalizeClassLevelOrder(
        character
          ?.classProgression
          ?.levelOrder,
        classes
      );

    const lastClassKey =
      levelOrder[
        levelOrder.length - 1
      ];

    const foundIndex =
      classes.findIndex((classEntry, index) => {
        return (
          getClassProgressionEntryKey(
            classEntry,
            index
          ) === lastClassKey
        );
      });

    return foundIndex >= 0
      ? foundIndex
      : 0;
  }

  function renderLevelUpWorkflow(
    character = creatorState.draft
  ) {
    const classes =
      getClassProgressionEntries(
        character
      );

    const entries =
      getMulticlassSummaryEntries(
        character
      );

    const totalLevel =
      calculateClassProgressionTotalLevel(
        character
      );

    const records =
      getCharacterLevelHitDieRecords(
        character
      );

    const lastRecord =
      records[records.length - 1] ||
      null;

    const defaultIndex =
      getDefaultLevelUpClassIndex(
        character
      );

    const levelUpChoices =
      entries.length
        ? entries.map((entry, index) => {
            return {
              value: index,
              label:
                `${entry.className} (currently level ${entry.classLevel})`
            };
          })
        : [
            {
              value: "",
              label: "Choose a class first"
            }
          ];

    return `
      <h3>Level Up Workflow</h3>

      <div class="hg-character-beginner-note">
        <strong>To multiclass:</strong>
        <p>
          1. Pick a class in Add Multiclass.<br>
          2. Click Add Selected Class.<br>
          3. Use Level Up Workflow to decide which class gains future levels.
        </p>
      </div>

      <div class="hg-character-current-choice">
        <b>Current Character Level:</b>
        ${totalLevel} / 20

        <br>

        <b>Next Character Level:</b>
        ${
          totalLevel < 20
            ? totalLevel + 1
            : "Maximum level reached"
        }

        <br>

        <b>Last Character Level:</b>
        ${
          lastRecord
            ? `${escapeHtml(lastRecord.className || "Class")} ${safeNumber(lastRecord.classLevel, 1)} at character level ${safeNumber(lastRecord.characterLevel, totalLevel)}`
            : "None yet"
        }

        <br>

        Use this to add the next character level in order. Add a new
        class below first if the next level should start a multiclass.
      </div>

      <div class="hg-character-field-grid three">
        ${wizardSelect(
          "Class Gaining Next Level",
          "ccLevelUpClassIndex",
          defaultIndex,
          levelUpChoices,
          {
            wide: true,
            extra:
              !classes.length ||
              totalLevel >= 20
                ? "disabled"
                : ""
          }
        )}

        <div class="hg-character-field">
          <label>
            Add Level
          </label>

          <button
            type="button"
            data-cc-action="add-character-level"
            ${
              !classes.length ||
              totalLevel >= 20
                ? "disabled"
                : ""
            }
          >
            Add Character Level
          </button>
        </div>

        <div class="hg-character-field">
          <label>
            Undo Last Level
          </label>

          <button
            type="button"
            data-cc-action="remove-last-character-level"
            ${totalLevel <= 1 ? "disabled" : ""}
          >
            Remove Last Level
          </button>
        </div>
      </div>

      ${renderLatestLevelUnlockSummary(character)}
    `;
  }

  function getSection12MulticlassAddStatus() {
    const stored =
      creatorState.multiclassAddStatus;

    return {
      message: cleanString(
        stored?.message
      ),
      tone:
        stored?.tone === "success"
          ? "success"
          : "warning"
    };
  }

  function renderSection12MulticlassAddStatus() {
    const status =
      getSection12MulticlassAddStatus();
    const isSuccess =
      status.tone === "success";

    return `
      <div
        id="ccMulticlassAddStatus"
        class="${isSuccess ? "hg-character-current-choice" : "hg-character-warning"} hg-character-multiclass-add-status"
        data-status-kind="${status.tone}"
        role="${isSuccess ? "status" : "alert"}"
        aria-live="polite"
        ${status.message ? "" : "hidden"}
      >
        ${escapeHtml(status.message)}
      </div>
    `;
  }

  function setSection12MulticlassAddStatus(
    message,
    tone = "warning",
    localRoot = null
  ) {
    const cleanMessage =
      cleanString(message);
    const cleanTone =
      tone === "success"
        ? "success"
        : "warning";

    creatorState.multiclassAddStatus = {
      message: cleanMessage,
      tone: cleanTone
    };

    setStatus(cleanMessage);

    if (typeof document === "undefined") {
      return cleanMessage;
    }

    const roots = [
      localRoot,
      W.stepBody,
      W.root
    ].filter((root, index, values) => {
      return (
        root &&
        typeof root.querySelector ===
          "function" &&
        values.indexOf(root) === index
      );
    });

    let statusElement = null;

    roots.some((root) => {
      statusElement =
        root.querySelector(
          "#ccMulticlassAddStatus"
        );

      return Boolean(statusElement);
    });

    if (!statusElement) {
      statusElement =
        document.getElementById(
          "ccMulticlassAddStatus"
        );
    }

    if (!statusElement) {
      return cleanMessage;
    }

    statusElement.textContent =
      cleanMessage;
    statusElement.hidden =
      !cleanMessage;
    statusElement.className =
      `${cleanTone === "success" ? "hg-character-current-choice" : "hg-character-warning"} hg-character-multiclass-add-status`;
    statusElement.dataset.statusKind =
      cleanTone;
    statusElement.setAttribute(
      "role",
      cleanTone === "success"
        ? "status"
        : "alert"
    );

    return cleanMessage;
  }

  function renderMulticlassProgressionEditor(
    character = creatorState.draft
  ) {
    const entries =
      getMulticlassSummaryEntries(
        character
      );

    const classes =
      getClassProgressionEntries(
        character
      );

    const totalLevel =
      calculateClassProgressionTotalLevel(
        character
      );

    const levelOrder =
      normalizeClassLevelOrder(
        character
          ?.classProgression
          ?.levelOrder,
        classes
      );

    const classSplit = entries
      .map((entry) => {
        return `${entry.className} ${entry.classLevel}`;
      })
      .join(" / ");

    const proficiencyBonus =
      getGenericProficiencyBonus(
        totalLevel
      );

    const existingClassIds =
      new Set(
        classes
          .map((classEntry) => {
            const template =
              resolveClassTemplateForEntry(
                classEntry
              );

            return (
              classEntry?.classId ||
              template?.id ||
              ""
            );
          })
          .filter(Boolean)
      );

    const failedPrerequisites =
      entries.length > 1
        ? getMulticlassPrerequisiteResults(
            character
          ).filter((result) => {
            return !result.met;
          })
        : [];

    const addClassChoices = [
      {
        value: "",
        label:
          totalLevel >= 20
            ? "Total level is already 20"
            : "Choose a class to add"
      },

      ...getAllClassTemplates()
        .filter((classData) => {
          return !existingClassIds.has(
            classData.id
          );
        })
        .map((classData) => {
          return {
            value: classData.id,
            label: classData.name
          };
        })
    ];

    const classCards =
      entries
        .map((entry, index) => {
          const classEntry =
            entry.classEntry;

          const classProgressionKey =
            getClassProgressionEntryKey(
              classEntry,
              index
            );

          const orderedLevelCount =
            levelOrder.filter((key) => {
              return key === classProgressionKey;
            }).length;

          const otherLevelTotal =
            classes.reduce(
              (sum, item, itemIndex) => {
                return (
                  sum +
                  (
                    itemIndex === index
                      ? 0
                      : getClassEntryLevel(
                          item,
                          1
                        )
                  )
                );
              },
              0
            );

          const maximumLevel =
            Math.max(
              1,
              20 - otherLevelTotal
            );

          const subclassOptions =
            (
              Array.isArray(
                entry.template?.subclasses
              )
                ? entry.template.subclasses
                : []
            )
              .map((subclass) => {
                return normalizeSection12Subclass(
                  subclass,
                  entry.template?.source ||
                  "template"
                );
              });

          const subclassUnlocked =
            entry.classLevel >=
            entry.subclassLevel;

          const selectedSubclass =
            getClassEntrySubclassTemplate(
              classEntry
            );

          const prerequisiteResult =
            getMulticlassPrerequisiteResultForClass(
              classEntry,
              character
            );

          const proficiencySummary =
            formatClassEntryProficiencySummary(
              classEntry,
              index,
              character
            );

          const toolChoiceConfig =
            getClassEntryToolChoiceConfig(
              classEntry,
              index,
              character
            );

          const pendingToolChoice =
            toolChoiceConfig.choose > 0 &&
            getValidClassEntryToolChoices(
              classEntry,
              index,
              character
            ).length !== toolChoiceConfig.choose;

          const isStartingClass =
            isStartingClassEntry(
              classEntry,
              character,
              index
            );

          const subclassChoices = [
            {
              value: "",
              label:
                subclassUnlocked
                  ? `Choose ${entry.template?.subclassLabel || "Subclass"}`
                  : `${entry.template?.subclassLabel || "Subclass"} unlocks at level ${entry.subclassLevel}`
            },

            ...subclassOptions.map(
              (subclass) => {
                return {
                  value: subclass.id,
                  label: subclass.name
                };
              }
            )
          ];

          return `
            <article class="hg-character-choice-card">
              <h3>
                ${escapeHtml(entry.className)}
                ${isStartingClass ? " &mdash; Starting Class" : ""}
              </h3>

              <p>
                <b>Class Level:</b>
                ${entry.classLevel}

                <br>

                <b>Levels in Order:</b>
                ${orderedLevelCount}

                <br>

                <b>Hit Die:</b>
                ${escapeHtml(entry.hitDie)}

                <br>

                <b>Subclass:</b>
                ${escapeHtml(
                  entry.subclassName ||
                  (
                    subclassUnlocked
                      ? "None selected"
                      : `Unlocks at level ${entry.subclassLevel}`
                  )
                )}

                <br>

                <b>Multiclass Prerequisite:</b>
                ${escapeHtml(prerequisiteResult.label)}
                ${prerequisiteResult.met ? "✓" : "⚠"}

                <br>

                <b>Proficiencies:</b>
                ${escapeHtml(proficiencySummary)}
              </p>

              ${
                pendingToolChoice
                  ? `
                    <div class="hg-character-warning">
                      <b>Pending multiclass choice:</b>
                      Choose ${toolChoiceConfig.choose}
                      ${escapeHtml(toolChoiceConfig.label)}${toolChoiceConfig.choose === 1 ? "" : "s"}.
                    </div>
                  `
                  : ""
              }

              ${wizardField(
                "Class Level",
                `ccMulticlassLevel-${index}`,
                entry.classLevel,
                {
                  type: "number",
                  valueType: "integer",
                  extra:
                    `min="1" max="${maximumLevel}" step="1" data-multiclass-class-index="${index}"`
                }
              )}

              <div class="hg-character-inline-actions">
                <button
                  type="button"
                  data-cc-action="adjust-multiclass-level"
                  data-class-index="${index}"
                  data-delta="-1"
                  ${entry.classLevel <= 1 ? "disabled" : ""}
                >
                  - Level
                </button>

                <button
                  type="button"
                  data-cc-action="adjust-multiclass-level"
                  data-class-index="${index}"
                  data-delta="1"
                  ${entry.classLevel >= maximumLevel ? "disabled" : ""}
                >
                  + Level
                </button>
              </div>

              <div class="hg-character-inline-actions">
                <button
                  type="button"
                  data-cc-action="add-character-level"
                  data-class-index="${index}"
                  ${totalLevel >= 20 || entry.classLevel >= maximumLevel ? "disabled" : ""}
                >
                  Add next level to ${escapeHtml(entry.className)}
                </button>
              </div>

              ${
                subclassOptions.length
                  ? wizardSelect(
                      entry.template?.subclassLabel || "Subclass",
                      `ccMulticlassSubclass-${index}`,
                      classEntry?.subclassId ||
                        selectedSubclass?.id ||
                        "",
                      subclassChoices,
                      {
                        extra:
                          `data-multiclass-subclass-index="${index}"${
                            subclassUnlocked
                              ? ""
                              : " disabled"
                          }`
                      }
                    )
                  : `
                    <p class="small">
                      This class does not have saved subclass options.
                    </p>
                      `
              }

              ${renderMulticlassStoredChoices(
                entry.classEntry
              )}

              ${renderMulticlassSkillChoices(
                entry.classEntry,
                index,
                character
              )}

              ${renderMulticlassToolChoices(
                entry.classEntry,
                index,
                character
              )}

              <div class="hg-character-inline-actions">
                <button
                  type="button"
                  data-cc-action="move-multiclass-class"
                  data-class-index="${index}"
                  data-delta="-1"
                  ${index <= 0 ? "disabled" : ""}
                >
                  Move Up
                </button>

                <button
                  type="button"
                  data-cc-action="move-multiclass-class"
                  data-class-index="${index}"
                  data-delta="1"
                  ${index >= entries.length - 1 ? "disabled" : ""}
                >
                  Move Down
                </button>

                ${
                  !isStartingClass
                    ? `
                      <button
                        type="button"
                        data-cc-action="remove-multiclass-class"
                        data-class-index="${index}"
                      >
                        Remove Class
                      </button>
                    `
                    : ""
                }
              </div>
            </article>
          `;
        })
        .join("");

    return `
      <h3>Class Progression</h3>

      <div class="hg-character-current-choice">
        <b>Total Character Level:</b>
        ${totalLevel} / 20

        <br>

        <b>Class Split:</b>
        ${escapeHtml(classSplit || "No class selected")}

        <br>

        <b>Proficiency Bonus:</b>
        +${proficiencyBonus}

        <br>

        Add character levels through the level-up workflow below.
        Advanced class totals and the level-by-level order are still
        editable when you need to correct an imported or older character.
      </div>

      ${
        failedPrerequisites.length
          ? `
            <div class="hg-character-warning">
              <b>Multiclass prerequisites not met:</b>
              ${escapeHtml(
                failedPrerequisites
                  .map(formatMulticlassPrerequisiteFailure)
                  .join("; ")
              )}.
            </div>
          `
          : ""
      }

      ${renderLevelUpWorkflow(character)}

      <hr>

      <div class="hg-character-beginner-note">
        <strong>Add Multiclass</strong>
        <p>
          Add Selected Class adds a new class at level 1. After that, use Level Up Workflow to add more levels to that class.
        </p>
      </div>

      <div class="hg-character-field-grid three">
        ${wizardSelect(
          "Choose class to add",
          "ccMulticlassAddClass",
          "",
          addClassChoices,
          {
            wide: true,
            extra:
              totalLevel >= 20
                ? "disabled"
                : ""
          }
        )}

        <div class="hg-character-field">
          <label>
            Action
          </label>

          <button
            type="button"
            data-cc-action="add-multiclass-class"
            ${totalLevel >= 20 ? "disabled" : ""}
          >
            Add Selected Class
          </button>
        </div>
      </div>

      ${renderSection12MulticlassAddStatus()}

      <div class="hg-character-choice-grid">
        ${classCards ||
          `
            <div class="hg-character-placeholder">
              Choose a class to begin the progression.
            </div>
          `}
      </div>
    `;
  }

  function calculateClassProgressionTotalLevel(
    character = creatorState.draft
  ) {
    const classes =
      Array.isArray(
        character
          ?.classProgression
          ?.classes
      )
        ? character
            .classProgression
            .classes
        : [];

    const total =
      classes.reduce(
        (sum, classEntry) => {
          return (
            sum +
            Math.max(
              0,
              Math.round(
                safeNumber(
                  classEntry?.level,
                  0
                )
              )
            )
          );
        },
        0
      );

    return clampLevel(total || 1);
  }

  function recalculateClassTotalLevel(
    character = creatorState.draft
  ) {
    ensureClassProgressionEntryData(
      character
    );

    syncClassLevelOrderToClassLevels(
      character
    );

    character.classProgression.totalLevel =
      enforceClassProgressionLevelCap(
        character
      );

    syncFirstUnarmoredDefenseSource(
      character
    );

    return character.classProgression.totalLevel;
  }

  function getClassProgressionEntries(
    character = creatorState.draft
  ) {
    return Array.isArray(
      character
        ?.classProgression
        ?.classes
    )
      ? character.classProgression.classes
      : [];
  }

  function getClassEntryAtIndex(
    classIndex,
    character = creatorState.draft
  ) {
    const index =
      Math.max(
        0,
        Math.round(
          safeNumber(classIndex, 0)
        )
      );

    return (
      getClassProgressionEntries(
        character
      )[index] ||
      null
    );
  }

  function getClassEntryLevel(
    classEntry,
    fallbackLevel = 1
  ) {
    return Math.max(
      0,
      Math.min(
        20,
        Math.round(
          safeNumber(
            classEntry?.level,
            fallbackLevel
          )
        )
      )
    );
  }

  function createClassProgressionEntry(
    classTemplate,
    level = 1
  ) {
    if (!classTemplate) {
      return null;
    }

    const existingEntries =
      getClassProgressionEntries();
    const existingIds = new Set(
      existingEntries
        .map((entry) => {
          return cleanString(entry?.entryId);
        })
        .filter(Boolean)
    );

    return {
      entryId: createClassEntryId(
        classTemplate.id ||
          classTemplate.name,
        existingEntries.length,
        existingIds
      ),
      classId: classTemplate.id,
      className: classTemplate.name,
      source: classTemplate.source,
      level: Math.max(
        1,
        Math.min(
          20,
          Math.round(
            safeNumber(level, 1)
          )
        )
      ),
      subclassId: "",
      subclassName: "",
      hitDie: normalizeClassEntryHitDie(
        classTemplate.hitDie,
        8
      ),
      templateSnapshot:
        findDefaultClassDefinition(
          classTemplate.id,
          classTemplate.name
        )
          ? null
          : cloneData(classTemplate),
      choices: {}
    };
  }

  function getClassEntrySubclassTemplate(
    classEntry
  ) {
    if (!classEntry) {
      return null;
    }

    const savedSnapshot =
      classEntry.choices
        ?.subclassSnapshot;

    const template =
      resolveClassTemplateForEntry(
        classEntry
      );

    const subclassId =
      cleanString(classEntry.subclassId);

    const subclassName =
      cleanString(classEntry.subclassName)
        .toLowerCase();

    const normalizedSavedSnapshot =
      savedSnapshot
        ? normalizeSection12Subclass(
            savedSnapshot,
            "character"
          )
        : null;

    const matchedTemplateSubclass =
      (
        Array.isArray(template?.subclasses)
          ? template.subclasses
          : []
      )
        .map((subclass) => {
          return normalizeSection12Subclass(
            subclass,
            template?.source || "template"
          );
        })
        .find((subclass) => {
          return (
            subclass.id === subclassId ||
            subclass.id ===
              normalizedSavedSnapshot?.id ||
            (
              subclassName &&
              subclass.name.toLowerCase() ===
                subclassName
            ) ||
            (
              normalizedSavedSnapshot?.name &&
              subclass.name.toLowerCase() ===
                normalizedSavedSnapshot.name
                  .toLowerCase()
            )
          );
        }) ||
      null;

    if (
      normalizedSavedSnapshot &&
      matchedTemplateSubclass &&
      findDefaultClassDefinition(
        classEntry.classId,
        classEntry.className
      )
    ) {
      return normalizeSection12Subclass(
        {
          ...cloneData(
            normalizedSavedSnapshot
          ),
          ...cloneData(
            matchedTemplateSubclass
          )
        },
        matchedTemplateSubclass.source ||
        "template"
      );
    }

    if (normalizedSavedSnapshot) {
      return normalizedSavedSnapshot;
    }

    return matchedTemplateSubclass;
  }

  function getSkillDefinitionByIdOrName(
    skillIdOrName
  ) {
    const cleanSkill =
      cleanString(skillIdOrName)
        .toLowerCase();

    if (!cleanSkill) {
      return null;
    }

    return (
      SKILL_DEFINITIONS.find((skill) => {
        return (
          skill.id.toLowerCase() ===
            cleanSkill ||
          skill.name.toLowerCase() ===
            cleanSkill
        );
      }) ||
      null
    );
  }

  function getClassEntrySkillChoiceConfig(
    classEntry,
    classIndex = 0,
    character = creatorState.draft
  ) {
    const template =
      resolveClassTemplateForEntry(
        classEntry
      );

    if (!template) {
      return {
        choose: 0,
        from: []
      };
    }

    const baseChoices =
      template.skillChoices || {};

    if (
      isStartingClassEntry(
        classEntry,
        character,
        classIndex
      )
    ) {
      return {
        choose: Math.max(
          0,
          Math.round(
            safeNumber(
              baseChoices.choose,
              0
            )
          )
        ),
        from: cleanArray(
          baseChoices.from
        )
      };
    }

    const rule =
      getMulticlassProficiencyRule(
        classEntry
      );

    return {
      choose: Math.max(
        0,
        Math.round(
          safeNumber(
            rule.skillChoices?.choose,
            0
          )
        )
      ),
      from: cleanArray(
        rule.skillChoices?.from?.length
          ? rule.skillChoices.from
          : baseChoices.from
      )
    };
  }

  function getClassEntryStoredSkillIds(
    classEntry
  ) {
    classEntry.choices =
      classEntry.choices || {};

    classEntry.choices.skillProficiencyIds =
      cleanArray(
        classEntry.choices
          .skillProficiencyIds
      );

    return classEntry.choices
      .skillProficiencyIds;
  }

  function getClassEntryToolChoiceConfig(
    classEntry,
    classIndex = 0,
    character = creatorState.draft
  ) {
    if (
      isStartingClassEntry(
        classEntry,
        character,
        classIndex
      )
    ) {
      return {
        choose: 0,
        label: "tool proficiency",
        from: []
      };
    }

    const rule =
      getMulticlassProficiencyRule(
        classEntry
      );

    return {
      choose: Math.max(
        0,
        Math.round(
          safeNumber(
            rule.toolChoices?.choose,
            0
          )
        )
      ),
      label: cleanString(
        rule.toolChoices?.label,
        "tool proficiency"
      ),
      from: cleanArray(
        rule.toolChoices?.from
      )
    };
  }

  function getClassEntryStoredToolChoices(
    classEntry
  ) {
    return cleanArray(
      classEntry?.choices
        ?.toolProficiencyIds
    );
  }

  function getClassEntryToolChoiceOptions(
    classEntry,
    classIndex = 0,
    character = creatorState.draft
  ) {
    const config =
      getClassEntryToolChoiceConfig(
        classEntry,
        classIndex,
        character
      );

    const configuredOptions =
      cleanArray(config.from);

    const sourceOptions =
      configuredOptions.length
        ? configuredOptions
        : [config.label];

    return uniqueCleanArray(
      sourceOptions.flatMap((option) => {
        return expandSection14ToolChoice(
          option
        );
      })
    ).sort((a, b) => {
      return a.localeCompare(b);
    });
  }

  function getValidClassEntryToolChoices(
    classEntry,
    classIndex = 0,
    character = creatorState.draft
  ) {
    const config =
      getClassEntryToolChoiceConfig(
        classEntry,
        classIndex,
        character
      );

    const allowed = new Set(
      cleanArray(config.from).map((value) => {
        return value.toLowerCase();
      })
    );

    return getClassEntryStoredToolChoices(
      classEntry
    )
      .filter((value) => {
        return (
          !allowed.size ||
          allowed.has(value.toLowerCase())
        );
      })
      .slice(0, config.choose);
  }

  function getMulticlassPendingToolChoiceWarnings(
    character = creatorState.draft
  ) {
    return getClassProgressionEntries(
      character
    ).flatMap((classEntry, classIndex) => {
      const config =
        getClassEntryToolChoiceConfig(
          classEntry,
          classIndex,
          character
        );

      if (config.choose <= 0) {
        return [];
      }

      const selectedCount =
        getValidClassEntryToolChoices(
          classEntry,
          classIndex,
          character
        ).length;

      if (selectedCount === config.choose) {
        return [];
      }

      const className =
        safeDisplayString(
          classEntry?.className,
          `Class ${classIndex + 1}`
        );

      return [
        `${className} multiclass proficiency choice is pending: choose ${config.choose} ${config.label}${config.choose === 1 ? "" : "s"}.`
      ];
    });
  }

  function getMulticlassPendingSkillChoiceWarnings(
    character = creatorState.draft
  ) {
    return getClassProgressionEntries(
      character
    ).flatMap((classEntry, classIndex) => {
      if (
        isStartingClassEntry(
          classEntry,
          character,
          classIndex
        )
      ) {
        return [];
      }

      const config =
        getClassEntrySkillChoiceConfig(
          classEntry,
          classIndex,
          character
        );

      if (config.choose <= 0) {
        return [];
      }

      const selectedCount =
        countValidClassEntrySkillChoices(
          classEntry,
          classIndex,
          character
        );

      if (selectedCount === config.choose) {
        return [];
      }

      const className =
        safeDisplayString(
          classEntry?.className,
          `Class ${classIndex + 1}`
        );

      return [
        `${className} multiclass skill choice is pending: choose ${config.choose} skill proficienc${config.choose === 1 ? "y" : "ies"}.`
      ];
    });
  }

  function getValidClassEntrySkillIds(
    classEntry,
    classIndex = 0,
    character = creatorState.draft
  ) {
    const config =
      getClassEntrySkillChoiceConfig(
        classEntry,
        classIndex,
        character
      );

    const allowedNames =
      cleanArray(config.from)
        .map((name) => {
          return name.toLowerCase();
        });

    const selected =
      getClassEntryStoredSkillIds(
        classEntry
      )
        .map(getSkillDefinitionByIdOrName)
        .filter((skill) => {
          return (
            skill &&
            (
              !allowedNames.length ||
              allowedNames.includes(
                skill.name.toLowerCase()
              )
            )
          );
        })
        .map((skill) => skill.id);

    return [
      ...new Set(selected)
    ].slice(
      0,
      config.choose
    );
  }

  function countValidClassEntrySkillChoices(
    classEntry,
    classIndex = 0,
    character = creatorState.draft
  ) {
    return getValidClassEntrySkillIds(
      classEntry,
      classIndex,
      character
    ).length;
  }

  function applyStoredClassSkillProficiencies(
    classEntry,
    classIndex = 0,
    character = creatorState.draft
  ) {
    const sourceLabel =
      getClassSourceLabel(
        classEntry
      );

    const config =
      getClassEntrySkillChoiceConfig(
        classEntry,
        classIndex,
        character
      );

    if (
      !sourceLabel ||
      config.choose <= 0
    ) {
      return;
    }

    const selectedIds =
      getValidClassEntrySkillIds(
        classEntry,
        classIndex,
        character
      );

    classEntry.choices =
      classEntry.choices || {};

    classEntry.choices.skillProficiencyIds =
      selectedIds;

    selectedIds.forEach((skillId) => {
      const skill =
        getSkillDefinitionByIdOrName(
          skillId
        );

      if (!skill) {
        return;
      }

      const current =
        getSection14SkillEntry(
          skill
        );

      setSection14SkillEntry(
        skill,
        {
          proficient: true,
          expertise:
            current.expertise === true,
          source: [
            ...new Set([
              ...cleanArray(
                current.source
              ),
              sourceLabel
            ])
          ]
        }
      );
    });
  }

  function applyClassProgressionProficiencies(
    character = creatorState.draft
  ) {
    removeSkillProficiencySourcesByPrefix([
      "class:"
    ]);

    removeListProficiencySourcesByPrefix([
      "class:"
    ]);

    getClassProgressionEntries(
      character
    ).forEach((classEntry, index) => {
      const template =
        resolveClassTemplateForEntry(
          classEntry
        );

      const sourceLabel =
        getClassSourceLabel(
          classEntry
        );

      if (
        !template ||
        !sourceLabel
      ) {
        return;
      }

      const isStartingClass =
        isStartingClassEntry(
          classEntry,
          character,
          index
        );

      if (isStartingClass) {
        setSourceProficiencyList(
          "savingThrows",
          template.savingThrows || [],
          sourceLabel
        );

        setSourceProficiencyList(
          "armor",
          template.armorProficiencies || [],
          sourceLabel
        );

        setSourceProficiencyList(
          "weapons",
          template.weaponProficiencies || [],
          sourceLabel
        );

        setSourceProficiencyList(
          "tools",
          template.toolProficiencies || [],
          sourceLabel
        );
      } else {
        const rule =
          getMulticlassProficiencyRule(
            classEntry
          );

        setSourceProficiencyList(
          "armor",
          rule.armor || [],
          sourceLabel
        );

        setSourceProficiencyList(
          "weapons",
          rule.weapons || [],
          sourceLabel
        );

        setSourceProficiencyList(
          "tools",
          [
            ...(rule.tools || []),
            ...getValidClassEntryToolChoices(
              classEntry,
              index,
              character
            )
          ],
          sourceLabel
        );
      }

      applyStoredClassSkillProficiencies(
        classEntry,
        index,
        character
      );
    });
  }

  function formatClassEntryProficiencySummary(
    classEntry,
    classIndex = 0,
    character = creatorState.draft
  ) {
    const template =
      resolveClassTemplateForEntry(
        classEntry
      );

    if (!template) {
      return "No class proficiency data.";
    }

    const config =
      getClassEntrySkillChoiceConfig(
        classEntry,
        classIndex,
        character
      );

    const isStartingClass =
      isStartingClassEntry(
        classEntry,
        character,
        classIndex
      );

    const lists =
      isStartingClass
        ? {
            savingThrows:
              template.savingThrows || [],
            armor:
              template.armorProficiencies || [],
            weapons:
              template.weaponProficiencies || [],
            tools:
              template.toolProficiencies || []
          }
        : {
            savingThrows: [],
            armor:
              getMulticlassProficiencyRule(
                classEntry
              ).armor || [],
            weapons:
              getMulticlassProficiencyRule(
                classEntry
              ).weapons || [],
            tools:
              [
                ...(
                  getMulticlassProficiencyRule(
                    classEntry
                  ).tools || []
                ),
                ...getValidClassEntryToolChoices(
                  classEntry,
                  classIndex,
                  character
                )
              ]
          };

    const parts = [];

    if (lists.savingThrows.length) {
      parts.push(
        `Saving throws: ${formatSection12List(lists.savingThrows)}`
      );
    }

    if (lists.armor.length) {
      parts.push(
        `Armor: ${formatSection12List(lists.armor)}`
      );
    }

    if (lists.weapons.length) {
      parts.push(
        `Weapons: ${formatSection12List(lists.weapons)}`
      );
    }

    if (lists.tools.length) {
      parts.push(
        `Tools: ${formatSection12List(lists.tools)}`
      );
    }

    if (config.choose > 0) {
      parts.push(
        `Skills: choose ${config.choose}`
      );
    }

    return parts.length
      ? parts.join("; ")
      : isStartingClass
        ? "No listed class proficiencies."
        : "No additional multiclass proficiencies.";
  }

  function renderMulticlassSkillChoices(
    classEntry,
    classIndex = 0,
    character = creatorState.draft
  ) {
    const config =
      getClassEntrySkillChoiceConfig(
        classEntry,
        classIndex,
        character
      );

    if (
      isStartingClassEntry(
        classEntry,
        character,
        classIndex
      ) ||
      config.choose <= 0
    ) {
      return "";
    }

    const selected =
      new Set(
        getValidClassEntrySkillIds(
          classEntry,
          classIndex,
          character
        )
      );

    const allowedSkills =
      cleanArray(config.from)
        .map(getSkillDefinitionByIdOrName)
        .filter(Boolean);

    return `
      <p>
        <b>Multiclass Skill:</b>
        Choose ${config.choose}.
        Selected ${selected.size} / ${config.choose}.
      </p>

      <div class="hg-character-inline-actions">
        ${allowedSkills
          .map((skill) => {
            const isSelected =
              selected.has(skill.id);

            return `
              <button
                type="button"
                class="${isSelected ? "selected" : ""}"
                data-cc-action="toggle-multiclass-skill"
                data-class-index="${classIndex}"
                data-skill-id="${escapeHtml(skill.id)}"
              >
                ${isSelected ? "Remove" : "Choose"}
                ${escapeHtml(skill.name)}
              </button>
            `;
          })
          .join("")}
      </div>
    `;
  }

  function renderMulticlassToolChoices(
    classEntry,
    classIndex = 0,
    character = creatorState.draft
  ) {
    const config =
      getClassEntryToolChoiceConfig(
        classEntry,
        classIndex,
        character
      );

    if (
      isStartingClassEntry(
        classEntry,
        character,
        classIndex
      ) ||
      config.choose <= 0
    ) {
      return "";
    }

    const selected = new Set(
      getValidClassEntryToolChoices(
        classEntry,
        classIndex,
        character
      )
    );

    const options =
      getClassEntryToolChoiceOptions(
        classEntry,
        classIndex,
        character
      );

    return `
      <p>
        <b>Multiclass Tool:</b>
        Choose ${config.choose}
        ${escapeHtml(config.label)}${config.choose === 1 ? "" : "s"}.
        Selected ${selected.size} / ${config.choose}.
      </p>

      <div class="hg-character-inline-actions">
        ${options
          .map((tool) => {
            const isSelected =
              selected.has(tool);

            return `
              <button
                type="button"
                class="${isSelected ? "selected" : ""}"
                data-cc-action="toggle-multiclass-tool"
                data-class-index="${classIndex}"
                data-tool-value="${escapeHtml(tool)}"
              >
                ${isSelected ? "Remove" : "Choose"}
                ${escapeHtml(tool)}
              </button>
            `;
          })
          .join("")}
      </div>
    `;
  }

  function toggleMulticlassSkillChoice(
    classIndex,
    skillId
  ) {
    const index =
      Math.max(
        0,
        Math.round(
          safeNumber(classIndex, 0)
        )
      );

    const classEntry =
      getClassEntryAtIndex(index);

    if (!classEntry) {
      return false;
    }

    const config =
      getClassEntrySkillChoiceConfig(
        classEntry,
        index
      );

    const skill =
      getSkillDefinitionByIdOrName(
        skillId
      );

    const allowedNames =
      cleanArray(config.from)
        .map((name) => {
          return name.toLowerCase();
        });

    if (
      !skill ||
      config.choose <= 0 ||
      (
        allowedNames.length &&
        !allowedNames.includes(
          skill.name.toLowerCase()
        )
      )
    ) {
      return false;
    }

    const choices =
      getClassEntryStoredSkillIds(
        classEntry
      );

    const alreadySelected =
      choices.includes(skill.id);

    if (alreadySelected) {
      classEntry.choices.skillProficiencyIds =
        choices.filter((id) => {
          return id !== skill.id;
        });
    } else if (
      choices.length >= config.choose
    ) {
      setStatus(
        `Choose only ${config.choose} ${classEntry.className || "class"} multiclass skill${config.choose === 1 ? "" : "s"}.`
      );

      return false;
    } else {
      classEntry.choices.skillProficiencyIds = [
        ...choices,
        skill.id
      ];
    }

    applyClassProgressionProficiencies();
    applyCompatibilityAliases(
      creatorState.draft
    );
    markDraftChanged();

    return true;
  }

  function toggleMulticlassToolChoice(
    classIndex,
    toolValue
  ) {
    const index =
      Math.max(
        0,
        Math.round(
          safeNumber(classIndex, 0)
        )
      );

    const classEntry =
      getClassEntryAtIndex(index);

    if (!classEntry) {
      return false;
    }

    const config =
      getClassEntryToolChoiceConfig(
        classEntry,
        index
      );
    const tool = cleanString(
      toolValue
    );
    const options =
      getClassEntryToolChoiceOptions(
        classEntry,
        index
      );

    if (
      config.choose <= 0 ||
      !options.includes(tool)
    ) {
      return false;
    }

    classEntry.choices = {
      ...(classEntry.choices || {})
    };

    const choices =
      getClassEntryStoredToolChoices(
        classEntry
      );
    const alreadySelected =
      choices.includes(tool);

    if (alreadySelected) {
      classEntry.choices
        .toolProficiencyIds =
          choices.filter((value) => {
            return value !== tool;
          });
    } else if (
      choices.length >= config.choose
    ) {
      setStatus(
        `Choose only ${config.choose} ${config.label}${config.choose === 1 ? "" : "s"}.`
      );

      return false;
    } else {
      classEntry.choices
        .toolProficiencyIds = [
          ...choices,
          tool
        ];
    }

    applyClassProgressionProficiencies();
    applyCompatibilityAliases(
      creatorState.draft
    );
    markDraftChanged();

    return true;
  }

  function collectSection12FeaturesForClassEntry(
    classEntry,
    classIndex = 0
  ) {
    const template =
      resolveClassTemplateForEntry(
        classEntry
      );

    if (!template) {
      return [];
    }

    const classLevel =
      getClassEntryLevel(
        classEntry,
        1
      );

    const classLabel =
      safeDisplayString(
        classEntry?.className,
        template.name ||
        `Class ${classIndex + 1}`
      );

    const defaultClass =
      findDefaultClassDefinition(
        classEntry?.classId,
        classEntry?.className
      );

    const classFeatures =
      defaultClass
        ? getDefaultClassFeaturesThroughLevel(
            defaultClass,
            classLevel
          )
        : collectSection12Features(
            template,
            classLevel,
            "class"
          );

    const subclassFeatures =
      collectSection12Features(
        getClassEntrySubclassTemplate(
          classEntry
        ),
        classLevel,
        "subclass"
      );

    return [
      ...classFeatures,
      ...subclassFeatures
    ].map((feature) => {
      const classEntryId =
        getClassProgressionEntryKey(
          classEntry,
          classIndex
        );

      return {
        ...feature,
        classIndex,
        classEntryId,
        choiceKey: `${classEntryId}:${feature.id}`,
        classId:
          classEntry?.classId ||
          template.id ||
          "",
        className: classLabel,
        classLevel
      };
    });
  }

  function getPendingClassFeatureChoiceWarnings(
    character = creatorState.draft
  ) {
    return getClassProgressionEntries(
      character
    ).flatMap((classEntry, classIndex) => {
      return collectSection12FeaturesForClassEntry(
        classEntry,
        classIndex
      ).flatMap((feature) => {
        const optionSource =
          cleanString(
            feature.optionSource
          ).toLowerCase();

        if (
          feature.type !== "choice" ||
          [
            "subclasses",
            "asiorfeat"
          ].includes(optionSource)
        ) {
          return [];
        }

        const options =
          getSection12FeatureChoiceOptions(
            feature
          );
        const required =
          getSection12FeatureChooseCount(
            feature
          );
        const selected =
          getSection12FeatureStoredChoices(
            feature
          ).filter((choice) => {
            return options.includes(choice);
          });

        if (
          !options.length ||
          selected.length >= required
        ) {
          return [];
        }

        return [
          `${feature.className || classEntry.className || "Class"} class level ${feature.level} has a pending ${feature.name} choice (${selected.length}/${required}).`
        ];
      });
    });
  }

  function getClassProgressionPendingChoiceWarnings(
    character = creatorState.draft
  ) {
    const warnings = [
      ...getPendingClassFeatureChoiceWarnings(
        character
      ),
      ...getMulticlassPendingSkillChoiceWarnings(
        character
      ),
      ...getMulticlassPendingToolChoiceWarnings(
        character
      )
    ];

    getMulticlassSummaryEntries(
      character
    ).forEach((entry) => {
      const subclassOptions =
        Array.isArray(
          entry.template?.subclasses
        )
          ? entry.template.subclasses
          : [];

      if (
        subclassOptions.length > 0 &&
        entry.classLevel >=
          entry.subclassLevel &&
        !entry.subclassName
      ) {
        warnings.push(
          `${entry.className} has a pending subclass choice at class level ${entry.subclassLevel}.`
        );
      }
    });

    getUnlockedFeatChoiceSlots(
      character
    )
      .filter((slot) => {
        return (
          !slot.selectedMode ||
          (
            slot.selectedMode === "feat" &&
            !slot.selectedFeatId
          )
        );
      })
      .forEach((slot) => {
        warnings.push(
          `${slot.className} class level ${slot.classLevel} has a pending ASI or feat choice.`
        );
      });

    return uniqueCleanArray(
      warnings
    );
  }

  function pruneAbandonedClassFeatureChoices(
    character = creatorState.draft
  ) {
    const activeChoiceIds = new Set();
    const primaryChoiceIds = new Set();
    const removedFeatIds = [];

    getClassProgressionEntries(
      character
    ).forEach((classEntry, classIndex) => {
      const availableIds = new Set();

      collectSection12FeaturesForClassEntry(
        classEntry,
        classIndex
      ).forEach((feature) => {
        availableIds.add(feature.id);
        availableIds.add(
          getSection12FeatureChoiceKey(
            feature
          )
        );
      });

      getUnlockedFeatChoiceSlots(
        character
      )
        .filter((slot) => {
          return (
            slot.classEntryId ===
            getClassProgressionEntryKey(
              classEntry,
              classIndex
            )
          );
        })
        .forEach((slot) => {
          availableIds.add(slot.id);
          availableIds.add(slot.legacyId);
          availableIds.add(slot.featureId);
        });

      availableIds.delete("");

      availableIds.forEach((id) => {
        activeChoiceIds.add(id);

        if (
          isStartingClassEntry(
            classEntry,
            character,
            classIndex
          )
        ) {
          primaryChoiceIds.add(id);
        }
      });

      classEntry.choices = {
        ...(classEntry.choices || {})
      };

      const storedChoices =
        normalizeClassChoiceMap(
          classEntry.choices
            .classFeatures
        );

      Object.keys(storedChoices)
        .forEach((choiceId) => {
          if (availableIds.has(choiceId)) {
            return;
          }

          storedChoices[choiceId]
            .filter((value) => {
              return value.startsWith(
                "feat:"
              );
            })
            .forEach((value) => {
              removedFeatIds.push(
                value.slice(
                  "feat:".length
                )
              );
            });

          delete storedChoices[choiceId];
        });

      classEntry.choices
        .classFeatures =
          storedChoices;
    });

    const compatibilityChoices =
      normalizeClassChoiceMap(
        character.classChoices
      );

    Object.keys(compatibilityChoices)
      .forEach((choiceId) => {
        if (
          primaryChoiceIds.has(choiceId)
        ) {
          return;
        }

        compatibilityChoices[choiceId]
          .filter((value) => {
            return value.startsWith(
              "feat:"
            );
          })
          .forEach((value) => {
            removedFeatIds.push(
              value.slice(
                "feat:".length
              )
            );
          });

        delete compatibilityChoices[
          choiceId
        ];
      });

    character.classChoices =
      compatibilityChoices;

    removedFeatIds.forEach(
      removeSection12AsiFeatIfUnused
    );

    return activeChoiceIds;
  }

  function pruneRemovedClassSpellSources(
    character = creatorState.draft
  ) {
    const store =
      getSection16ClassSourceStore(
        character
      );
    const activeSourceKeys = new Set(
      getSpellcastingClassOptions(
        character
      )
        .map(getSection16SourceKey)
        .filter(Boolean)
    );
    const removedSourceKeys = [];

    Object.keys(store)
      .forEach((sourceKey) => {
        if (
          activeSourceKeys.has(sourceKey)
        ) {
          return;
        }

        removedSourceKeys.push(
          sourceKey
        );
        delete store[sourceKey];
      });

    if (
      character === creatorState.draft &&
      removedSourceKeys.length
    ) {
      syncSection16LegacySpellAliases();
    }

    return removedSourceKeys;
  }

  function refreshClassProgressionDerivedValues(
    options = {}
  ) {
    const draft =
      creatorState.draft;

    const totalLevel =
      recalculateClassTotalLevel(
        draft
      );

    pruneAbandonedClassFeatureChoices(
      draft
    );

    pruneRemovedClassSpellSources(
      draft
    );

    draft.combat.proficiencyBonus =
      getGenericProficiencyBonus(
        totalLevel
      );

    draft.combat.hitDice =
      calculateCharacterHitDice(
        draft
      );

    applyClassProgressionProficiencies(
      draft
    );

    if (
      options.refreshSpecies !== false
    ) {
      clearSection11SpeciesMechanics();
      applySection11SpeciesMechanics();
    }

    applySelectedFeatMechanics();

    refreshSelectedClassFeatures();

    calculateSection16SpellcastingValues({
      markDraft: false
    });

    applyCompatibilityAliases(
      draft
    );

    return totalLevel;
  }

  function tryAddMulticlassClass(
    classId
  ) {
    const cleanClassId =
      cleanString(classId);

    if (!cleanClassId) {
      return {
        ok: false,
        reason: "empty-class-id",
        classId: "",
        className: "",
        message:
          "Choose a class to add first.",
        failedPrerequisites: []
      };
    }

    const selectedClass =
      getAllClassTemplates().find((classData) => {
        return classData.id === cleanClassId;
      });

    if (!selectedClass) {
      return {
        ok: false,
        reason: "class-not-found",
        classId: cleanClassId,
        className: "",
        message:
          "That class could not be found.",
        failedPrerequisites: []
      };
    }

    const classes =
      getClassProgressionEntries();

    const existingClass =
      classes.find((classEntry) => {
        const template =
          resolveClassTemplateForEntry(
            classEntry
          );

        return (
          classEntry?.classId === selectedClass.id ||
          template?.id === selectedClass.id
        );
      });

    if (existingClass) {
      return {
        ok: false,
        reason: "duplicate-class",
        classId: selectedClass.id,
        className: selectedClass.name,
        message:
          "That class is already in this character's progression.",
        failedPrerequisites: []
      };
    }

    const currentTotal =
      recalculateClassTotalLevel(
        creatorState.draft
      );

    if (currentTotal >= 20) {
      return {
        ok: false,
        reason: "maximum-level",
        classId: selectedClass.id,
        className: selectedClass.name,
        message:
          "Character is already level 20.",
        failedPrerequisites: []
      };
    }

    if (classes.length) {
      const failedPrerequisites =
        getMulticlassPrerequisiteResults(
          creatorState.draft,
          selectedClass.id
        ).filter((result) => {
          return !result.met;
        });

      if (failedPrerequisites.length) {
        const failureSummary =
          failedPrerequisites
            .map(
              formatMulticlassPrerequisiteFailure
            )
            .join("; ");

        return {
          ok: false,
          reason: "prerequisites-not-met",
          classId: selectedClass.id,
          className: selectedClass.name,
          message:
            `Multiclass prerequisites are not met: ${failureSummary}.`,
          failedPrerequisites:
            cloneData(
              failedPrerequisites
            )
        };
      }
    }

    if (!classes.length) {
      creatorState.draft
        .classProgression
        .classes = [
          createClassProgressionEntry(
            selectedClass,
            1
          )
        ];
    } else {
      classes.push(
        createClassProgressionEntry(
          selectedClass,
          1
        )
      );
    }

    const totalLevel =
      refreshClassProgressionDerivedValues();

    markDraftChanged();

    return {
      ok: true,
      reason: "added",
      classId: selectedClass.id,
      className: selectedClass.name,
      totalLevel,
      message:
        `${selectedClass.name} added. Use Level Up Workflow to add ${selectedClass.name} levels. Total level is now ${totalLevel}.`,
      failedPrerequisites: []
    };
  }

  function addMulticlassClass(
    classId
  ) {
    const result =
      tryAddMulticlassClass(
        classId
      );

    setStatus(result.message);

    return result.ok;
  }

  function setMulticlassClassLevel(
    classIndex,
    value
  ) {
    const classes =
      getClassProgressionEntries();

    const index =
      Math.max(
        0,
        Math.round(
          safeNumber(classIndex, 0)
        )
      );

    const classEntry =
      classes[index];

    if (!classEntry) {
      return false;
    }

    const otherTotal =
      classes.reduce(
        (sum, entry, entryIndex) => {
          return (
            sum +
            (
              entryIndex === index
                ? 0
                : getClassEntryLevel(
                    entry,
                    1
                  )
            )
          );
        },
        0
      );

    const maximumLevel =
      Math.max(
        1,
        20 - otherTotal
      );

    const nextLevel =
      Math.max(
        1,
        Math.min(
          maximumLevel,
          Math.round(
            safeNumber(value, 1)
          )
        )
      );
    const currentLevel =
      getClassEntryLevel(
        classEntry,
        1
      );

    if (
      currentLevel === nextLevel
    ) {
      return false;
    }

    if (
      nextLevel > currentLevel &&
      classes.length > 1
    ) {
      const failedPrerequisites =
        getMulticlassPrerequisiteResults(
          creatorState.draft
        ).filter((result) => {
          return !result.met;
        });

      if (failedPrerequisites.length) {
        setStatus(
          `Class level was not changed. Multiclass prerequisites are not met: ${failedPrerequisites.map(formatMulticlassPrerequisiteFailure).join("; ")}.`
        );

        return false;
      }

      const pendingChoices =
        getClassProgressionPendingChoiceWarnings(
          creatorState.draft
        );

      if (pendingChoices.length) {
        setStatus(
          `Class level was not changed. Complete pending class choices first: ${pendingChoices.join(" ")}`
        );

        return false;
      }
    }

    classEntry.level =
      nextLevel;

    refreshClassProgressionDerivedValues();
    markDraftChanged();

    return true;
  }

  function adjustMulticlassClassLevel(
    classIndex,
    delta
  ) {
    const classEntry =
      getClassEntryAtIndex(
        classIndex
      );

    if (!classEntry) {
      return false;
    }

    return setMulticlassClassLevel(
      classIndex,
      getClassEntryLevel(
        classEntry,
        1
      ) +
        safeNumber(delta, 0)
    );
  }

  function removeMulticlassClass(
    classIndex
  ) {
    const classes =
      getClassProgressionEntries();

    if (classes.length <= 1) {
      setStatus(
        "A character needs at least one class."
      );
      return false;
    }

    const index =
      Math.max(
        0,
        Math.round(
          safeNumber(classIndex, 0)
        )
      );

    if (!classes[index]) {
      return false;
    }

    if (
      isStartingClassEntry(
        classes[index],
        creatorState.draft,
        index
      )
    ) {
      setStatus(
        "The starting class is set by Character Level 1 and cannot be removed. Move or remove later class levels instead."
      );
      return false;
    }

    classes.splice(index, 1);

    refreshClassProgressionDerivedValues();
    markDraftChanged();

    return true;
  }

  function moveMulticlassClass(
    classIndex,
    delta
  ) {
    const classes =
      getClassProgressionEntries();

    const index =
      Math.max(
        0,
        Math.round(
          safeNumber(classIndex, 0)
        )
      );

    const nextIndex =
      index +
      Math.round(
        safeNumber(delta, 0)
      );

    if (
      !classes[index] ||
      nextIndex < 0 ||
      nextIndex >= classes.length
    ) {
      return false;
    }

    const [entry] =
      classes.splice(index, 1);

    classes.splice(
      nextIndex,
      0,
      entry
    );

    refreshClassProgressionDerivedValues();
    markDraftChanged();

    return true;
  }

  function moveCharacterLevelOrder(
    levelIndex,
    delta
  ) {
    const levelOrder =
      syncClassLevelOrderToClassLevels(
        creatorState.draft
      );

    const index =
      Math.max(
        0,
        Math.round(
          safeNumber(levelIndex, 0)
        )
      );

    const nextIndex =
      index +
      Math.round(
        safeNumber(delta, 0)
      );

    if (
      !levelOrder[index] ||
      nextIndex < 0 ||
      nextIndex >= levelOrder.length
    ) {
      return false;
    }

    const [entry] =
      levelOrder.splice(index, 1);

    levelOrder.splice(
      nextIndex,
      0,
      entry
    );

    creatorState.draft
      .classProgression
      .levelOrder =
        levelOrder;

    refreshClassProgressionDerivedValues();
    markDraftChanged();

    return true;
  }

  function addCharacterLevelToClass(
    classIndex
  ) {
    const classes =
      getClassProgressionEntries();

    const index =
      Math.max(
        0,
        Math.round(
          safeNumber(classIndex, 0)
        )
      );

    const classEntry =
      classes[index];

    if (!classEntry) {
      setStatus(
        "Choose a class before adding a level."
      );

      return false;
    }

    const currentTotal =
      recalculateClassTotalLevel(
        creatorState.draft
      );

    if (currentTotal >= 20) {
      setStatus(
        "Total character level is already 20."
      );

      return false;
    }

    const levelOrder =
      syncClassLevelOrderToClassLevels(
        creatorState.draft
      );

    const classKey =
      getClassProgressionEntryKey(
        classEntry,
        index
      );

    classEntry.level =
      getClassEntryLevel(
        classEntry,
        1
      ) + 1;

    creatorState.draft
      .classProgression
      .levelOrder = [
        ...levelOrder,
        classKey
      ];

    refreshClassProgressionDerivedValues();
    markDraftChanged();

    return true;
  }

  function removeLastCharacterLevel() {
    const classes =
      getClassProgressionEntries();

    const levelOrder =
      syncClassLevelOrderToClassLevels(
        creatorState.draft
      );

    if (levelOrder.length <= 1) {
      setStatus(
        "A character needs at least one level."
      );

      return false;
    }

    const lastClassKey =
      levelOrder[levelOrder.length - 1];

    const classIndex =
      classes.findIndex((classEntry, index) => {
        return (
          getClassProgressionEntryKey(
            classEntry,
            index
          ) === lastClassKey
        );
      });

    const classEntry =
      classes[classIndex];

    if (!classEntry) {
      return false;
    }

    const nextLevel =
      getClassEntryLevel(
        classEntry,
        1
      ) - 1;

    creatorState.draft
      .classProgression
      .levelOrder =
        levelOrder.slice(0, -1);

    if (nextLevel <= 0) {
      classes.splice(
        classIndex,
        1
      );
    } else {
      classEntry.level =
        nextLevel;
    }

    refreshClassProgressionDerivedValues();
    markDraftChanged();

    return true;
  }

  function setMulticlassSubclass(
    classIndex,
    subclassId
  ) {
    const classEntry =
      getClassEntryAtIndex(
        classIndex
      );

    if (!classEntry) {
      return false;
    }

    const template =
      resolveClassTemplateForEntry(
        classEntry
      );

    const cleanSubclassId =
      cleanString(subclassId);

    if (!cleanSubclassId) {
      classEntry.subclassId = "";
      classEntry.subclassName = "";

      classEntry.choices = {
        ...(classEntry.choices || {})
      };

      delete classEntry
        .choices
        .subclassSnapshot;

      refreshClassProgressionDerivedValues();
      markDraftChanged();

      return true;
    }

    const subclass =
      (
        Array.isArray(template?.subclasses)
          ? template.subclasses
          : []
      )
        .map((entry) => {
          return normalizeSection12Subclass(
            entry,
            template?.source || "template"
          );
        })
        .find((entry) => {
          return entry.id === cleanSubclassId;
        });

    if (!subclass) {
      return false;
    }

    classEntry.subclassId =
      subclass.id;

    classEntry.subclassName =
      subclass.name;

    classEntry.choices = {
      ...(classEntry.choices || {}),
      subclassSnapshot:
        cloneData(subclass)
    };

    refreshClassProgressionDerivedValues();
    markDraftChanged();

    return true;
  }

  function blockMulticlassEdit(actionText) {
    const message =
      `${actionText} is handled through the class progression controls for multiclass characters. Existing class data was preserved.`;

    setStatus(message);

    return false;
  }

  function selectClassTemplate(classId) {
    if (isMulticlassDraft()) {
      return blockMulticlassEdit(
        "Changing the primary class"
      );
    }

    const selectedClass =
      getAllClassTemplates().find((classData) => {
        return classData.id === classId;
      });

    if (!selectedClass) {
      return false;
    }

    const totalLevel = clampLevel(
      creatorState.draft.classProgression.totalLevel
    );

    const oldPrimaryClass =
      getPrimaryClassEntry(
        creatorState.draft
      );

    const oldClassSource =
      getClassSourceLabel(
        oldPrimaryClass
      );

    if (oldClassSource) {
      removeSkillProficiencySource(
        oldClassSource
      );

      removeListProficiencySource(
        oldClassSource
      );
    }

    const selectedEntry = {
      entryId: createClassEntryId(
        selectedClass.id || selectedClass.name,
        0,
        new Set(),
        oldPrimaryClass?.entryId
      ),
      classId: selectedClass.id,
      className: selectedClass.name,
      source: selectedClass.source,
      level:
        oldPrimaryClass?.level ||
        totalLevel,
      subclassId: "",
      subclassName: "",
      hitDie: normalizeClassEntryHitDie(
        selectedClass.hitDie,
        8
      ),
      templateSnapshot:
        findDefaultClassDefinition(
          selectedClass.id,
          selectedClass.name
        )
          ? null
          : cloneData(selectedClass),
      choices: {}
    };

    creatorState.draft.classChoices =
      oldPrimaryClass?.classId === selectedClass.id
        ? normalizeClassChoiceMap(
            creatorState.draft.classChoices
          )
        : {};

    creatorState.draft
      .classProgression
      .classes = [
        selectedEntry
      ];

    recalculateClassTotalLevel(
      creatorState.draft
    );

    creatorState.dirty = true;
    markCharacterBuilderAsDraft(
      creatorState.draft
    );

    applyCompatibilityAliases(
      creatorState.draft
    );

    return true;
  }

  function setCurrentStep(stepId) {
    const step = getStepById(stepId);

    creatorState.currentStepId = step.id;
    creatorState.currentStepIndex = getStepIndex(step.id);
    creatorState.draft.builder.currentStep = step.id;

    if (
      !creatorState.draft.builder.visitedSteps.includes(
        step.id
      )
    ) {
      creatorState.draft.builder.visitedSteps.push(
        step.id
      );
    }
  }

  function refreshLoadedClassDerivedValues() {
    if (
      getPrimaryClassEntry(
        creatorState.draft
      )
    ) {
      if (
        isMulticlassDraft(
          creatorState.draft
        )
      ) {
        refreshClassProgressionDerivedValues();
      } else {
        refreshSelectedClassFeatures();
        applyCompatibilityAliases(
          creatorState.draft
        );
      }
    }
  }

  function replaceDraft(character, options = {}) {
    creatorState.multiclassAddStatus = {
      message: "",
      tone: "warning"
    };

    creatorState.draft = normalizeCharacter(character);

    refreshLoadedClassDerivedValues();

    creatorState.currentCharacterId =
      options.characterId ||
      character?.id ||
      null;

    creatorState.dirty =
      options.dirty === true;

    setCurrentStep(
      options.stepId ||
      creatorState.draft.builder.currentStep ||
      "basics"
    );

    return creatorState.draft;
  }

  function startNewDraft() {
    replaceDraft(
      createEmptyCharacter(),
      {
        characterId: null,
        dirty: false,
        stepId: "basics"
      }
    );

    creatorState.viewMode = "builder";

    setStatus("New character started.");

    return creatorState.draft;
  }

  function confirmDiscardUnsavedDraft(
    actionDescription
  ) {
    if (creatorState.dirty !== true) {
      return true;
    }

    if (typeof window === "undefined") {
      return false;
    }

    return window.confirm(
      `Discard unsaved changes before ${actionDescription}?`
    );
  }

  function duplicateIntoDraft(character) {
    const copy = normalizeCharacter(character);

    copy.identity.name = copy.identity.name
      ? `${copy.identity.name} Copy`
      : "Character Copy";

    markCharacterBuilderAsDraft(copy);

    applyCompatibilityAliases(copy);

    replaceDraft(
      copy,
      {
        characterId: null,
        dirty: true,
        stepId: "save"
      }
    );

    creatorState.viewMode = "builder";

    setStatus(
      "Duplicate draft created. Saving it will create a separate character."
    );

    return creatorState.draft;
  }

  function setDraftValue(path, value) {
    const parts = String(path || "")
      .split(".")
      .filter(Boolean);

    if (!parts.length) {
      return;
    }

    let cursor = creatorState.draft;

    for (
      let index = 0;
      index < parts.length - 1;
      index += 1
    ) {
      const part = parts[index];

      if (
        !cursor[part] ||
        typeof cursor[part] !== "object"
      ) {
        cursor[part] = {};
      }

      cursor = cursor[part];
    }

    cursor[parts[parts.length - 1]] = value;
    creatorState.dirty = true;
    markCharacterBuilderAsDraft(
      creatorState.draft
    );

    applyCompatibilityAliases(
      creatorState.draft
    );
  }

  function getCharacterSnapshot() {
    return createCharacterPayload(
      creatorState.draft
    );
  }


// =====================================================
// CHARACTER CREATOR SECTION 6 — WIZARD DOM / ELEMENTS
// =====================================================

  const W = {
    root: null,
    actionBar: null,
    stepRail: null,
    stepBody: null,
    previousButton: null,
    nextButton: null,
    status: null,
    importInput: null
  };

  const wizardRuntime = {
    shellBuilt: false,
    eventsConnected: false,
    popstateConnected: false,
    draftPersistenceLifecycleConnected: false
  };

  function refreshWizardElements() {
    refreshElements();

    W.root = $("characterWizardRoot");
    W.actionBar = C.actionBar;
    W.stepRail = $("characterWizardStepRail");
    W.stepBody = $("characterWizardStepBody");
    W.previousButton = $("characterPreviousStepButton");
    W.nextButton = $("characterNextStepButton");
    W.status = $("characterCreatorStatus");
    W.importInput = $("characterWizardImportInput");
  }

