// =====================================================
// CHARACTER CREATOR SECTION 13 — LEVEL / ABILITY SCORES
// =====================================================

  const SECTION13_POINT_BUY_COSTS = Object.freeze({
    8: 0,
    9: 1,
    10: 2,
    11: 3,
    12: 4,
    13: 5,
    14: 7,
    15: 9
  });

  function getSection13AbilityName(abilityId) {
    return (
      ABILITY_DEFINITIONS.find((ability) => {
        return ability.id === abilityId;
      })?.name ||
      String(abilityId || "").toUpperCase()
    );
  }

  function getSection13AbilityScore(abilityId) {
    return Math.max(
      1,
      Math.min(
        30,
        Math.round(
          safeNumber(
            creatorState.draft
              .abilities
              .scores[abilityId],
            10
          )
        )
      )
    );
  }

  function getSection13BaseAbilityScore(abilityId) {
    return Math.max(
      1,
      Math.min(
        30,
        Math.round(
          safeNumber(
            creatorState.draft
              .abilities
              .base[abilityId],
            10
          )
        )
      )
    );
  }

  function getSection13AbilityBonus(abilityId) {
    return safeNumber(
      creatorState.draft
        .abilities
        .bonuses?.[abilityId],
      0
    );
  }

  function renderSection13AbilityScoreDetails(
    abilityId
  ) {
    const base =
      getSection13BaseAbilityScore(
        abilityId
      );

    const bonus =
      getSection13AbilityBonus(
        abilityId
      );

    const finalScore =
      getSection13AbilityScore(
        abilityId
      );

    const modifier =
      calculateAbilityModifier(
        finalScore
      );

    return `
      <p class="small">
        Base Score:
        <b>${base}</b>

        <br>

        Species/Other Bonuses:
        <b>${formatSignedNumber(bonus)}</b>

        <br>

        Final Score:
        <b>${finalScore}</b>

        <br>

        Modifier:
        <b>${formatSignedNumber(modifier)}</b>
      </p>
    `;
  }

  function setSection13AbilityMethod(method) {
    const validMethod =
      ABILITY_SCORE_METHODS.some((item) => {
        return item.id === method;
      })
        ? method
        : "manual";

    creatorState.draft
      .abilities
      .method = validMethod;

    if (validMethod === "standard-array") {
      applySection13StandardArray();
      return;
    }

    if (validMethod === "point-buy") {
      applySection13PointBuyDefaults();
      return;
    }

    if (
      validMethod === "rolled" &&
      !Array.isArray(
        creatorState.draft
          .abilities
          .assignmentPool
      )
    ) {
      creatorState.draft
        .abilities
        .assignmentPool = [];
    }

    markDraftChanged();
  }

  function applySection13Scores(scoreMap) {
    ABILITY_DEFINITIONS.forEach((ability) => {
      const score = Math.max(
        1,
        Math.min(
          30,
          Math.round(
            safeNumber(
              scoreMap?.[ability.id],
              10
            )
          )
        )
      );

      creatorState.draft
        .abilities
        .base[ability.id] = score;
    });

    recalculateAbilityTotals(
      creatorState.draft
    );

    creatorState.draft.builder.validation = {
      ...(creatorState.draft.builder.validation || {}),
      abilitiesTouched: true
    };

    applyCompatibilityAliases(
      creatorState.draft
    );

    if (
      creatorState.draft
        .magic
        .spellcastingAbility
    ) {
      calculateSection16SpellcastingValues({
        markDraft: false
      });
    }

    markDraftChanged();
    refreshSection13AbilitySummary();
  }

  function applySection13StandardArray() {
    creatorState.draft
      .abilities
      .method = "standard-array";

    creatorState.draft
      .abilities
      .assignmentPool = [
        15,
        14,
        13,
        12,
        10,
        8
      ];

    applySection13Scores({
      str: 15,
      dex: 14,
      con: 13,
      int: 12,
      wis: 10,
      cha: 8
    });
  }

  function assignSection13StandardScore(
    abilityId,
    newScore
  ) {
    const pool = [
      15,
      14,
      13,
      12,
      10,
      8
    ];

    const score = Math.round(
      safeNumber(newScore, 10)
    );

    if (!pool.includes(score)) {
      return false;
    }

    const currentScore =
      getSection13BaseAbilityScore(
        abilityId
      );

    const otherAbility =
      ABILITY_DEFINITIONS.find(
        (ability) => {
          return (
            ability.id !== abilityId &&
            getSection13BaseAbilityScore(
              ability.id
            ) === score
          );
        }
      );

    creatorState.draft
      .abilities
      .base[abilityId] = score;

    if (otherAbility) {
      creatorState.draft
        .abilities
        .base[otherAbility.id] =
          currentScore;
    }

    recalculateAbilityTotals(
      creatorState.draft
    );

    applyCompatibilityAliases(
      creatorState.draft
    );

    markDraftChanged();

    return true;
  }

  function applySection13PointBuyDefaults() {
    creatorState.draft
      .abilities
      .method = "point-buy";

    creatorState.draft
      .abilities
      .assignmentPool = [];

    applySection13Scores({
      str: 8,
      dex: 8,
      con: 8,
      int: 8,
      wis: 8,
      cha: 8
    });
  }

  function getSection13PointBuySpent() {
    return ABILITY_DEFINITIONS.reduce(
      (total, ability) => {
        const score = Math.max(
          8,
          Math.min(
            15,
            getSection13BaseAbilityScore(
              ability.id
            )
          )
        );

        return (
          total +
          safeNumber(
            SECTION13_POINT_BUY_COSTS[
              score
            ],
            0
          )
        );
      },
      0
    );
  }

  function changeSection13PointBuyScore(
    abilityId,
    direction
  ) {
    const currentScore = Math.max(
      8,
      Math.min(
        15,
        getSection13BaseAbilityScore(
          abilityId
        )
      )
    );

    const nextScore =
      currentScore + direction;

    if (
      nextScore < 8 ||
      nextScore > 15
    ) {
      return false;
    }

    const currentCost =
      SECTION13_POINT_BUY_COSTS[
        currentScore
      ];

    const nextCost =
      SECTION13_POINT_BUY_COSTS[
        nextScore
      ];

    const spent =
      getSection13PointBuySpent();

    const nextSpent =
      spent -
      currentCost +
      nextCost;

    if (nextSpent > 27) {
      setStatus(
        "Point buy cannot exceed 27 points."
      );

      return false;
    }

    creatorState.draft
      .abilities
      .base[abilityId] = nextScore;

    recalculateAbilityTotals(
      creatorState.draft
    );

    applyCompatibilityAliases(
      creatorState.draft
    );

    markDraftChanged();

    return true;
  }

  function rollSection13AbilityScore() {
    const rolls = Array.from(
      { length: 4 },
      () => {
        return (
          Math.floor(
            Math.random() * 6
          ) + 1
        );
      }
    ).sort((a, b) => a - b);

    return rolls
      .slice(1)
      .reduce(
        (total, roll) => {
          return total + roll;
        },
        0
      );
  }

  function rollSection13ScorePool() {
    creatorState.draft
      .abilities
      .method = "rolled";

    creatorState.draft
      .abilities
      .assignmentPool =
        Array.from(
          { length: 6 },
          () => {
            return rollSection13AbilityScore();
          }
        );

    markDraftChanged();

    return creatorState.draft
      .abilities
      .assignmentPool;
  }

  function applySection13RolledScores() {
    const pool =
      Array.isArray(
        creatorState.draft
          .abilities
          .assignmentPool
      )
        ? creatorState.draft
            .abilities
            .assignmentPool
        : [];

    if (pool.length !== 6) {
      alert(
        "Roll six scores before applying them."
      );

      return false;
    }

    const scoreMap = {};

    ABILITY_DEFINITIONS.forEach(
      (ability, index) => {
        scoreMap[ability.id] =
          safeNumber(
            pool[index],
            10
          );
      }
    );

    applySection13Scores(
      scoreMap
    );

    return true;
  }

  function getSection13HitDieSize() {
    const selectedClass =
      getSelectedClassTemplate();

    const text = String(
      selectedClass?.hitDie ||
      "d8"
    );

    return Math.max(
      4,
      Math.round(
        safeNumber(
          text.replace(/[^0-9]/g, ""),
          8
        )
      )
    );
  }

  function calculateSection13SuggestedHp() {
    const selectedClass =
      getSelectedClassTemplate();

    if (!selectedClass) {
      return null;
    }

    return calculateCharacterHp(
      creatorState.draft
    ).maximumHp;
  }

  function formatSection13HpRolls(
    values
  ) {
    return Array.isArray(values)
      ? values
          .map((value) => {
            return value &&
              typeof value === "object" &&
              !Array.isArray(value)
              ? safeNumber(value.roll, 0)
              : safeNumber(value, 0);
          })
          .filter((value) => {
            return value > 0;
          })
          .join(", ")
      : "";
  }

  function parseSection13HpRolls(
    value
  ) {
    return String(value || "")
      .split(/[\n,]+/)
      .map((item) => {
        return Math.round(
          safeNumber(item.trim(), 0)
        );
      })
      .filter((item) => {
        return item > 0;
      });
  }

  function createSection13HpRollRecord(
    levelRecord,
    roll
  ) {
    const dieSize =
      getHitDieSize(
        levelRecord?.hitDie
      );

    return {
      characterLevel:
        Math.max(
          2,
          Math.round(
            safeNumber(
              levelRecord?.characterLevel,
              2
            )
          )
        ),
      classId:
        cleanString(
          levelRecord?.classId
        ),
      classEntryId:
        cleanString(
          levelRecord?.classEntryId
        ),
      className:
        cleanString(
          levelRecord?.className,
          "Class"
        ),
      hitDie:
        cleanString(
          levelRecord?.hitDie,
          "d8"
        ),
      roll:
        Math.max(
          1,
          Math.min(
            dieSize,
            Math.round(
              safeNumber(
                roll,
                Math.floor(dieSize / 2) + 1
              )
            )
          )
        )
    };
  }

  function getSection13HpRollState(
    character = creatorState.draft,
    hpCalculation =
      normalizeHpCalculation(
        character?.combat?.hpCalculation,
        character?.combat?.maxHp
      )
  ) {
    const levelRecords =
      getCharacterLevelHitDieRecords(
        character
      );

    const laterLevels =
      levelRecords.slice(1);

    const rawRecords =
      getHpRollRawRecords(
        hpCalculation.laterLevelValues
      );

    const activeRolls =
      normalizeHpRollRecordsForCharacter(
        hpCalculation.laterLevelValues,
        character
      );

    const activeLevelNumbers =
      new Set(
        laterLevels.map((record) => {
          return record.characterLevel;
        })
      );

    const warnings = [];

    rawRecords.forEach((rawRecord) => {
      const activeLevel =
        laterLevels.find((record) => {
          return (
            record.characterLevel ===
            rawRecord.characterLevel
          );
        });

      if (!activeLevel) {
        warnings.push(
          `Stored rolled HP for level ${rawRecord.characterLevel} is inactive after the current class level changes.`
        );

        return;
      }

      if (
        !hpRollRawMatchesLevel(
          rawRecord,
          activeLevel
        )
      ) {
        warnings.push(
          `Level ${rawRecord.characterLevel} now uses ${activeLevel.className || "Class"} ${activeLevel.hitDie || "d8"}; the stored roll is adjusted to that Hit Die.`
        );
      }

      const dieSize =
        getHitDieSize(
          activeLevel.hitDie
        );

      if (rawRecord.roll > dieSize) {
        warnings.push(
          `Level ${rawRecord.characterLevel} rolled HP is capped at ${activeLevel.hitDie || `d${dieSize}`}.`
        );
      }
    });

    return {
      levelRecords,
      laterLevels,
      activeRolls,
      rawRecords,
      inactiveRecords:
        rawRecords.filter((record) => {
          return !activeLevelNumbers.has(
            record.characterLevel
          );
        }),
      warnings: [
        ...new Set(warnings)
      ]
    };
  }

  function setSection13HpRollValue(
    characterLevel,
    rawValue
  ) {
    const hpCalculation =
      normalizeHpCalculation(
        creatorState.draft
          .combat
          .hpCalculation,
        creatorState.draft
          .combat
          .maxHp
      );

    const levelNumber =
      Math.max(
        2,
        Math.round(
          safeNumber(characterLevel, 2)
        )
      );

    const rollState =
      getSection13HpRollState(
        creatorState.draft,
        hpCalculation
      );

    const levelRecord =
      rollState.laterLevels.find(
        (record) => {
          return (
            record.characterLevel ===
            levelNumber
          );
        }
      );

    if (!levelRecord) {
      return false;
    }

    const nextActiveRolls =
      rollState.activeRolls.map(
        (record) => {
          if (
            record.characterLevel !==
            levelNumber
          ) {
            return record;
          }

          return createSection13HpRollRecord(
            levelRecord,
            rawValue
          );
        }
      );

    const activeLevels =
      new Set(
        rollState.laterLevels.map(
          (record) => {
            return record.characterLevel;
          }
        )
      );

    const inactiveRolls =
      rollState.rawRecords
        .filter((record) => {
          return !activeLevels.has(
            record.characterLevel
          );
        })
        .map((record) => {
          return {
            characterLevel:
              record.characterLevel,
            classId:
              record.classId,
            classEntryId:
              record.classEntryId,
            className:
              record.className,
            hitDie:
              record.hitDie,
            roll:
              record.roll
          };
        });

    creatorState.draft
      .combat
      .hpCalculation = {
        ...hpCalculation,
        laterLevelValues: [
          ...nextActiveRolls,
          ...inactiveRolls
        ]
      };

    applyCompatibilityAliases(
      creatorState.draft
    );

    markDraftChanged();

    return true;
  }

  function renderSection13RolledHpInputs(
    hpCalculation
  ) {
    const rollState =
      getSection13HpRollState(
        creatorState.draft,
        hpCalculation
      );

    if (!rollState.levelRecords.length) {
      return `
        <div class="hg-character-placeholder">
          Choose a class before entering rolled HP.
        </div>
      `;
    }

    const rollByLevel =
      new Map(
        rollState.activeRolls.map((roll) => {
          return [
            roll.characterLevel,
            roll
          ];
        })
      );

    const warningHtml =
      rollState.warnings.length
        ? `
          <div class="hg-character-warning">
            ${rollState.warnings
              .map((warning) => {
                return `<p>${escapeHtml(warning)}</p>`;
              })
              .join("")}
          </div>
        `
        : "";

    return `
      <hr>

      <h3>Rolled HP by Level</h3>

      ${warningHtml}

      <div class="hg-character-choice-grid">
        ${rollState.levelRecords
          .map((levelRecord) => {
            const dieSize =
              getHitDieSize(
                levelRecord.hitDie
              );

            const rollRecord =
              rollByLevel.get(
                levelRecord.characterLevel
              );

            const isFirstLevel =
              levelRecord.characterLevel === 1;

            return `
              <article class="hg-character-choice-card">
                <h3>
                  Level ${levelRecord.characterLevel}
                </h3>

                <p>
                  <b>Class:</b>
                  ${escapeHtml(
                    levelRecord.className ||
                    "Class"
                  )}

                  <br>

                  <b>Hit Die:</b>
                  ${escapeHtml(
                    levelRecord.hitDie ||
                    "d8"
                  )}
                </p>

                ${
                  isFirstLevel
                    ? `
                      <p class="small">
                        Level 1 uses the full Hit Die unless the Level 1 HP Override field is set.
                      </p>
                    `
                    : `
                      <div class="hg-character-field">
                        <label for="ccHpRollLevel-${levelRecord.characterLevel}">
                          Roll
                        </label>

                        <input
                          id="ccHpRollLevel-${levelRecord.characterLevel}"
                          type="number"
                          min="1"
                          max="${dieSize}"
                          step="1"
                          value="${escapeHtml(
                            rollRecord?.roll ?? ""
                          )}"
                          data-hp-roll-level="${levelRecord.characterLevel}"
                          data-hp-roll-hit-die="${escapeHtml(
                            levelRecord.hitDie ||
                            "d8"
                          )}"
                        >

                        <p class="small">
                          Enter 1-${dieSize}; this roll is capped by ${escapeHtml(
                            levelRecord.hitDie ||
                            `d${dieSize}`
                          )}.
                        </p>
                      </div>
                    `
                }
              </article>
            `;
          })
          .join("")}
      </div>
    `;
  }

  function applySection13SuggestedHp() {
    const selectedClass =
      getSelectedClassTemplate();

    if (!selectedClass) {
      alert(
        "Choose a class before calculating HP."
      );

      return null;
    }

    const hpSummary =
      calculateCharacterHp(
        creatorState.draft
      );

    creatorState.draft
      .combat
      .maxHp = hpSummary.maximumHp;

    creatorState.draft
      .combat
      .currentHp = hpSummary.maximumHp;

    creatorState.draft
      .combat
      .hpCalculation =
        normalizeHpCalculation(
          {
          ...creatorState.draft
            .combat
            .hpCalculation,
          lastCalculatedConModifier:
              calculateAbilityModifier(
                getSection13AbilityScore(
                  "con"
                )
              )
          },
          hpSummary.maximumHp
        );

    applyCompatibilityAliases(
      creatorState.draft
    );

    markDraftChanged();

    return hpSummary.maximumHp;
  }

  function refreshSection13LevelProgression() {
    if (isMulticlassDraft()) {
      refreshClassProgressionDerivedValues();
      markDraftChanged();

      return true;
    }

    const selectedClass =
      getSelectedClassTemplate();

    const level = clampLevel(
      creatorState.draft
        .classProgression
        .totalLevel
    );

    const primaryClass =
      getPrimaryClassEntry(
        creatorState.draft
      );

    if (primaryClass) {
      primaryClass.level = level;
    }

    syncClassLevelOrderToClassLevels(
      creatorState.draft
    );

    creatorState.draft
      .combat
      .proficiencyBonus =
        getGenericProficiencyBonus(
          level
        );

    clearSection11SpeciesMechanics();
    applySection11SpeciesMechanics();

    if (
      selectedClass &&
      typeof applySection12ClassDefaults ===
        "function"
    ) {
      applySection12ClassDefaults(
        selectedClass
      );
    } else if (
      typeof refreshSelectedClassFeatures ===
      "function"
    ) {
      refreshSelectedClassFeatures();
    }

    applyCompatibilityAliases(
      creatorState.draft
    );

    markDraftChanged();
  }

  function renderSection13HitDice() {
    const hitDice =
      calculateCharacterHitDice(
        creatorState.draft
      );

    if (!hitDice.length) {
      return `
        <div class="hg-character-placeholder">
          No hit dice are currently recorded.
        </div>
      `;
    }

    return hitDice
      .map((entry) => {
        return `
          <article class="hg-character-choice-card">
            <h3>
              ${escapeHtml(
                entry.className ||
                getSafeClassName() ||
                "Class"
              )}
            </h3>

            <p>
              ${Math.max(
                1,
                Math.round(
                  safeNumber(
                    entry.count,
                    1
                  )
                )
              )}

              ${escapeHtml(
                entry.die ||
                "d8"
              )}

              hit dice
            </p>
          </article>
        `;
      })
      .join("");
  }

  function renderSection13HpGuide() {
    const draft = creatorState.draft;

    const level = clampLevel(
      draft.classProgression.totalLevel
    );

    const selectedClass =
      getSelectedClassTemplate();

    const hitDie =
      selectedClass?.hitDie || "d8";

    const dieSize = getHitDieSize(hitDie);

    const constitutionModifier =
      calculateAbilityModifier(
        getAbilityScore(draft, "con")
      );

    const levelOneHp = Math.max(
      1,
      dieSize + constitutionModifier
    );

    const fixedDieAverage =
      Math.floor(dieSize / 2) + 1;

    const fixedLaterGain = Math.max(
      1,
      fixedDieAverage +
      constitutionModifier
    );

    return `
      <div class="hg-character-current-choice">
        <b>Level 1 HP:</b>
        Hit die maximum (${dieSize}) + Constitution modifier
        (${formatSignedNumber(
          constitutionModifier
        )}) = ${levelOneHp} HP.

        <br>

        <b>Later Levels:</b>
        Choose the fixed average or enter a roll for each level.
        Die averages are d6 = 4, d8 = 5, d10 = 6, and d12 = 7.
        Add your Constitution modifier each level; the minimum gain
        is 1 HP per level. Your current fixed gain is
        ${fixedLaterGain} HP per later level.

        <br>

        <b>Hit Dice:</b>
        A single-class level ${level} character has ${level}
        ${escapeHtml(hitDie)} hit ${level === 1 ? "die" : "dice"}.
        Hit-dice count equals class level. Single-class creation is
        the primary workflow for now.
      </div>
    `;
  }

  function renderSection13ArmorClassGuide() {
    const draft = creatorState.draft;

    const dexterityModifier =
      calculateAbilityModifier(
        getAbilityScore(draft, "dex")
      );

    const constitutionModifier =
      calculateAbilityModifier(
        getAbilityScore(draft, "con")
      );

    const wisdomModifier =
      calculateAbilityModifier(
        getAbilityScore(draft, "wis")
      );

    const armorClass =
      calculateArmorClassOptions(draft)
        .selected;

    return `
      <div class="hg-character-current-choice">
        <b>Armor Class Basics:</b>
        Unarmored AC = 10 + Dexterity modifier
        (${formatSignedNumber(
          dexterityModifier
        )}). Light armor = armor base + full Dexterity modifier.
        Medium armor = armor base + Dexterity modifier, maximum +2.
        Heavy armor uses its armor base with no Dexterity modifier.

        <br>

        <b>Shields:</b>
        An equipped shield adds +2 AC before any magical bonus.

        <br>

        <b>Class Defenses:</b>
        Barbarian Unarmored Defense = 10 + Dexterity
        (${formatSignedNumber(
          dexterityModifier
        )}) + Constitution (${formatSignedNumber(
          constitutionModifier
        )}). Monk Unarmored Defense = 10 + Dexterity
        (${formatSignedNumber(
          dexterityModifier
        )}) + Wisdom (${formatSignedNumber(
          wisdomModifier
        )}) and cannot use a shield. If more than one unarmored
        formula is available, select one formula; their ability
        modifiers never combine.

        <br>

        <b>Current AC:</b>
        ${armorClass.total} using
        ${escapeHtml(armorClass.label)}
        (${escapeHtml(armorClass.breakdown)}).
        Manual override remains available in the AC controls below.
      </div>
    `;
  }

  function renderLevelStep() {
    const draft =
      creatorState.draft;

    const isMulticlass =
      isMulticlassDraft(draft);

    const level = clampLevel(
      draft.classProgression
        .totalLevel
    );

    const selectedClass =
      getSelectedClassTemplate();

    const suggestedHp =
      calculateSection13SuggestedHp();

    const suggestedHpLabel =
      suggestedHp === null
        ? "Choose a class to calculate"
        : suggestedHp;

    const hpSummary =
      calculateCharacterHp(draft);

    const hpCalculation =
      normalizeHpCalculation(
        draft.combat.hpCalculation,
        draft.combat.maxHp
      );

    const armorClass =
      calculateArmorClassOptions(draft)
        .selected;

    const armorClassOptions =
      calculateArmorClassOptions(draft)
        .options;

    const initiative =
      calculateCharacterInitiative(draft);

    const hpModeChoices = [
      {
        value: "fixed",
        label: "Fixed Average"
      },
      {
        value: "rolled",
        label: "Rolled"
      },
      {
        value: "manual",
        label: "Manual Override"
      }
    ];

    const armorClassModeChoices = [
      {
        value: "auto",
        label: "Automatic"
      },
      {
        value: "manual",
        label: "Manual Override"
      }
    ];

    const armorClassMethodChoices =
      armorClassOptions.map((option) => {
        return {
          value: option.id,
          label:
            `${option.label} (${option.total})`
        };
      });

    return `
      ${
        isMulticlass
          ? `
            ${renderMulticlassProgressionEditor(
              draft
            )}

            ${renderMulticlassLevelBreakdown(
              draft
            )}
          `
          : ""
      }

      ${renderSection13HpGuide()}

      ${renderSection13ArmorClassGuide()}

      <div class="hg-character-current-choice">
        <b>Current progression:</b>

        Level ${level}

        ${escapeHtml(
          getSafeClassName() ||
          "No class selected"
        )}

        <br>

        <b>Proficiency Bonus:</b>

        +${Math.max(
          0,
          getCharacterProficiencyBonus(
            draft
          )
        )}

        <br>

        <b>Calculated HP:</b>

        ${hpSummary.maximumHp}

        <span class="small">
          (${escapeHtml(hpSummary.mode)}, ${escapeHtml(hpSummary.hitDie)}${
            hpSummary.speciesHpBonus
              ? `, Dwarven Toughness +${hpSummary.speciesHpBonus}`
              : ""
          })
        </span>

        <br>

        <b>Calculated AC:</b>

        ${armorClass.total}

        <span class="small">
          (${escapeHtml(armorClass.label)})
        </span>

        <br>

        <b>Calculated Initiative:</b>

        ${formatSection17Modifier(
          initiative.total
        )}
      </div>

      <div class="hg-character-field-grid three">
        ${wizardField(
          isMulticlass
            ? "Total Character Level"
            : "Class Level",
          "ccCharacterLevel",
          level,
          {
            type: "number",
            valueType: "integer",
            extra:
              `min="1" max="20" step="1" data-level-input="true"${
                isMulticlass
                  ? ' disabled data-multiclass-total="true"'
                  : ""
              }`
          }
        )}

        ${wizardSelect(
          "HP Calculation",
          "ccHpCalculationMode",
          hpCalculation.mode,
          hpModeChoices,
          {
            path:
              "combat.hpCalculation.mode"
          }
        )}

        ${wizardField(
          "Level 1 HP Override",
          "ccHpLevelOneValue",
          hpCalculation.levelOneValue === null
            ? ""
            : hpCalculation.levelOneValue,
          {
            type: "number",
            path:
              "combat.hpCalculation.levelOneValue",
            valueType: "number",
            extra:
              'min="1" step="1"'
          }
        )}

        ${wizardField(
          "Manual HP Override",
          "ccHpManualOverride",
          hpCalculation.manualOverride === null
            ? ""
            : hpCalculation.manualOverride,
          {
            type: "number",
            path:
              "combat.hpCalculation.manualOverride",
            valueType: "number",
            extra:
              'min="1" step="1"'
          }
        )}

        ${wizardField(
          "Maximum HP",
          "ccMaximumHp",
          draft.combat.maxHp,
          {
            type: "number",
            path: "combat.maxHp",
            valueType: "number",
            extra:
              'min="1" step="1"'
          }
        )}

        ${wizardField(
          "Current HP",
          "ccCurrentHp",
          draft.combat.currentHp,
          {
            type: "number",
            path: "combat.currentHp",
            valueType: "number",
            extra:
              'min="0" step="1"'
          }
        )}

        ${wizardField(
          "Temporary HP",
          "ccTemporaryHp",
          draft.combat.temporaryHp,
          {
            type: "number",
            path: "combat.temporaryHp",
            valueType: "number",
            extra:
              'min="0" step="1"'
          }
        )}

        ${wizardSelect(
          "Armor Class Mode",
          "ccArmorClassMode",
          draft.combat.armorClassMode,
          armorClassModeChoices,
          {
            path:
              "combat.armorClassMode"
          }
        )}

        ${
          armorClassMethodChoices.length
            ? wizardSelect(
                "AC Calculation",
                "ccSelectedArmorClassMethod",
                draft.combat.selectedArmorClassMethod ||
                armorClass.id,
                armorClassMethodChoices,
                {
                  path:
                    "combat.selectedArmorClassMethod"
                }
              )
            : ""
        }

        ${wizardField(
          "Manual AC",
          "ccManualArmorClass",
          draft.combat.manualArmorClass ??
          draft.combat.armorClass,
          {
            type: "number",
            path: "combat.manualArmorClass",
            valueType: "number",
            extra:
              'min="0" step="1"'
          }
        )}

        ${wizardField(
          "AC Bonus",
          "ccArmorClassBonus",
          draft.combat.armorClassBonus,
          {
            type: "number",
            path:
              "combat.armorClassBonus",
            valueType: "number",
            extra:
              'step="1"'
          }
        )}

        ${wizardField(
          "Initiative Bonus",
          "ccInitiativeBonus",
          draft.combat.initiativeBonus,
          {
            type: "number",
            path: "combat.initiativeBonus",
            valueType: "number",
            extra:
              'step="1"'
          }
        )}
      </div>

      ${
        hpCalculation.mode === "rolled"
          ? renderSection13RolledHpInputs(
              hpCalculation
            )
          : ""
      }

      <div class="hg-character-inline-actions">
        <button
          type="button"
          data-cc-action="refresh-level-progression"
        >
          Refresh Level Progression
        </button>

        <button
          type="button"
          data-cc-action="calculate-character-hp"
          ${suggestedHp === null ? "disabled" : ""}
        >
          Apply Calculated HP (${hpSummary.maximumHp || suggestedHpLabel})
        </button>
      </div>

      <hr>

      <h3>Movement Speeds</h3>

      <div class="hg-character-field-grid three">
        ${wizardField(
          "Walking Speed",
          "ccWalkSpeed",
          draft.combat.speed.walk,
          {
            type: "number",
            path: "combat.speed.walk",
            valueType: "number",
            extra:
              'min="0" step="5"'
          }
        )}

        ${wizardField(
          "Climbing Speed",
          "ccClimbSpeed",
          draft.combat.speed.climb,
          {
            type: "number",
            path: "combat.speed.climb",
            valueType: "number",
            extra:
              'min="0" step="5"'
          }
        )}

        ${wizardField(
          "Swimming Speed",
          "ccSwimSpeed",
          draft.combat.speed.swim,
          {
            type: "number",
            path: "combat.speed.swim",
            valueType: "number",
            extra:
              'min="0" step="5"'
          }
        )}

        ${wizardField(
          "Flying Speed",
          "ccFlySpeed",
          draft.combat.speed.fly,
          {
            type: "number",
            path: "combat.speed.fly",
            valueType: "number",
            extra:
              'min="0" step="5"'
          }
        )}

        ${wizardField(
          "Burrowing Speed",
          "ccBurrowSpeed",
          draft.combat.speed.burrow,
          {
            type: "number",
            path: "combat.speed.burrow",
            valueType: "number",
            extra:
              'min="0" step="5"'
          }
        )}

        ${wizardField(
          "Special Movement Notes",
          "ccSpecialMovement",
          safeDisplayString(
            draft.combat.speed.special
          ),
          {
            path: "combat.speed.special",
            placeholder:
              "Hover, teleport, conditional movement..."
          }
        )}
      </div>

      <hr>

      <h3>Hit Dice</h3>

      <p>
        ${
          isMulticlass
            ? "This class progression currently uses class-specific"
            : "The selected class currently uses a"
        }
        <b>${escapeHtml(
          isMulticlass
            ? "hit dice"
            : selectedClass?.hitDie ||
              "d8"
        )}</b>
        ${isMulticlass ? "." : "hit die."}
      </p>

      <div class="hg-character-choice-grid">
        ${renderSection13HitDice()}
      </div>
    `;
  }

  function renderSection13ManualAbilities() {
    return `
      <div class="hg-character-choice-grid">
        ${ABILITY_DEFINITIONS.map(
          (ability) => {
            return `
              <article class="hg-character-choice-card">
                <h3>
                  ${escapeHtml(
                    ability.name
                  )}
                </h3>

                ${wizardField(
                  "Base Score",
                  `ccAbility-${ability.id}`,
                  getSection13BaseAbilityScore(
                    ability.id
                  ),
                  {
                    type: "number",
                    extra:
                      `min="1" max="30" step="1" data-ability-id="${escapeHtml(
                        ability.id
                      )}"`
                  }
                )}

                ${renderSection13AbilityScoreDetails(
                  ability.id
                )}
              </article>
            `;
          }
        ).join("")}
      </div>
    `;
  }

  function renderSection13StandardArray() {
    const choices = [
      15,
      14,
      13,
      12,
      10,
      8
    ].map((score) => {
      return {
        value: score,
        label: String(score)
      };
    });

    return `
      <div class="hg-character-warning">
        Each score can only be assigned once. Choosing a
        score already in use swaps the two abilities.
      </div>

      <div class="hg-character-choice-grid">
        ${ABILITY_DEFINITIONS.map(
          (ability) => {
            return `
              <article class="hg-character-choice-card">
                <h3>
                  ${escapeHtml(
                    ability.name
                  )}
                </h3>

                ${wizardSelect(
                  "Base Score",
                  `ccStandard-${ability.id}`,
                  getSection13BaseAbilityScore(
                    ability.id
                  ),
                  choices,
                  {
                    extra:
                      `data-standard-ability-id="${escapeHtml(
                        ability.id
                      )}"`
                  }
                )}

                ${renderSection13AbilityScoreDetails(
                  ability.id
                )}
              </article>
            `;
          }
        ).join("")}
      </div>

      <div class="hg-character-inline-actions">
        <button
          type="button"
          data-cc-action="reset-standard-array"
        >
          Reset Standard Array
        </button>
      </div>
    `;
  }

  function renderSection13PointBuy() {
    const spent =
      getSection13PointBuySpent();

    const remaining =
      Math.max(0, 27 - spent);

    return `
      <div class="hg-character-current-choice">
        <b>Points spent:</b>
        ${spent} / 27

        <br>

        <b>Points remaining:</b>
        ${remaining}
      </div>

      <div class="hg-character-choice-grid">
        ${ABILITY_DEFINITIONS.map(
          (ability) => {
            const baseScore =
              Math.max(
                8,
                Math.min(
                  15,
                  getSection13BaseAbilityScore(
                    ability.id
                  )
                )
              );

            const cost =
              SECTION13_POINT_BUY_COSTS[
                baseScore
              ];

            return `
              <article class="hg-character-choice-card">
                <h3>
                  ${escapeHtml(
                    ability.name
                  )}
                </h3>

                <p>
                  <b>Base Score:</b>
                  ${baseScore}

                  <br>

                  <b>Species/Other Bonuses:</b>
                  ${formatSignedNumber(
                    getSection13AbilityBonus(
                      ability.id
                    )
                  )}

                  <br>

                  <b>Final Score:</b>
                  ${getSection13AbilityScore(
                    ability.id
                  )}

                  <br>

                  <b>Modifier:</b>
                  ${formatSignedNumber(
                    calculateAbilityModifier(
                      getSection13AbilityScore(
                        ability.id
                      )
                    )
                  )}

                  <br>

                  <b>Cost:</b>
                  ${cost}
                </p>

                <div class="hg-character-card-actions">
                  <button
                    type="button"
                    data-cc-action="point-buy-decrease"
                    data-ability-id="${escapeHtml(
                      ability.id
                    )}"
                    ${baseScore <= 8 ? "disabled" : ""}
                  >
                    −
                  </button>

                  <button
                    type="button"
                    data-cc-action="point-buy-increase"
                    data-ability-id="${escapeHtml(
                      ability.id
                    )}"
                    ${baseScore >= 15 ? "disabled" : ""}
                  >
                    +
                  </button>
                </div>
              </article>
            `;
          }
        ).join("")}
      </div>

      <div class="hg-character-inline-actions">
        <button
          type="button"
          data-cc-action="reset-point-buy"
        >
          Reset Point Buy
        </button>
      </div>
    `;
  }

  function renderSection13RolledAbilities() {
    const pool =
      Array.isArray(
        creatorState.draft
          .abilities
          .assignmentPool
      )
        ? creatorState.draft
            .abilities
            .assignmentPool
        : [];

    return `
      <div class="hg-character-current-choice">
        <b>Rolled pool:</b>

        ${escapeHtml(
          pool.length
            ? pool.join(", ")
            : "No scores rolled yet"
        )}
      </div>

      <div class="hg-character-inline-actions">
        <button
          type="button"
          data-cc-action="roll-ability-scores"
        >
          Roll 4d6, Drop Lowest
        </button>

        <button
          type="button"
          data-cc-action="apply-rolled-scores"
          ${pool.length === 6 ? "" : "disabled"}
        >
          Apply Rolls in Order
        </button>
      </div>

      <p class="small">
        Rolls are applied in this order:
        Strength, Dexterity, Constitution,
        Intelligence, Wisdom, Charisma.
        After applying them, you can still edit the
        base scores manually below.
      </p>

      ${renderSection13ManualAbilities()}
    `;
  }

  function renderSection13AbilitySummary() {
    return `
      <div class="hg-character-choice-grid">
        ${ABILITY_DEFINITIONS.map(
          (ability) => {
            const score =
              getSection13AbilityScore(
                ability.id
              );

            const modifier =
              calculateAbilityModifier(
                score
              );

            const bonus =
              getSection13AbilityBonus(
                ability.id
              );

            return `
              <article class="hg-character-choice-card">
                <h3>
                  ${escapeHtml(
                    ability.name
                  )}
                </h3>

                <p>
                  <b>Base Score:</b>
                  ${getSection13BaseAbilityScore(
                    ability.id
                  )}

                  <br>

                  <b>Species/Other Bonuses:</b>
                  ${formatSignedNumber(bonus)}

                  <br>

                  <b>Final Score:</b>
                  ${score}

                  <br>

                  <b>Modifier:</b>
                  ${formatSignedNumber(modifier)}
                </p>
              </article>
            `;
          }
        ).join("")}
      </div>

      ${renderSection13DerivedMechanics()}
    `;
  }

  function renderSection13MechanicsGuide() {
    return `
      <div class="hg-character-current-choice">
        <b>Standard Array:</b> 15, 14, 13, 12, 10, 8.
        Assign each number once.

        <br>

        <b>Manual Entry:</b> Enter each base score directly.
        Ability modifiers update automatically using
        (score - 10) divided by 2, rounded down.

        <br>

        <b>Proficiency Bonus by Total Level:</b>
        levels 1-4: +2; 5-8: +3; 9-12: +4;
        13-16: +5; 17-20: +6.

        <br>

        <b>Common formulas:</b>
        Initiative = Dexterity modifier + bonuses.
        Passive Perception = 10 + Perception bonus.
        Spell save DC = 8 + proficiency bonus + spellcasting
        ability modifier. Spell attack = proficiency bonus +
        spellcasting ability modifier.
      </div>
    `;
  }

  function renderSection13DerivedMechanics() {
    const draft = creatorState.draft;

    const totalLevel = clampLevel(
      draft.classProgression.totalLevel
    );

    const proficiencyBonus =
      getGenericProficiencyBonus(totalLevel);

    const initiative =
      calculateCharacterInitiative(draft);

    const passivePerception =
      calculateCharacterPassiveScores(
        draft
      ).perception || {
        skillModifier: 0,
        total: 10
      };

    const spellcastingClasses =
      getSpellcastingSummary(draft)
        .classes
        .filter((entry) => {
          return (
            entry.spellSaveDc !== null &&
            entry.spellAttackBonus !== null
          );
        });

    const spellcastingSummary =
      spellcastingClasses.length
        ? spellcastingClasses
            .map((entry) => {
              return `
                <b>${escapeHtml(entry.className)}:</b>
                DC ${entry.spellSaveDc}, attack
                ${formatSignedNumber(
                  entry.spellAttackBonus
                )}
              `;
            })
            .join("<br>")
        : "No spellcasting ability selected.";

    return `
      <hr>

      <h3>Calculated Mechanics</h3>

      <div class="hg-character-choice-grid">
        <article class="hg-character-choice-card">
          <h3>Proficiency Bonus</h3>

          <p>
            <b>${formatSignedNumber(proficiencyBonus)}</b>
            at total level ${totalLevel}
          </p>
        </article>

        <article class="hg-character-choice-card">
          <h3>Initiative</h3>

          <p>
            <b>${formatSignedNumber(initiative.total)}</b>

            <br>

            Dexterity ${formatSignedNumber(
              initiative.dexterityModifier
            )} + bonuses ${formatSignedNumber(
              initiative.proficiencyBonus +
              initiative.bonus
            )}
          </p>
        </article>

        <article class="hg-character-choice-card">
          <h3>Passive Perception</h3>

          <p>
            <b>${passivePerception.total}</b>

            <br>

            10 + Perception
            ${formatSignedNumber(
              passivePerception.skillModifier
            )}
          </p>
        </article>

        <article class="hg-character-choice-card">
          <h3>Spellcasting</h3>

          <p>${spellcastingSummary}</p>
        </article>
      </div>
    `;
  }

  function refreshSection13AbilitySummary() {
    if (
      creatorState.currentStepId !==
      "abilities"
    ) {
      return;
    }

    const summaryElement =
      typeof document !== "undefined"
        ? document.getElementById(
            "characterAbilitySummary"
          )
        : null;

    if (!summaryElement) {
      return;
    }

    summaryElement.innerHTML =
      renderSection13AbilitySummary();
  }

  function renderAbilitiesStep() {
    const method =
      creatorState.draft
        .abilities
        .method ||
      "manual";

    const methodChoices =
      ABILITY_SCORE_METHODS.map(
        (item) => {
          return {
            value: item.id,
            label: item.name
          };
        }
      );

    let methodContent = "";

    if (method === "standard-array") {
      methodContent =
        renderSection13StandardArray();
    } else if (method === "point-buy") {
      methodContent =
        renderSection13PointBuy();
    } else if (method === "rolled") {
      methodContent =
        renderSection13RolledAbilities();
    } else {
      methodContent =
        renderSection13ManualAbilities();
    }

    return `
      ${beginnerNote(
        "Ability Scores",
        "Ability scores are your core stats. The modifier is the number added to most rolls. Constitution helps HP, Dexterity often helps Armor Class and initiative, and your class usually has one or two most important abilities."
      )}

      ${renderSection13MechanicsGuide()}

      <div class="hg-character-field-grid">
        ${wizardSelect(
          "Ability Score Method",
          "ccAbilityMethod",
          method,
          methodChoices,
          {
            changeAction:
              "change-ability-method"
          }
        )}
      </div>

      <div style="margin-top: 16px;">
        ${methodContent}
      </div>

      <hr>

      <h3>Current Ability Summary</h3>

      <div id="characterAbilitySummary">
        ${renderSection13AbilitySummary()}
      </div>
    `;
  }

  function findSection13ActionElement(
    ...values
  ) {
    for (const value of values) {
      const candidates = [
        value,
        value?.target,
        value?.currentTarget,
        value?.element,
        value?.button,
        value?.control,
        value?.actionElement
      ];

      for (const candidate of candidates) {
        if (
          typeof Element !==
            "undefined" &&
          candidate instanceof Element
        ) {
          return (
            candidate.closest(
              "[data-cc-action]"
            ) ||
            candidate
          );
        }
      }
    }

    return null;
  }

  function handleSection13RefreshLevel() {
    if (
      refreshSection13LevelProgression() ===
      false
    ) {
      return;
    }

    setStatus(
      "Level progression refreshed."
    );

    renderCreatorView();
  }

  function handleSection13CalculateHp() {
    const hp =
      applySection13SuggestedHp();

    if (hp === null) {
      setStatus(
        "Choose a class before calculating suggested hit points."
      );

      renderCreatorView();

      return;
    }

    setStatus(
      `Suggested hit points applied: ${hp}.`
    );

    renderCreatorView();
  }

  function handleSection13ResetStandardArray() {
    applySection13StandardArray();

    setStatus(
      "Standard array reset."
    );

    renderCreatorView();
  }

  function handleSection13PointBuy(
    direction,
    ...values
  ) {
    const button =
      findSection13ActionElement(
        ...values
      );

    const abilityId =
      button?.dataset
        ?.abilityId ||
      "";

    if (
      changeSection13PointBuyScore(
        abilityId,
        direction
      )
    ) {
      setStatus(
        `${getSection13AbilityName(
          abilityId
        )} updated.`
      );

      renderCreatorView();
    }
  }

  function handleSection13ResetPointBuy() {
    applySection13PointBuyDefaults();

    setStatus(
      "Point buy reset."
    );

    renderCreatorView();
  }

  function handleSection13RollScores() {
    const rolls =
      rollSection13ScorePool();

    setStatus(
      `Rolled scores: ${rolls.join(
        ", "
      )}.`
    );

    renderCreatorView();
  }

  function handleSection13ApplyRolls() {
    if (
      applySection13RolledScores()
    ) {
      setStatus(
        "Rolled scores applied."
      );

      renderCreatorView();
    }
  }

  function handleSection13Change({ target }) {
    if (
      target?.dataset
        ?.ccActionChange ===
      "change-ability-method"
    ) {
      setSection13AbilityMethod(
        target.value
      );

      setStatus(
        "Ability score method changed."
      );

      renderCreatorView();

      return true;
    }

    if (
      target?.dataset
        ?.standardAbilityId
    ) {
      assignSection13StandardScore(
        target.dataset
          .standardAbilityId,
        target.value
      );

      setStatus(
        "Standard array assignment updated."
      );

      renderCreatorView();

      return true;
    }

    if (
      target?.dataset
        ?.hpRollLevel
    ) {
      setSection13HpRollValue(
        target.dataset.hpRollLevel,
        target.value
      );

      renderCreatorView();

      return true;
    }

    if (
      target?.dataset
        ?.draftPath ===
      "combat.hpCalculation.laterLevelValues"
    ) {
      setDraftValue(
        "combat.hpCalculation.laterLevelValues",
        parseSection13HpRolls(
          target.value
        )
      );

      markDraftChanged();
      renderCreatorView();

      return true;
    }

    if (
      [
        "combat.hpCalculation.mode",
        "combat.hpCalculation.levelOneValue",
        "combat.hpCalculation.manualOverride",
        "combat.armorClassMode",
        "combat.selectedArmorClassMethod",
        "combat.manualArmorClass",
        "combat.armorClassBonus",
        "combat.initiativeBonus"
      ].includes(
        target?.dataset?.draftPath
      )
    ) {
      const path =
        target.dataset.draftPath;

      const blankMeansNull = [
        "combat.hpCalculation.levelOneValue",
        "combat.hpCalculation.manualOverride",
        "combat.manualArmorClass"
      ].includes(path);

      if (
        blankMeansNull &&
        String(target.value || "").trim() === ""
      ) {
        setDraftValue(path, null);
      } else {
        setSimpleDraftField(
          path,
          target.value,
          target.dataset.valueType ||
          "string"
        );
      }

      applyCompatibilityAliases(
        creatorState.draft
      );

      markDraftChanged();
      renderCreatorView();

      return true;
    }

    if (
      target?.id ===
      "ccCharacterLevel"
    ) {
      setCharacterLevel(
        target.value
      );

      refreshSection13LevelProgression();

      setStatus(
        `Character level set to ${clampLevel(
          target.value
        )}.`
      );

      renderCreatorView();

      return true;
    }

    return false;
  }

  registerCharacterStepRenderer(
    "level",
    renderLevelStep
  );

  registerCharacterStepRenderer(
    "abilities",
    renderAbilitiesStep
  );

  registerCharacterCreatorAction(
    "refresh-level-progression",
    handleSection13RefreshLevel
  );

  registerCharacterCreatorAction(
    "calculate-character-hp",
    handleSection13CalculateHp
  );

  registerCharacterCreatorAction(
    "reset-standard-array",
    handleSection13ResetStandardArray
  );

  registerCharacterCreatorAction(
    "point-buy-decrease",
    (...values) => {
      handleSection13PointBuy(
        -1,
        ...values
      );
    }
  );

  registerCharacterCreatorAction(
    "point-buy-increase",
    (...values) => {
      handleSection13PointBuy(
        1,
        ...values
      );
    }
  );

  registerCharacterCreatorAction(
    "reset-point-buy",
    handleSection13ResetPointBuy
  );

  registerCharacterCreatorAction(
    "roll-ability-scores",
    handleSection13RollScores
  );

  registerCharacterCreatorAction(
    "apply-rolled-scores",
    handleSection13ApplyRolls
  );

  registerCharacterCreatorChangeHandler(
    handleSection13Change
  );

// =====================================================
// CHARACTER CREATOR SECTION 14 — BACKGROUND / PROFICIENCIES
// =====================================================

  function parseSection14List(value) {
    return String(value || "")
      .split(/[\n,]+/)
      .map((item) => item.trim())
      .filter(Boolean);
  }

  function formatSection14List(value) {
    return Array.isArray(value)
      ? value.join(", ")
      : "";
  }

  function normalizeSection14Background(
    rawBackground,
    fallbackSource = "template"
  ) {
    const raw = rawBackground || {};

    const name =
      safeDisplayString(
        raw.name,
        "Custom Background"
      );
    const backgroundId = makeSafeId(
      raw.id || name,
      "custom-background"
    );

    return {
      ...cloneData(raw),
      ...getLegacy2014Metadata(
        "background",
        backgroundId,
        raw
      ),

      id: backgroundId,

      name,

      source:
        safeDisplayString(
          raw.source,
          fallbackSource
        ),

      summary:
        safeDisplayString(
          raw.summary ||
          raw.description,
          "No description provided."
        ),

      skillChoices: {
        choose: Math.max(
          0,
          Math.round(
            safeNumber(
              raw.skillChoices?.choose,
              0
            )
          )
        ),

        from:
          cleanArray(
            raw.skillChoices?.from
          )
      },

      toolChoices: {
        choose: Math.max(
          0,
          Math.round(
            safeNumber(
              raw.toolChoices?.choose,
              0
            )
          )
        ),

        from:
          cleanArray(
            raw.toolChoices?.from
          )
      },

      languageChoices: {
        choose: Math.max(
          0,
          Math.round(
            safeNumber(
              raw.languageChoices?.choose,
              0
            )
          )
        ),

        from:
          cleanArray(
            raw.languageChoices?.from
          )
      },

      equipmentPackageIds:
        cleanArray(
          raw.equipmentPackageIds
        ),

      customEquipmentItems:
        cleanArray(
          raw.customEquipmentItems ||
          raw.equipmentItems
        ),

      features:
        Array.isArray(raw.features)
          ? cloneData(raw.features)
          : []
    };
  }

  function getAllSection14Backgrounds() {
    const backgroundMap = new Map();

    DEFAULT_BACKGROUND_TEMPLATES
      .forEach((background) => {
        const normalized =
          normalizeSection14Background(
            background,
            "template"
          );

        backgroundMap.set(
          normalized.id,
          normalized
        );
      });

    (
      creatorState.roomBackgroundCache ||
      []
    ).forEach((background) => {
      if (!isActiveRulesetEntry(background)) {
        return;
      }

      const normalized =
        normalizeSection14Background(
          background,
          "homebrew"
        );

      backgroundMap.set(
        normalized.id,
        normalized
      );
    });

    const selectedSnapshot =
      creatorState.draft
        .background
        .templateSnapshot;

    if (
      selectedSnapshot &&
      isActiveRulesetEntry(selectedSnapshot) &&
      creatorState.draft
        .background
        .source !== "custom" &&
      creatorState.draft
        .background
        .source !== "skipped"
    ) {
      const normalized =
        normalizeSection14Background(
          selectedSnapshot,
          "character"
        );

      backgroundMap.set(
        normalized.id,
        normalized
      );
    }

    return Array.from(
      backgroundMap.values()
    ).sort((a, b) => {
      return a.name.localeCompare(
        b.name
      );
    });
  }

  function getSelectedSection14Background() {
    const background =
      creatorState.draft.background;

    const selectedSnapshot =
      background?.templateSnapshot;

    if (selectedSnapshot) {
      return normalizeSection14Background(
        selectedSnapshot,
        background.source ||
        "character"
      );
    }

    return (
      getAllSection14Backgrounds()
        .find((template) => {
          return (
            template.id ===
            background?.id
          );
        }) ||
      null
    );
  }

  function getSection14BackgroundChoiceList(
    choiceKey
  ) {
    const background =
      creatorState.draft.background;

    background.featureChoices =
      background.featureChoices || {};

    background.featureChoices[choiceKey] =
      cleanArray(
        background.featureChoices[choiceKey]
      );

    return background.featureChoices[
      choiceKey
    ];
  }

  function setSection14BackgroundChoiceList(
    choiceKey,
    values
  ) {
    creatorState.draft
      .background
      .featureChoices =
        creatorState.draft
          .background
          .featureChoices || {};

    creatorState.draft
      .background
      .featureChoices[choiceKey] =
        uniqueCleanArray(values);
  }

  function getSection14AllExactToolOptions() {
    return uniqueCleanArray([
      ...GENERAL_TOOL_OPTIONS,
      ...ARTISAN_TOOL_OPTIONS,
      ...GAMING_SET_OPTIONS,
      ...MUSICAL_INSTRUMENT_OPTIONS
    ]).sort((a, b) => {
      return a.localeCompare(b);
    });
  }

  function expandSection14ToolChoice(
    option
  ) {
    const cleanOption =
      cleanString(option);

    const normalized =
      cleanOption
        .toLowerCase()
        .replace(/[’']/g, "'");

    if (!cleanOption) {
      return [];
    }

    if (
      normalized.includes(
        "artisan"
      ) &&
      normalized.includes(
        "musical"
      )
    ) {
      return [
        ...ARTISAN_TOOL_OPTIONS,
        ...MUSICAL_INSTRUMENT_OPTIONS
      ];
    }

    if (
      normalized.includes(
        "artisan"
      )
    ) {
      return [
        ...ARTISAN_TOOL_OPTIONS
      ];
    }

    if (
      normalized.includes(
        "gaming set"
      )
    ) {
      return [
        ...GAMING_SET_OPTIONS
      ];
    }

    if (
      normalized.includes(
        "musical instrument"
      )
    ) {
      return [
        ...MUSICAL_INSTRUMENT_OPTIONS
      ];
    }

    return [cleanOption];
  }

  function getSection14BackgroundToolOptions(
    background
  ) {
    const options =
      cleanArray(
        background?.toolChoices?.from
      );

    const sourceOptions =
      options.length
        ? options
        : getSection14AllExactToolOptions();

    return uniqueCleanArray(
      sourceOptions.flatMap((option) => {
        return expandSection14ToolChoice(
          option
        );
      })
    ).sort((a, b) => {
      return a.localeCompare(b);
    });
  }

  function getSection14BackgroundToolOptionsForIndex(
    background,
    index
  ) {
    const required =
      Math.max(
        0,
        safeNumber(
          background?.toolChoices?.choose,
          0
        )
      );

    const sourceOptions =
      cleanArray(
        background?.toolChoices?.from
      );

    if (
      sourceOptions.length === required &&
      index >= 0 &&
      index < sourceOptions.length
    ) {
      return uniqueCleanArray(
        expandSection14ToolChoice(
          sourceOptions[index]
        )
      ).sort((a, b) => {
        return a.localeCompare(b);
      });
    }

    return getSection14BackgroundToolOptions(
      background
    );
  }

  function getSection14BackgroundLanguageOptions(
    background
  ) {
    const options =
      cleanArray(
        background?.languageChoices?.from
      );

    return options.length
      ? options
      : STANDARD_LANGUAGE_OPTIONS;
  }

  function countSection14BackgroundSourceList(
    category
  ) {
    const sourceName =
      getBackgroundSourceLabel(
        creatorState.draft.background
      );

    if (!sourceName) {
      return 0;
    }

    const allSources =
      ensureProficiencySources(
        creatorState.draft
      );

    const categorySources =
      allSources[category] || {};

    return uniqueCleanArray(
      creatorState.draft
        .proficiencies[category]
    ).filter((value) => {
      return getStoredSources(
        categorySources,
        value,
        []
      ).includes(sourceName);
    }).length;
  }

  function getSection14BackgroundSourceValues(
    category
  ) {
    const sourceName =
      getBackgroundSourceLabel(
        creatorState.draft.background
      );

    if (!sourceName) {
      return [];
    }

    const allSources =
      ensureProficiencySources(
        creatorState.draft
      );

    const categorySources =
      allSources[category] || {};

    return uniqueCleanArray(
      creatorState.draft
        .proficiencies[category]
    ).filter((value) => {
      return getStoredSources(
        categorySources,
        value,
        []
      ).includes(sourceName);
    });
  }

  function countSection14ValidBackgroundToolChoices(
    background =
      getSelectedSection14Background()
  ) {
    const required =
      Math.max(
        0,
        safeNumber(
          background?.toolChoices?.choose,
          0
        )
      );

    const selectedChoices =
      cleanArray(
        creatorState.draft
          .background
          .featureChoices
          ?.toolProficiencies
      );

    const sourcedTools =
      new Set(
        getSection14BackgroundSourceValues(
          "tools"
        )
      );

    const seen = new Set();
    let validCount = 0;

    for (
      let index = 0;
      index < required;
      index += 1
    ) {
      const selected =
        cleanString(
          selectedChoices[index]
        );

      const validTools =
        new Set(
          getSection14BackgroundToolOptionsForIndex(
            background,
            index
          )
        );

      if (
        selected &&
        !seen.has(selected) &&
        sourcedTools.has(selected) &&
        validTools.has(selected)
      ) {
        seen.add(selected);
        validCount += 1;
      }
    }

    return validCount;
  }

  function applySection14BackgroundChoices() {
    const background =
      getSelectedSection14Background();

    const sourceName =
      getBackgroundSourceLabel(
        creatorState.draft.background
      );

    if (!background || !sourceName) {
      alert(
        "Choose a background first."
      );

      return false;
    }

    const toolRequired =
      Math.max(
        0,
        safeNumber(
          background.toolChoices?.choose,
          0
        )
      );

    const languageRequired =
      Math.max(
        0,
        safeNumber(
          background.languageChoices?.choose,
          0
        )
      );

    const toolChoices =
      Array.from(
        { length: toolRequired },
        (_, index) => {
          return cleanString(
            $(`ccBackgroundToolChoice-${index}`)
              ?.value
          );
        }
      ).filter(Boolean);

    const languageChoices =
      Array.from(
        { length: languageRequired },
        (_, index) => {
          return cleanString(
            $(`ccBackgroundLanguageChoice-${index}`)
              ?.value
          );
        }
      ).filter(Boolean);

    if (
      toolChoices.length !== toolRequired ||
      new Set(toolChoices).size !==
        toolChoices.length ||
      !toolChoices.every((tool, index) => {
        return getSection14BackgroundToolOptionsForIndex(
          background,
          index
        ).includes(tool);
      })
    ) {
      alert(
        "Choose the required exact background tool proficiencies."
      );

      return false;
    }

    if (
      languageChoices.length !==
        languageRequired ||
      new Set(languageChoices).size !==
        languageChoices.length
    ) {
      alert(
        "Choose the required background languages."
      );

      return false;
    }

    setSection14BackgroundChoiceList(
      "toolProficiencies",
      toolChoices
    );

    setSection14BackgroundChoiceList(
      "languageProficiencies",
      languageChoices
    );

    setSourceProficiencyList(
      "tools",
      toolChoices,
      sourceName
    );

    setSourceProficiencyList(
      "languages",
      languageChoices,
      sourceName
    );

    applyCompatibilityAliases(
      creatorState.draft
    );

    markDraftChanged();

    return true;
  }

  function getSection14BackgroundPackages(
    background
  ) {
    const packageIds =
      cleanArray(
        background?.equipmentPackageIds
      );

    const packages =
      DEFAULT_BACKGROUND_EQUIPMENT_PACKAGES
        .filter((pack) => {
          return packageIds.includes(pack.id);
        })
        .map((pack) => cloneData(pack));

    const customItems =
      cleanArray(
        background?.customEquipmentItems
      );

    if (customItems.length) {
      packages.push({
        id:
          `${background.id}-custom-pack`,
        name:
          `${background.name} Equipment`,
        items:
          customItems.map((name) => {
            return {
              name,
              quantity: 1,
              weight: null
            };
          })
      });
    }

    return packages;
  }

  function removeSection14BackgroundEquipment(
    sourceName,
    packageId = ""
  ) {
    const cleanSource =
      cleanString(sourceName);

    if (!cleanSource) {
      return;
    }

    const cleanPackageId =
      cleanString(packageId);

    creatorState.draft
      .equipment
      .items =
        getSection15Inventory()
          .filter((item) => {
            if (item.source !== cleanSource) {
              return true;
            }

            if (!cleanPackageId) {
              return false;
            }

            return (
              cleanString(
                item.backgroundPackageId
              ) !== cleanPackageId
            );
          });

    removeSection14BackgroundCurrency(
      cleanSource,
      cleanPackageId
    );

    const currentSource =
      getBackgroundSourceLabel(
        creatorState.draft.background
      );

    if (currentSource === cleanSource) {
      const choices =
        creatorState.draft
          .background
          .featureChoices =
            creatorState.draft
              .background
              .featureChoices || {};

      choices.appliedEquipmentPackageIds =
        cleanPackageId
          ? cleanArray(
              choices.appliedEquipmentPackageIds
            ).filter((id) => {
              return id !== cleanPackageId;
            })
          : [];
    }
  }

  function getSection14BackgroundCurrencyGrant(
    sourceName,
    packageId
  ) {
    const cleanSource =
      cleanString(sourceName);

    const cleanPackageId =
      cleanString(packageId);

    if (!cleanSource || !cleanPackageId) {
      return null;
    }

    const sources =
      ensureEquipmentCurrencySources(
        creatorState.draft.equipment
      );

    return (
      sources[cleanSource]?.[
        cleanPackageId
      ] || null
    );
  }

  function hasSection14BackgroundCurrency(
    sourceName
  ) {
    const cleanSource =
      cleanString(sourceName);

    if (!cleanSource) {
      return false;
    }

    const sources =
      ensureEquipmentCurrencySources(
        creatorState.draft.equipment
      );

    const packageMap =
      sources[cleanSource] || {};

    return Object.values(packageMap)
      .some((currency) => {
        return hasCurrencyValue(currency);
      });
  }

  function formatSection14CurrencySummary(
    currency
  ) {
    const clean =
      normalizeCurrencyMap(currency);

    const parts =
      CURRENCY_DENOMINATIONS
        .filter((coin) => {
          return clean[coin] > 0;
        })
        .map((coin) => {
          return `${clean[coin]} ${coin}`;
        });

    return parts.length
      ? parts.join(", ")
      : "none";
  }

  function getSection14BackgroundRemovalSummary(
    sourceName
  ) {
    const cleanSource =
      cleanString(sourceName);

    const itemCount =
      getSection15Inventory()
        .filter((item) => {
          return item.source === cleanSource;
        })
        .length;

    const sources =
      ensureEquipmentCurrencySources(
        creatorState.draft.equipment
      );

    const currency =
      Object.values(
        sources[cleanSource] || {}
      ).reduce(
        (total, packageCurrency) => {
          return addCurrencyMaps(
            total,
            packageCurrency
          );
        },
        normalizeCurrencyMap({})
      );

    return {
      itemCount,
      currency,
      hasCurrency:
        hasCurrencyValue(currency),
      hasAnything:
        itemCount > 0 ||
        hasCurrencyValue(currency)
    };
  }

  function addSection14BackgroundCurrency(
    sourceName,
    packageId,
    currency
  ) {
    const cleanSource =
      cleanString(sourceName);

    const cleanPackageId =
      cleanString(packageId);

    const cleanCurrency =
      normalizeCurrencyMap(currency);

    if (
      !cleanSource ||
      !cleanPackageId ||
      !hasCurrencyValue(cleanCurrency)
    ) {
      return false;
    }

    const equipment =
      creatorState.draft.equipment;

    const manualCurrency =
      getManualCurrencyBalance(
        equipment
      );

    const sources =
      ensureEquipmentCurrencySources(
        equipment
      );

    sources[cleanSource] =
      sources[cleanSource] || {};

    if (
      hasCurrencyValue(
        sources[cleanSource][
          cleanPackageId
        ]
      )
    ) {
      syncEquipmentCurrencyFromSources(
        equipment,
        manualCurrency
      );

      return false;
    }

    sources[cleanSource][
      cleanPackageId
    ] = cleanCurrency;

    syncEquipmentCurrencyFromSources(
      equipment,
      manualCurrency
    );

    return true;
  }

  function removeSection14BackgroundCurrency(
    sourceName,
    packageId = ""
  ) {
    const cleanSource =
      cleanString(sourceName);

    if (!cleanSource) {
      return false;
    }

    const cleanPackageId =
      cleanString(packageId);

    const equipment =
      creatorState.draft.equipment;

    const manualCurrency =
      getManualCurrencyBalance(
        equipment
      );

    const sources =
      ensureEquipmentCurrencySources(
        equipment
      );

    if (!sources[cleanSource]) {
      return false;
    }

    if (cleanPackageId) {
      delete sources[cleanSource][
        cleanPackageId
      ];

      if (
        !Object.keys(
          sources[cleanSource]
        ).length
      ) {
        delete sources[cleanSource];
      }
    } else {
      delete sources[cleanSource];
    }

    syncEquipmentCurrencyFromSources(
      equipment,
      manualCurrency
    );

    return true;
  }

  function handleSection14OldBackgroundEquipment(
    sourceName
  ) {
    const cleanSource =
      cleanString(sourceName);

    if (!cleanSource) {
      return;
    }

    const removalSummary =
      getSection14BackgroundRemovalSummary(
        cleanSource
      );

    if (!removalSummary.hasAnything) {
      return;
    }

    const removeOld =
      typeof window !== "undefined" &&
      typeof window.confirm === "function"
        ? window.confirm(
            [
              "Remove items and currency granted by the previous background?",
              "",
              `Items to remove: ${removalSummary.itemCount}`,
              `Currency to remove: ${formatSection14CurrencySummary(removalSummary.currency)}`,
              "",
              "OK removes only those previous-background items and currency.",
              "Cancel keeps the existing background items and currency."
            ].join("\n")
          )
        : false;

    if (removeOld) {
      removeSection14BackgroundEquipment(
        cleanSource
      );
    }
  }

  function applySection14BackgroundPackage(
    packageId
  ) {
    const background =
      getSelectedSection14Background();

    const sourceName =
      getBackgroundSourceLabel(
        creatorState.draft.background
      );

    if (!background || !sourceName) {
      alert(
        "Choose a background first."
      );

      return false;
    }

    const pack =
      getSection14BackgroundPackages(
        background
      ).find((candidate) => {
        return candidate.id === packageId;
      });

    if (!pack) {
      return false;
    }

    const choices =
      creatorState.draft
        .background
        .featureChoices =
          creatorState.draft
            .background
            .featureChoices || {};

    choices.appliedEquipmentPackageIds =
      cleanArray(
        choices.appliedEquipmentPackageIds
      );

    const alreadyApplied =
      choices.appliedEquipmentPackageIds
        .includes(pack.id);

    const inventory =
      getSection15Inventory();

    (Array.isArray(pack.items)
      ? pack.items
      : []
    ).forEach((packItem) => {
      const catalogItem =
        packItem.catalogId
          ? getSection15Catalog()
              .find((item) => {
                return item.id ===
                  packItem.catalogId;
              })
          : null;

      const baseItem =
        catalogItem ||
        {
          id:
            makeSafeId(
              packItem.name,
              "background-item"
            ),
          name:
            packItem.name ||
            "Background Item",
          category:
            packItem.category ||
            "adventuring-gear",
          weight:
            packItem.weight ?? null,
          quantity:
            packItem.quantity || 1
        };

      const grantKey =
        `${pack.id}:${baseItem.id || baseItem.name}`;

      const exists =
        inventory.some((item) => {
          return (
            item.source === sourceName &&
            item.backgroundGrantKey ===
              grantKey
          );
        });

      if (exists) {
        return;
      }

      inventory.push(
        normalizeSection15Item(
          {
            ...baseItem,
            id:
              makeSafeId(
                `${sourceName}-${grantKey}`,
                "background-item"
              ),
            quantity:
              packItem.quantity ||
              baseItem.quantity ||
              1,
            source: sourceName,
            backgroundPackageId:
              pack.id,
            backgroundGrantKey:
              grantKey
          },
          sourceName
        )
      );
    });

    if (!alreadyApplied) {
      addSection14BackgroundCurrency(
        sourceName,
        pack.id,
        pack.currency || {}
      );

      choices.appliedEquipmentPackageIds.push(
        pack.id
      );
    } else if (
      getSection14BackgroundCurrencyGrant(
        sourceName,
        pack.id
      )
    ) {
      syncEquipmentCurrencyFromSources(
        creatorState.draft.equipment
      );
    }

    markDraftChanged();

    return true;
  }

  function chooseSection14Background(
    backgroundId
  ) {
    const template =
      getAllSection14Backgrounds()
        .find((background) => {
          return (
            background.id ===
            backgroundId
          );
        });

    if (!template) {
      return false;
    }

    const current =
      creatorState.draft.background;

    const oldBackgroundSource =
      getBackgroundSourceLabel(
        current
      );

    if (oldBackgroundSource) {
      handleSection14OldBackgroundEquipment(
        oldBackgroundSource
      );

      removeSkillProficiencySource(
        oldBackgroundSource
      );

      removeListProficiencySource(
        oldBackgroundSource
      );
    }

    creatorState.draft.background = {
      id: template.id,
      name: template.name,

      source:
        template.source ||
        "template",

      templateSnapshot:
        cloneData(template),

      featureChoices: {},

      traits:
        safeDisplayString(
          current?.traits
        ),

      ideals:
        safeDisplayString(
          current?.ideals
        ),

      bonds:
        safeDisplayString(
          current?.bonds
        ),

      flaws:
        safeDisplayString(
          current?.flaws
        ),

      backstory:
        safeDisplayString(
          current?.backstory
        )
    };

    creatorState.draft
      .features
      .backgroundFeatures =
        cloneData(
          template.features ||
          []
        );

    applyCompatibilityAliases(
      creatorState.draft
    );

    markDraftChanged();

    return true;
  }

  function skipSection14Background() {
    const current =
      creatorState.draft.background;

    const oldBackgroundSource =
      getBackgroundSourceLabel(
        current
      );

    if (oldBackgroundSource) {
      handleSection14OldBackgroundEquipment(
        oldBackgroundSource
      );

      removeSkillProficiencySource(
        oldBackgroundSource
      );

      removeListProficiencySource(
        oldBackgroundSource
      );
    }

    creatorState.draft.background = {
      ...createEmptyCharacter()
        .background,
      source: "skipped",
      featureChoices: {
        skipped: true
      }
    };

    creatorState.draft
      .features
      .backgroundFeatures = [];

    applyCompatibilityAliases(
      creatorState.draft
    );

    markDraftChanged();

    return true;
  }

  function applySection14CustomBackground() {
    const name =
      safeDisplayString(
        $("ccCustomBackgroundName")
          ?.value
      );

    if (!name) {
      alert(
        "Enter a custom background name."
      );

      return false;
    }

    const current =
      creatorState.draft.background;

    const oldBackgroundSource =
      getBackgroundSourceLabel(
        current
      );

    if (oldBackgroundSource) {
      handleSection14OldBackgroundEquipment(
        oldBackgroundSource
      );

      removeSkillProficiencySource(
        oldBackgroundSource
      );

      removeListProficiencySource(
        oldBackgroundSource
      );
    }

    const customBackground =
      normalizeSection14Background(
        {
          id: makeSafeId(
            name,
            "custom-background"
          ),

          name,
          source: "custom",

          summary:
            safeDisplayString(
              $("ccCustomBackgroundSummary")
                ?.value,
              "Custom background."
            ),

          skillChoices: {
            choose: Math.max(
              0,
              Math.round(
                safeNumber(
                  $("ccCustomBackgroundSkillCount")
                    ?.value,
                  0
                )
              )
            ),

            from:
              parseSection14List(
                $("ccCustomBackgroundSkills")
                  ?.value
              )
          },

          toolChoices: {
            choose: Math.max(
              0,
              Math.round(
                safeNumber(
                  $("ccCustomBackgroundToolCount")
                    ?.value,
                  0
                )
              )
            ),

            from:
              parseSection14List(
                $("ccCustomBackgroundTools")
                  ?.value
              )
          },

          languageChoices: {
            choose: Math.max(
              0,
              Math.round(
                safeNumber(
                  $("ccCustomBackgroundLanguageCount")
                    ?.value,
                  0
                )
              )
            ),

            from:
              parseSection14List(
                $("ccCustomBackgroundLanguages")
                  ?.value
              )
          },

          equipmentPackageIds: [],

          customEquipmentItems:
            parseSection14List(
              $("ccCustomBackgroundEquipment")
                ?.value
            ),

          features:
            cloneData(
              creatorState.draft
                .features
                .backgroundFeatures ||
              []
            )
        },

        "custom"
      );

    creatorState.draft.background = {
      id: customBackground.id,
      name: customBackground.name,
      source: "custom",

      templateSnapshot:
        cloneData(
          customBackground
        ),

      featureChoices:
        cloneData(
          current?.featureChoices ||
          {}
        ),

      traits:
        safeDisplayString(
          current?.traits
        ),

      ideals:
        safeDisplayString(
          current?.ideals
        ),

      bonds:
        safeDisplayString(
          current?.bonds
        ),

      flaws:
        safeDisplayString(
          current?.flaws
        ),

      backstory:
        safeDisplayString(
          current?.backstory
        )
    };

    applyCompatibilityAliases(
      creatorState.draft
    );

    markDraftChanged();

    return true;
  }

  function syncSection14BackgroundFeatures() {
    const background =
      creatorState.draft.background;

    if (
      background?.source ===
        "custom" &&
      background.templateSnapshot
    ) {
      background
        .templateSnapshot
        .features =
          cloneData(
            creatorState.draft
              .features
              .backgroundFeatures ||
            []
          );
    }
  }

  function addSection14BackgroundFeature() {
    const name =
      safeDisplayString(
        $("ccNewBackgroundFeatureName")
          ?.value
      );

    const summary =
      safeDisplayString(
        $("ccNewBackgroundFeatureSummary")
          ?.value
      );

    if (!name) {
      alert(
        "Enter a background feature name."
      );

      return false;
    }

    if (
      !Array.isArray(
        creatorState.draft
          .features
          .backgroundFeatures
      )
    ) {
      creatorState.draft
        .features
        .backgroundFeatures = [];
    }

    creatorState.draft
      .features
      .backgroundFeatures
      .push({
        id: makeSafeId(
          `${name}-${Date.now()}`,
          "background-feature"
        ),

        name,
        summary,
        source: "background"
      });

    syncSection14BackgroundFeatures();
    markDraftChanged();

    return true;
  }

  function removeSection14BackgroundFeature(
    index
  ) {
    const features =
      creatorState.draft
        .features
        .backgroundFeatures;

    if (
      !Array.isArray(features) ||
      index < 0 ||
      index >= features.length
    ) {
      return false;
    }

    features.splice(index, 1);

    syncSection14BackgroundFeatures();
    markDraftChanged();

    return true;
  }

  function renderBackgroundStep() {
    const selectedBackground =
      getSelectedSection14Background();

    const selectedId =
      creatorState.draft
        .background
        .id;

    const backgroundCards =
      getAllSection14Backgrounds()
        .map((background) => {
          const selected =
            selectedId ===
            background.id;

          return wizardChoiceCard(
            background.name ||
            "Unnamed Background",

            `
              <p>
                ${escapeHtml(
                  background.summary ||
                  "No description provided."
                )}
              </p>

              <p>
                <b>Skill Choices:</b>

                ${Math.max(
                  0,
                  safeNumber(
                    background
                      .skillChoices
                      ?.choose,
                    0
                  )
                )}

                <br>

                <b>Tool Choices:</b>

                ${Math.max(
                  0,
                  safeNumber(
                    background
                      .toolChoices
                      ?.choose,
                    0
                  )
                )}

                <br>

                <b>Language Choices:</b>

                ${Math.max(
                  0,
                  safeNumber(
                    background
                      .languageChoices
                      ?.choose,
                    0
                  )
                )}
              </p>

              <p>
                ${renderRulesetMetadata(background, "background")}
              </p>
            `,

            selected
              ? "Selected"
              : "Choose Background",

            "choose-background",

            {
              "background-id":
                background.id
            },

            selected
          );
        })
        .join("");

    const backgroundFeatures =
      Array.isArray(
        creatorState.draft
          .features
          .backgroundFeatures
      )
        ? creatorState.draft
            .features
            .backgroundFeatures
        : [];

    const featureCards =
      backgroundFeatures
        .map((feature, index) => {
          return wizardChoiceCard(
            feature.name ||
            "Unnamed Feature",

            `
              <p>
                ${escapeHtml(
                  feature.summary ||
                  feature.description ||
                  "No description provided."
                )}
              </p>
            `,

            "Remove Feature",

            "remove-background-feature",

            {
              index
            },

            false
          );
        })
        .join("");

    const customSelected =
      creatorState.draft
        .background
        .source ===
      "custom";

    const selectedToolChoices =
      getSection14BackgroundChoiceList(
        "toolProficiencies"
      );

    const selectedLanguageChoices =
      getSection14BackgroundChoiceList(
        "languageProficiencies"
      );

    const toolRequired =
      Math.max(
        0,
        safeNumber(
          selectedBackground
            ?.toolChoices
            ?.choose,
          0
        )
      );

    const languageRequired =
      Math.max(
        0,
        safeNumber(
          selectedBackground
            ?.languageChoices
            ?.choose,
          0
        )
      );

    const backgroundChoiceHtml =
      selectedBackground &&
      creatorState.draft
        .background
        .source !== "skipped"
        ? `
          <hr>

          <h3>Background Choices</h3>

          <div class="hg-character-field-grid three">
            ${Array.from(
              { length: toolRequired },
              (_, index) => {
                return wizardSelect(
                  `Exact Tool Choice ${index + 1}`,
                  `ccBackgroundToolChoice-${index}`,
                  selectedToolChoices[index] ||
                    "",
                  [
                    {
                      value: "",
                      label: "Choose exact tool"
                    },
                    ...getSection14BackgroundToolOptionsForIndex(
                      selectedBackground,
                      index
                    ).map((tool) => {
                      return {
                        value: tool,
                        label: tool
                      };
                    })
                  ]
                );
              }
            ).join("")}

            ${Array.from(
              { length: languageRequired },
              (_, index) => {
                return wizardSelect(
                  `Language Choice ${index + 1}`,
                  `ccBackgroundLanguageChoice-${index}`,
                  selectedLanguageChoices[index] ||
                    "",
                  [
                    {
                      value: "",
                      label: "Choose language"
                    },
                    ...getSection14BackgroundLanguageOptions(
                      selectedBackground
                    ).map((language) => {
                      return {
                        value: language,
                        label: language
                      };
                    })
                  ]
                );
              }
            ).join("")}
          </div>

          ${
            toolRequired ||
            languageRequired
              ? `
                <div class="hg-character-inline-actions">
                  <button
                    type="button"
                    data-cc-action="apply-background-choices"
                  >
                    Apply Background Choices
                  </button>
                </div>
              `
              : `
                <div class="hg-character-placeholder">
                  This background has no tool or language choices.
                </div>
              `
          }
        `
        : "";

    const backgroundPackages =
      selectedBackground
        ? getSection14BackgroundPackages(
            selectedBackground
          )
        : [];

    const backgroundPackageCards =
      backgroundPackages
        .map((pack) => {
          return wizardChoiceCard(
            pack.name || "Background Equipment",
            `
              <p>
                ${
                  (Array.isArray(pack.items)
                    ? pack.items
                    : []
                  ).map((item) => {
                    return escapeHtml(
                      item.name ||
                      item.catalogId ||
                      "Item"
                    );
                  }).join(", ") ||
                  "No package items listed."
                }
              </p>
            `,
            "Apply Package",
            "apply-background-package",
            {
              "package-id": pack.id
            },
            cleanArray(
              creatorState.draft
                .background
                .featureChoices
                ?.appliedEquipmentPackageIds
            ).includes(pack.id)
          );
        })
        .join("");

    return `
      ${beginnerNote(
        "Choosing a Background",
        "Background is what your character was before adventuring. It usually gives skill proficiencies, tools or languages, starting gear, and a story feature."
      )}

      <div class="hg-character-current-choice">
        <b>Current background:</b>

        ${escapeHtml(
          creatorState.draft
            .background
            .source === "skipped"
            ? "No Background Selected"
            : getSafeBackgroundName() ||
              "None selected"
        )}
      </div>

      <div class="hg-character-inline-actions">
        <button
          type="button"
          data-cc-action="skip-background"
        >
          Skip Background
        </button>
      </div>

      <div class="hg-character-choice-grid">
        ${backgroundCards}
      </div>

      ${backgroundChoiceHtml}

      ${selectedBackground &&
        creatorState.draft.background.source !== "skipped"
        ? `
          <hr>

          <h3>Background Skills and Proficiencies</h3>

          ${renderSection14ProficiencyGuide()}

          ${renderSection14SourceSkillChoices(
            "background"
          )}
        `
        : ""}

      ${renderSection14ExpertiseChoices()}

      ${
        backgroundPackages.length
          ? `
            <hr>

            <h3>Background Equipment Packages</h3>

            <div class="hg-character-choice-grid">
              ${backgroundPackageCards}
            </div>
          `
          : ""
      }

      <hr>

      <h3>Custom Background</h3>

      <div class="hg-character-field-grid three">
        ${wizardField(
          "Background Name",
          "ccCustomBackgroundName",

          customSelected
            ? getSafeBackgroundName()
            : "",

          {
            placeholder:
              "Monster Hunter"
          }
        )}

        ${wizardField(
          "Skill Choices",
          "ccCustomBackgroundSkillCount",

          customSelected
            ? selectedBackground
                ?.skillChoices
                ?.choose || 0
            : 0,

          {
            type: "number",
            valueType: "integer",

            extra:
              'min="0" max="18" step="1"'
          }
        )}

        ${wizardField(
          "Tool Choices",
          "ccCustomBackgroundToolCount",

          customSelected
            ? selectedBackground
                ?.toolChoices
                ?.choose || 0
            : 0,

          {
            type: "number",
            valueType: "integer",

            extra:
              'min="0" max="10" step="1"'
          }
        )}

        ${wizardField(
          "Language Choices",
          "ccCustomBackgroundLanguageCount",

          customSelected
            ? selectedBackground
                ?.languageChoices
                ?.choose || 0
            : 0,

          {
            type: "number",
            valueType: "integer",

            extra:
              'min="0" max="10" step="1"'
          }
        )}

        ${wizardField(
          "Available Skills",
          "ccCustomBackgroundSkills",

          customSelected
            ? formatSection14List(
                selectedBackground
                  ?.skillChoices
                  ?.from
              )
            : "",

          {
            placeholder:
              "Survival, Nature, Perception",

            wide: true
          }
        )}

        ${wizardField(
          "Available Tools",
          "ccCustomBackgroundTools",

          customSelected
            ? formatSection14List(
                selectedBackground
                  ?.toolChoices
                  ?.from
              )
            : "",

          {
            placeholder:
              "Herbalism kit, Smith's tools",

            wide: true
          }
        )}

        ${wizardField(
          "Available Languages",
          "ccCustomBackgroundLanguages",

          customSelected
            ? formatSection14List(
                selectedBackground
                  ?.languageChoices
                  ?.from
              )
            : "",

          {
            placeholder:
              "Draconic, Elvish",

            wide: true
          }
        )}

        ${wizardField(
          "Equipment Package Items",
          "ccCustomBackgroundEquipment",

          customSelected
            ? formatSection14List(
                selectedBackground
                  ?.customEquipmentItems
              )
            : "",

          {
            placeholder:
              "Monster journal, silver badge, travel papers",

            wide: true
          }
        )}

        ${wizardField(
          "Background Summary",
          "ccCustomBackgroundSummary",

          customSelected
            ? selectedBackground
                ?.summary || ""
            : "",

          {
            type: "textarea",

            placeholder:
              "Describe this background's history and theme...",

            wide: true
          }
        )}
      </div>

      <div class="hg-character-inline-actions">
        <button
          type="button"
          data-cc-action="use-custom-background"
        >
          Use Custom Background
        </button>
      </div>

      <hr>

      <h3>Personality and Story</h3>

      <div class="hg-character-field-grid">
        ${wizardField(
          "Personality Traits",
          "ccBackgroundTraits",

          safeDisplayString(
            creatorState.draft
              .background
              .traits
          ),

          {
            type: "textarea",
            path: "background.traits",

            placeholder:
              "Habits, personality, mannerisms...",

            wide: true
          }
        )}

        ${wizardField(
          "Ideals",
          "ccBackgroundIdeals",

          safeDisplayString(
            creatorState.draft
              .background
              .ideals
          ),

          {
            type: "textarea",
            path: "background.ideals",

            placeholder:
              "What principles guide this character?",

            wide: true
          }
        )}

        ${wizardField(
          "Bonds",
          "ccBackgroundBonds",

          safeDisplayString(
            creatorState.draft
              .background
              .bonds
          ),

          {
            type: "textarea",
            path: "background.bonds",

            placeholder:
              "People, places, promises, or treasures...",

            wide: true
          }
        )}

        ${wizardField(
          "Flaws",
          "ccBackgroundFlaws",

          safeDisplayString(
            creatorState.draft
              .background
              .flaws
          ),

          {
            type: "textarea",
            path: "background.flaws",

            placeholder:
              "Fears, weaknesses, or destructive habits...",

            wide: true
          }
        )}

        ${wizardField(
          "Backstory",
          "ccBackgroundBackstory",

          safeDisplayString(
            creatorState.draft
              .background
              .backstory
          ),

          {
            type: "textarea",
            path: "background.backstory",

            placeholder:
              "Write the character's history...",

            wide: true
          }
        )}
      </div>

      <hr>

      <h3>Background Features</h3>

      <div class="hg-character-choice-grid">
        ${
          featureCards ||
          `
            <div class="hg-character-placeholder">
              No background features have been added yet.
            </div>
          `
        }
      </div>

      <div
        class="hg-character-field-grid"
        style="margin-top: 12px;"
      >
        ${wizardField(
          "Feature Name",
          "ccNewBackgroundFeatureName",
          "",
          {
            placeholder:
              "Guild Membership"
          }
        )}

        ${wizardField(
          "Feature Description",
          "ccNewBackgroundFeatureSummary",
          "",
          {
            placeholder:
              "Short original description"
          }
        )}
      </div>

      <div class="hg-character-inline-actions">
        <button
          type="button"
          data-cc-action="add-background-feature"
        >
          Add Background Feature
        </button>
      </div>
    `;
  }

  function getSection14SkillEntry(
    skill
  ) {
    const skills =
      creatorState.draft
        .proficiencies
        .skills || {};

    const raw =
      skills[skill.id] ||
      skills[skill.name] ||
      null;

    return {
      proficient:
        raw?.proficient === true,

      expertise:
        raw?.expertise === true,

      expertiseSources:
        Array.isArray(raw?.expertiseSources)
          ? uniqueCleanArray(raw.expertiseSources)
          : raw?.expertise === true
            ? ["legacy"]
            : [],

      source:
        Array.isArray(raw?.source)
          ? cleanArray(raw.source)
          : raw?.proficient === true
            ? ["legacy"]
            : []
    };
  }

  function getSection14SkillSourceLabel(
    sourceType
  ) {
    if (sourceType === "class") {
      return getClassSourceLabel(
        getPrimaryClassEntry(
          creatorState.draft
        )
      );
    }

    if (sourceType === "background") {
      return getBackgroundSourceLabel(
        creatorState.draft
          .background
      );
    }

    if (sourceType === "legacy") {
      return "legacy";
    }

    return "manual";
  }

  function getSection14SkillChoiceList(
    sourceType
  ) {
    if (sourceType === "class") {
      const primaryClass =
        getPrimaryClassEntry(
          creatorState.draft
        );

      if (!primaryClass) {
        return [];
      }

      primaryClass.choices =
        primaryClass.choices || {};

      primaryClass.choices.skillProficiencyIds =
        cleanArray(
          primaryClass.choices
            .skillProficiencyIds
        );

      return primaryClass.choices
        .skillProficiencyIds;
    }

    if (sourceType === "background") {
      const background =
        creatorState.draft
          .background;

      background.featureChoices =
        background.featureChoices || {};

      background.featureChoices.skillProficiencyIds =
        cleanArray(
          background.featureChoices
            .skillProficiencyIds
        );

      return background.featureChoices
        .skillProficiencyIds;
    }

    return [];
  }

  function setSection14StoredSkillChoice(
    sourceType,
    skillId,
    selected
  ) {
    const choices =
      getSection14SkillChoiceList(
        sourceType
      );

    const cleanSkillId =
      cleanString(skillId);

    if (!cleanSkillId) {
      return choices;
    }

    const nextChoices =
      selected
        ? [
            ...new Set([
              ...choices,
              cleanSkillId
            ])
          ]
        : choices.filter((id) => {
            return id !== cleanSkillId;
          });

    if (sourceType === "class") {
      const primaryClass =
        getPrimaryClassEntry(
          creatorState.draft
        );

      if (primaryClass) {
        primaryClass.choices =
          primaryClass.choices || {};

        primaryClass.choices
          .skillProficiencyIds =
            nextChoices;
      }
    }

    if (sourceType === "background") {
      creatorState.draft
        .background
        .featureChoices =
          creatorState.draft
            .background
            .featureChoices || {};

      creatorState.draft
        .background
        .featureChoices
        .skillProficiencyIds =
          nextChoices;
    }

    return nextChoices;
  }

  function countSection14SkillSource(
    sourceType
  ) {
    const sourceLabel =
      getSection14SkillSourceLabel(
        sourceType
      );

    if (!sourceLabel) {
      return 0;
    }

    return Object.values(
      creatorState.draft
        .proficiencies
        .skills || {}
    ).filter((entry) => {
      return cleanArray(
        entry?.source
      ).includes(sourceLabel);
    }).length;
  }

  function countSection14ValidSkillSource(
    sourceType
  ) {
    const sourceLabel =
      getSection14SkillSourceLabel(
        sourceType
      );

    if (!sourceLabel) {
      return 0;
    }

    const choices =
      sourceType === "class"
        ? getSelectedClassTemplate()
            ?.skillChoices || {}
        : getSelectedSection14Background()
            ?.skillChoices || {};

    const allowed =
      cleanArray(choices.from)
        .map((name) => {
          return name.toLowerCase();
        });

    return SKILL_DEFINITIONS.filter((skill) => {
      if (
        allowed.length &&
        !allowed.includes(
          skill.name.toLowerCase()
        )
      ) {
        return false;
      }

      const entry =
        getSection14SkillEntry(skill);

      return cleanArray(entry.source)
        .includes(sourceLabel);
    }).length;
  }

  function setSection14SkillEntry(
    skill,
    entry
  ) {
    const skills =
      creatorState.draft
        .proficiencies
        .skills;

    delete skills[skill.name];

    if (!entry?.proficient) {
      delete skills[skill.id];
      return;
    }

    skills[skill.id] = {
      name: skill.name,
      ability: skill.ability,
      proficient: true,

      expertise:
        entry.expertise === true,

      expertiseSources:
        entry.expertise === true
          ? uniqueCleanArray(
              entry.expertiseSources || ["manual"]
            )
          : [],

      source:
        Array.isArray(entry.source) &&
        entry.source.length
          ? [...new Set(entry.source)]
          : ["manual"]
    };
  }

  function toggleSection14Skill(
    skillId,
    sourceType = "manual"
  ) {
    const skill =
      SKILL_DEFINITIONS.find(
        (item) => {
          return item.id === skillId;
        }
      );

    if (!skill) {
      return false;
    }

    const current =
      getSection14SkillEntry(
        skill
      );

    const sourceLabel =
      getSection14SkillSourceLabel(
        sourceType
      );

    if (!sourceLabel) {
      return false;
    }

    const currentSources =
      cleanArray(current.source);

    const alreadySelected =
      currentSources.includes(
        sourceLabel
      );

    if (
      !alreadySelected &&
      sourceType === "class"
    ) {
      const selectedClass =
        getSelectedClassTemplate();

      const maxChoices =
        Math.max(
          0,
          safeNumber(
            selectedClass
              ?.skillChoices
              ?.choose,
            0
          )
        );

      if (
        maxChoices > 0 &&
        countSection14SkillSource(
          "class"
        ) >= maxChoices
      ) {
        alert(
          `Choose only ${maxChoices} class skill proficienc${
            maxChoices === 1
              ? "y"
              : "ies"
          }.`
        );

        return false;
      }
    }

    if (
      !alreadySelected &&
      sourceType === "background"
    ) {
      const selectedBackground =
        getSelectedSection14Background();

      const maxChoices =
        Math.max(
          0,
          safeNumber(
            selectedBackground
              ?.skillChoices
              ?.choose,
            0
          )
        );

      if (
        maxChoices > 0 &&
        countSection14SkillSource(
          "background"
        ) >= maxChoices
      ) {
        alert(
          `Choose only ${maxChoices} background skill proficienc${
            maxChoices === 1
              ? "y"
              : "ies"
          }.`
        );

        return false;
      }
    }

    const nextSources =
      alreadySelected
        ? currentSources.filter(
            (source) => {
              return source !==
                sourceLabel;
            }
          )
        : [
            ...new Set([
              ...currentSources,
              sourceLabel
            ])
          ];

    if (
      sourceType === "class" ||
      sourceType === "background"
    ) {
      setSection14StoredSkillChoice(
        sourceType,
        skill.id,
        !alreadySelected
      );
    }

    setSection14SkillEntry(
      skill,
      {
        proficient:
          nextSources.length > 0,

        expertise:
          nextSources.length > 0 &&
          current.expertise === true,

        source: nextSources
      }
    );

    applyCompatibilityAliases(
      creatorState.draft
    );

    markDraftChanged();

    return true;
  }

  function toggleSection14Expertise(
    skillId
  ) {
    const skill =
      SKILL_DEFINITIONS.find(
        (item) => {
          return item.id === skillId;
        }
      );

    if (!skill) {
      return false;
    }

    const current =
      getSection14SkillEntry(
        skill
      );

    if (!current.proficient) {
      if (typeof alert === "function") {
        alert(
          "Choose proficiency before adding expertise."
        );
      }

      return false;
    }

    setSection14SkillEntry(
      skill,
      {
        proficient:
          current.proficient,

        expertise:
          !current.expertise,

        expertiseSources:
          current.expertise
            ? current.expertiseSources.filter(
                (source) => source !== "manual"
              )
            : uniqueCleanArray([
                ...current.expertiseSources,
                "manual"
              ]),

        source:
          current.source.length
            ? current.source
            : ["manual"]
      }
    );

    applyCompatibilityAliases(
      creatorState.draft
    );

    markDraftChanged();

    return true;
  }

  function getSection14SkillModifier(
    skill
  ) {
    const entry =
      getSection14SkillEntry(
        skill
      );

    const abilityModifier =
      calculateAbilityModifier(
        creatorState.draft
          .abilities
          .scores[skill.ability]
      );

    const proficiencyBonus =
      getCharacterProficiencyBonus(
        creatorState.draft
      );

    if (!entry.proficient) {
      return abilityModifier;
    }

    return (
      abilityModifier +
      proficiencyBonus *
      (entry.expertise ? 2 : 1)
    );
  }

  function applySection14ProficiencyLists() {
    setManualProficiencyList(
      "savingThrows",
      parseSection14List(
        $("ccSavingThrowProficiencies")
          ?.value
      )
    );

    setManualProficiencyList(
      "armor",
      parseSection14List(
        $("ccArmorProficiencies")
          ?.value
      )
    );

    setManualProficiencyList(
      "weapons",
      parseSection14List(
        $("ccWeaponProficiencies")
          ?.value
      )
    );

    setManualProficiencyList(
      "tools",
      parseSection14List(
        $("ccToolProficiencies")
          ?.value
      )
    );

    setManualProficiencyList(
      "languages",
      parseSection14List(
        $("ccLanguageProficiencies")
          ?.value
      )
    );

    applyCompatibilityAliases(
      creatorState.draft
    );

    markDraftChanged();

    return true;
  }

  function renderSection14ProficiencyGuide() {
    return `
      <div class="hg-character-current-choice">
        <b>How proficiency works:</b>
        Your proficiency bonus is added when you are trained.
        Expertise doubles that bonus. Saving throw proficiency
        comes mostly from your class. Armor, weapon, tool, and
        language proficiencies are separate from skills.
      </div>
    `;
  }

  function renderSection14SourceSkillChoices(
    sourceType
  ) {
    const isClass = sourceType === "class";

    const sourceTemplate = isClass
      ? getSelectedClassTemplate()
      : getSelectedSection14Background();

    if (!sourceTemplate) {
      return `
        <div class="hg-character-placeholder">
          Choose a ${isClass ? "class" : "background"}
          before selecting its skills.
        </div>
      `;
    }

    const skillChoices =
      sourceTemplate.skillChoices || {};

    const required = Math.max(
      0,
      Math.round(
        safeNumber(skillChoices.choose, 0)
      )
    );

    if (!required) {
      return `
        <div class="hg-character-placeholder">
          This ${isClass ? "class" : "background"}
          does not grant a skill choice.
        </div>
      `;
    }

    const allowedNames = cleanArray(
      skillChoices.from
    ).map((name) => {
      return String(name).toLowerCase();
    });

    const sourceLabel =
      getSection14SkillSourceLabel(
        sourceType
      );

    const availableSkills =
      SKILL_DEFINITIONS.filter((skill) => {
        return (
          !allowedNames.length ||
          allowedNames.includes(
            skill.name.toLowerCase()
          )
        );
      });

    const skillCards = availableSkills
      .map((skill) => {
        const entry =
          getSection14SkillEntry(skill);

        const selected = Boolean(
          sourceLabel &&
          entry.source.includes(sourceLabel)
        );

        const modifier =
          getSection14SkillModifier(skill);

        return `
          <article class="hg-character-choice-card ${selected ? "selected" : ""}">
            <h3>${escapeHtml(skill.name)}</h3>

            <p>
              <b>Ability:</b>
              ${escapeHtml(
                String(skill.ability).toUpperCase()
              )}

              <br>

              <b>Current modifier:</b>
              ${modifier >= 0 ? "+" : ""}${modifier}
            </p>

            <div class="hg-character-card-actions">
              <button
                type="button"
                data-cc-action="toggle-skill-proficiency"
                data-skill-id="${escapeHtml(skill.id)}"
                data-skill-source="${escapeHtml(sourceType)}"
              >
                ${selected ? "Remove" : "Choose"}
              </button>
            </div>
          </article>
        `;
      })
      .join("");

    return `
      <div class="hg-character-current-choice">
        <b>${isClass ? "Class" : "Background"} skill choices:</b>
        ${countSection14ValidSkillSource(sourceType)} / ${required}

        <br>

        <b>Proficiency Bonus:</b>
        +${Math.max(
          0,
          getCharacterProficiencyBonus(
            creatorState.draft
          )
        )}
      </div>

      <div class="hg-character-choice-grid">
        ${skillCards}
      </div>
    `;
  }

  function renderSection14ExpertiseChoices() {
    const proficientSkills =
      SKILL_DEFINITIONS.filter((skill) => {
        return getSection14SkillEntry(
          skill
        ).proficient;
      });

    return `
      <hr>

      <h3>Expertise</h3>

      <p class="small">
        Expertise doubles the proficiency bonus for a trained
        skill. Choose it only when a feature grants expertise.
      </p>

      <div class="hg-character-choice-grid">
        ${proficientSkills.length
          ? proficientSkills
              .map((skill) => {
                const entry =
                  getSection14SkillEntry(skill);

                return `
                  <article class="hg-character-choice-card ${entry.expertise ? "selected" : ""}">
                    <h3>${escapeHtml(skill.name)}</h3>

                    <p>
                      ${entry.expertise
                        ? "Expertise selected"
                        : "Proficient"}
                    </p>

                    <div class="hg-character-card-actions">
                      <button
                        type="button"
                        data-cc-action="toggle-skill-expertise"
                        data-skill-id="${escapeHtml(skill.id)}"
                      >
                        ${entry.expertise
                          ? "Remove Expertise"
                          : "Add Expertise"}
                      </button>
                    </div>
                  </article>
                `;
              })
              .join("")
          : `
            <div class="hg-character-placeholder">
              Choose at least one skill proficiency before
              assigning expertise.
            </div>
          `}
      </div>
    `;
  }

  function renderSkillsStep() {
    const selectedClass =
      getSelectedClassTemplate();

    const selectedBackground =
      getSelectedSection14Background();

    const classSkillChoices =
      selectedClass
        ?.skillChoices || {};

    const backgroundSkillChoices =
      selectedBackground
        ?.skillChoices || {};

    const proficientCount =
      SKILL_DEFINITIONS.filter(
        (skill) => {
          return getSection14SkillEntry(
            skill
          ).proficient;
        }
      ).length;

    const skillCards =
      SKILL_DEFINITIONS.map(
        (skill) => {
          const entry =
            getSection14SkillEntry(
              skill
            );

          const modifier =
            getSection14SkillModifier(
              skill
            );

          const classAvailable =
            !Array.isArray(
              classSkillChoices.from
            ) ||
            classSkillChoices
              .from.length === 0 ||
            classSkillChoices
              .from.some((name) => {
                return (
                  String(name)
                    .toLowerCase() ===
                  skill.name
                    .toLowerCase()
                );
              });

          const backgroundAvailable =
            !Array.isArray(
              backgroundSkillChoices.from
            ) ||
            backgroundSkillChoices
              .from.length === 0 ||
            backgroundSkillChoices
              .from.some((name) => {
                return (
                  String(name)
                    .toLowerCase() ===
                  skill.name
                    .toLowerCase()
                );
              });

          const classSourceLabel =
            getSection14SkillSourceLabel(
              "class"
            );

          const backgroundSourceLabel =
            getSection14SkillSourceLabel(
              "background"
            );

          const classSelected =
            Boolean(
              classSourceLabel &&
              entry.source.includes(
                classSourceLabel
              )
            );

          const backgroundSelected =
            Boolean(
              backgroundSourceLabel &&
              entry.source.includes(
                backgroundSourceLabel
              )
            );

          const manualSelected =
            entry.source.includes(
              "manual"
            );

          return `
            <article
              class="
                hg-character-choice-card
                ${entry.proficient ? "selected" : ""}
              "
            >
              <h3>
                ${escapeHtml(
                  skill.name
                )}
              </h3>

              <p>
                <b>Ability:</b>

                ${escapeHtml(
                  String(
                    skill.ability ||
                    ""
                  ).toUpperCase()
                )}

                <br>

                <b>Modifier:</b>

                ${modifier >= 0 ? "+" : ""}${modifier}

                <br>

                <b>Status:</b>

                ${
                  entry.expertise
                    ? "Expertise"
                    : entry.proficient
                      ? "Proficient"
                      : "Not proficient"
                }
              </p>

              <p class="small">
                ${
                  classAvailable
                    ? "Class option"
                    : ""
                }

                ${
                  classAvailable &&
                  backgroundAvailable
                    ? " · "
                    : ""
                }

                ${
                  backgroundAvailable
                    ? "Background option"
                    : ""
                }
              </p>

              <div class="hg-character-card-actions">
                ${
                  classAvailable &&
                  classSourceLabel
                    ? `
                      <button
                        type="button"
                        data-cc-action="toggle-skill-proficiency"
                        data-skill-id="${escapeHtml(
                          skill.id
                        )}"
                        data-skill-source="class"
                      >
                        ${
                          classSelected
                            ? "Remove Class"
                            : "Add Class"
                        }
                      </button>
                    `
                    : ""
                }

                ${
                  backgroundAvailable &&
                  backgroundSourceLabel
                    ? `
                      <button
                        type="button"
                        data-cc-action="toggle-skill-proficiency"
                        data-skill-id="${escapeHtml(
                          skill.id
                        )}"
                        data-skill-source="background"
                      >
                        ${
                          backgroundSelected
                            ? "Remove Background"
                            : "Add Background"
                        }
                      </button>
                    `
                    : ""
                }

                <button
                  type="button"
                  data-cc-action="toggle-skill-proficiency"
                  data-skill-id="${escapeHtml(
                    skill.id
                  )}"
                  data-skill-source="manual"
                >
                  ${
                    manualSelected
                      ? "Remove Manual"
                      : "Add Manual"
                  }
                </button>

                <button
                  type="button"
                  data-cc-action="toggle-skill-expertise"
                  data-skill-id="${escapeHtml(
                    skill.id
                  )}"
                >
                  ${
                    entry.expertise
                      ? "Remove Expertise"
                      : "Add Expertise"
                  }
                </button>
              </div>
            </article>
          `;
        }
      ).join("");

    return `
      <div class="hg-character-current-choice">
        <b>Skill proficiencies selected:</b>

        ${proficientCount}

        <br>

        <b>Class skill choices:</b>

        ${countSection14ValidSkillSource(
          "class"
        )} /
        ${Math.max(
          0,
          safeNumber(
            classSkillChoices.choose,
            0
          )
        )}

        <br>

        <b>Background skill choices:</b>

        ${countSection14ValidSkillSource(
          "background"
        )} /
        ${Math.max(
          0,
          safeNumber(
            backgroundSkillChoices.choose,
            0
          )
        )}
      </div>

      <div class="hg-character-warning">
        The creator shows your class and background options,
        but it does not block homebrew choices. You can select
        any skills your table allows.
      </div>

      <div class="hg-character-choice-grid">
        ${skillCards}
      </div>

      <hr>

      <h3>Other Proficiencies</h3>

      <p>
        Separate multiple entries with commas or new lines.
      </p>

      <div class="hg-character-field-grid">
        ${wizardField(
          "Saving Throws",
          "ccSavingThrowProficiencies",

          formatSection14List(
            getManualProficiencyList(
              "savingThrows"
            )
          ),

          {
            type: "textarea",

            placeholder:
              "Strength, Constitution",

            wide: true
          }
        )}

        ${wizardField(
          "Armor Training",
          "ccArmorProficiencies",

          formatSection14List(
            getManualProficiencyList(
              "armor"
            )
          ),

          {
            type: "textarea",

            placeholder:
              "Light armor, Medium armor, Shields",

            wide: true
          }
        )}

        ${wizardField(
          "Weapon Training",
          "ccWeaponProficiencies",

          formatSection14List(
            getManualProficiencyList(
              "weapons"
            )
          ),

          {
            type: "textarea",

            placeholder:
              "Simple weapons, Martial weapons",

            wide: true
          }
        )}

        ${wizardField(
          "Tools",
          "ccToolProficiencies",

          formatSection14List(
            getManualProficiencyList(
              "tools"
            )
          ),

          {
            type: "textarea",

            placeholder:
              "Thieves' tools, Smith's tools",

            wide: true
          }
        )}

        ${wizardField(
          "Languages",
          "ccLanguageProficiencies",

          formatSection14List(
            getManualProficiencyList(
              "languages"
            )
          ),

          {
            type: "textarea",

            placeholder:
              "Common, Draconic, Elvish",

            wide: true
          }
        )}
      </div>

      <div class="hg-character-inline-actions">
        <button
          type="button"
          data-cc-action="apply-proficiency-lists"
        >
          Apply Proficiency Lists
        </button>
      </div>
    `;
  }

  function findSection14ActionElement(
    ...values
  ) {
    for (const value of values) {
      const candidates = [
        value,
        value?.target,
        value?.currentTarget,
        value?.element,
        value?.button,
        value?.control,
        value?.actionElement
      ];

      for (const candidate of candidates) {
        if (
          typeof Element !==
            "undefined" &&
          candidate instanceof Element
        ) {
          return (
            candidate.closest(
              "[data-cc-action]"
            ) ||
            candidate
          );
        }
      }
    }

    return null;
  }

  function handleSection14ChooseBackground(
    ...values
  ) {
    const button =
      findSection14ActionElement(
        ...values
      );

    const backgroundId =
      button?.dataset
        ?.backgroundId ||
      "";

    if (
      chooseSection14Background(
        backgroundId
      )
    ) {
      setStatus(
        "Background selected: " +
        getSafeBackgroundName() +
        "."
      );

      renderCreatorView();
    }
  }

  function handleSection14SkipBackground() {
    if (skipSection14Background()) {
      setStatus(
        "Background skipped."
      );

      renderCreatorView();
    }
  }

  function handleSection14CustomBackground() {
    if (
      applySection14CustomBackground()
    ) {
      setStatus(
        "Custom background applied."
      );

      renderCreatorView();
    }
  }

  function handleSection14ApplyBackgroundChoices() {
    if (
      applySection14BackgroundChoices()
    ) {
      setStatus(
        "Background choices applied."
      );

      renderCreatorView();
    }
  }

  function handleSection14ApplyBackgroundPackage(
    ...values
  ) {
    const button =
      findSection14ActionElement(
        ...values
      );

    const packageId =
      button?.dataset?.packageId ||
      "";

    if (
      applySection14BackgroundPackage(
        packageId
      )
    ) {
      setStatus(
        "Background equipment package applied."
      );

      renderCreatorView();
    }
  }

  function handleSection14AddFeature() {
    if (
      addSection14BackgroundFeature()
    ) {
      setStatus(
        "Background feature added."
      );

      renderCreatorView();
    }
  }

  function handleSection14RemoveFeature(
    ...values
  ) {
    const button =
      findSection14ActionElement(
        ...values
      );

    const index =
      Math.round(
        safeNumber(
          button?.dataset?.index,
          -1
        )
      );

    if (
      removeSection14BackgroundFeature(
        index
      )
    ) {
      setStatus(
        "Background feature removed."
      );

      renderCreatorView();
    }
  }

  function handleSection14ToggleSkill(
    ...values
  ) {
    const button =
      findSection14ActionElement(
        ...values
      );

    const skillId =
      button?.dataset?.skillId ||
      "";

    const sourceType =
      button?.dataset
        ?.skillSource ||
      "manual";

    if (
      toggleSection14Skill(
        skillId,
        sourceType
      )
    ) {
      setStatus(
        "Skill proficiency updated."
      );

      renderCreatorView();
    }
  }

  function handleSection14ToggleExpertise(
    ...values
  ) {
    const button =
      findSection14ActionElement(
        ...values
      );

    const skillId =
      button?.dataset?.skillId ||
      "";

    if (
      toggleSection14Expertise(
        skillId
      )
    ) {
      setStatus(
        "Skill expertise updated."
      );

      renderCreatorView();
    }
  }

  function handleSection14ApplyLists() {
    applySection14ProficiencyLists();

    setStatus(
      "Proficiency lists applied."
    );

    renderCreatorView();
  }

  registerCharacterStepRenderer(
    "background",
    renderBackgroundStep
  );

  registerCharacterStepRenderer(
    "skills",
    renderSkillsStep
  );

  registerCharacterCreatorAction(
    "choose-background",
    handleSection14ChooseBackground
  );

  registerCharacterCreatorAction(
    "skip-background",
    handleSection14SkipBackground
  );

  registerCharacterCreatorAction(
    "use-custom-background",
    handleSection14CustomBackground
  );

  registerCharacterCreatorAction(
    "apply-background-choices",
    handleSection14ApplyBackgroundChoices
  );

  registerCharacterCreatorAction(
    "apply-background-package",
    handleSection14ApplyBackgroundPackage
  );

  registerCharacterCreatorAction(
    "add-background-feature",
    handleSection14AddFeature
  );

  registerCharacterCreatorAction(
    "remove-background-feature",
    handleSection14RemoveFeature
  );

  registerCharacterCreatorAction(
    "toggle-skill-proficiency",
    handleSection14ToggleSkill
  );

  registerCharacterCreatorAction(
    "toggle-skill-expertise",
    handleSection14ToggleExpertise
  );

  registerCharacterCreatorAction(
    "apply-proficiency-lists",
    handleSection14ApplyLists
  );

// =====================================================
// CHARACTER CREATOR SECTION 15 — EQUIPMENT / INVENTORY
// =====================================================

  function normalizeSection15Item(
    rawItem,
    fallbackSource = "custom"
  ) {
    const raw = rawItem || {};

    const name =
      safeDisplayString(
        raw.name,
        "Unnamed Item"
      );

    const category =
      safeDisplayString(
        raw.category,
        "miscellaneous"
      );

    const quantity = Math.max(
      1,
      Math.round(
        safeNumber(
          raw.quantity,
          1
        )
      )
    );

    const rawWeight =
      raw.weight === null ||
      raw.weight === undefined ||
      raw.weight === ""
        ? null
        : Math.max(
            0,
            safeNumber(
              raw.weight,
              0
            )
          );

    const isMagical =
      raw.isMagical === true ||
      safeDisplayString(raw.category)
        .toLowerCase() === "magic-item";

    const requiresAttunement =
      isMagical &&
      (
        raw.requiresAttunement === true ||
        raw.attuned === true
      );

    const isContainer =
      raw.isContainer === true;

    const capacityWeight =
      raw.capacityWeight === null ||
      raw.capacityWeight === undefined ||
      raw.capacityWeight === ""
        ? null
        : Math.max(
            0,
            safeNumber(
              raw.capacityWeight,
              0
            )
          );

    const armorCategory =
      cleanString(
        raw.armorCategory ||
        (
          raw.isShield === true ||
          category.toLowerCase() === "shield"
            ? "shield"
            : category.toLowerCase() === "armor"
              ? "light armor"
              : ""
        )
      );

    const baseArmorClass =
      raw.baseArmorClass === null ||
      raw.baseArmorClass === undefined ||
      raw.baseArmorClass === ""
        ? null
        : Math.max(
            0,
            safeNumber(
              raw.baseArmorClass,
              10
            )
          );

    const dexterityCap =
      raw.dexterityCap === null ||
      raw.dexterityCap === undefined ||
      raw.dexterityCap === ""
        ? null
        : safeNumber(
            raw.dexterityCap,
            2
          );

    const isShield =
      raw.isShield === true ||
      category.toLowerCase() === "shield" ||
      armorCategory.toLowerCase() === "shield";

    const legacyMagicalBonus =
      safeNumber(
        raw.magicalBonus,
        0
      );

    const legacyBonusLooksArmor =
      legacyMagicalBonus !== 0 &&
      (
        isShield ||
        baseArmorClass !== null ||
        category.toLowerCase() === "armor"
      );

    const legacyBonusLooksWeapon =
      legacyMagicalBonus !== 0 &&
      (
        category.toLowerCase() === "weapon" ||
        cleanString(raw.weaponType) ||
        cleanString(raw.damageDice)
      );

    return {
      ...cloneData(raw),

      id: makeSafeId(
        raw.id ||
        `${name}-${Date.now()}-${Math.random()}`,
        "inventory-item"
      ),

      name,

      category,

      quantity,

      weight: rawWeight,

      source:
        safeDisplayString(
          raw.source,
          fallbackSource
        ),

      notes:
        safeDisplayString(
          raw.notes
        ),

      equipped:
        raw.equipped === true &&
        !cleanString(raw.containerId) &&
        isContainer !== true,

      isMagical,

      requiresAttunement,

      attuned:
        requiresAttunement &&
        raw.attuned === true &&
        !cleanString(raw.containerId) &&
        isContainer !== true,

      magicalBonus:
        safeNumber(
          raw.magicalBonus,
          0
        ),

      armorCategory,

      baseArmorClass,

      dexterityCap,

      isShield,

      magicalArmorClassBonus:
        safeNumber(
          raw.magicalArmorClassBonus ??
          (
            legacyBonusLooksArmor
              ? legacyMagicalBonus
              : 0
          ),
          0
        ),

      weaponType:
        cleanString(raw.weaponType),

      attackAbility:
        cleanString(raw.attackAbility),

      finesse:
        raw.finesse === true,

      ranged:
        raw.ranged === true ||
        cleanString(raw.weaponType)
          .toLowerCase()
          .includes("ranged"),

      thrown:
        raw.thrown === true,

      proficient:
        raw.proficient === true,

      damageDice:
        cleanString(raw.damageDice),

      versatileDamageDice:
        cleanString(raw.versatileDamageDice),

      magicalAttackBonus:
        safeNumber(
          raw.magicalAttackBonus ??
          (
            legacyBonusLooksWeapon
              ? legacyMagicalBonus
              : 0
          ),
          0
        ),

      magicalDamageBonus:
        safeNumber(
          raw.magicalDamageBonus ??
          (
            legacyBonusLooksWeapon
              ? legacyMagicalBonus
              : 0
          ),
          0
        ),

      containerId:
        cleanString(raw.containerId),

      isContainer,

      capacityWeight,

      ownerCharacterId:
        cleanString(raw.ownerCharacterId)
    };
  }

  function getSection15Inventory() {
    if (
      !Array.isArray(
        creatorState.draft
          .equipment
          .items
      )
    ) {
      creatorState.draft
        .equipment
        .items = [];
    }

    creatorState.draft
      .equipment
      .items =
        creatorState.draft
          .equipment
          .items
          .map((item) => {
            return normalizeSection15Item(
              item,
              item?.source || "custom"
            );
          });

    return creatorState.draft
      .equipment
      .items;
  }

  function getSection15Catalog() {
    const catalogMap =
      new Map();

    DEFAULT_EQUIPMENT_CATALOG
      .forEach((item) => {
        const normalized =
          normalizeSection15Item(
            item,
            "template"
          );

        catalogMap.set(
          normalized.id,
          normalized
        );
      });

    return Array.from(
      catalogMap.values()
    ).sort((a, b) => {
      const categoryCompare =
        a.category.localeCompare(
          b.category
        );

      if (categoryCompare !== 0) {
        return categoryCompare;
      }

      return a.name.localeCompare(
        b.name
      );
    });
  }

  function addSection15CatalogItem(
    itemId
  ) {
    const item =
      getSection15Catalog()
        .find((entry) => {
          return entry.id === itemId;
        });

    if (!item) {
      return false;
    }

    const inventory =
      getSection15Inventory();

    const matchingItem =
      inventory.find((entry) => {
        return (
          entry.id === item.id ||
          (
            safeDisplayString(
              entry.name
            ).toLowerCase() ===
              item.name.toLowerCase() &&
            safeDisplayString(
              entry.category
            ).toLowerCase() ===
              item.category.toLowerCase()
          )
        );
      });

    if (matchingItem) {
      matchingItem.quantity =
        Math.max(
          1,
          Math.round(
            safeNumber(
              matchingItem.quantity,
              1
            )
          )
        ) +
        Math.max(
          1,
          Math.round(
            safeNumber(
              item.quantity,
              1
            )
          )
        );
    } else {
      inventory.push(
        normalizeSection15Item(
          item,
          "template"
        )
      );
    }

    markDraftChanged();

    return true;
  }

  function addSection15CustomItem() {
    const name =
      safeDisplayString(
        $("ccNewItemName")
          ?.value
      );

    if (!name) {
      alert(
        "Enter an item name."
      );

      return false;
    }

    const quantity =
      Math.max(
        1,
        Math.round(
          safeNumber(
            $("ccNewItemQuantity")
              ?.value,
            1
          )
        )
      );

    const weightText =
      $("ccNewItemWeight")
        ?.value;

    const weight =
      weightText === "" ||
      weightText === null ||
      weightText === undefined
        ? null
        : Math.max(
            0,
            safeNumber(
              weightText,
              0
            )
          );

    const capacityText =
      $("ccNewItemCapacityWeight")
        ?.value;

    const capacityWeight =
      capacityText === "" ||
      capacityText === null ||
      capacityText === undefined
        ? null
        : Math.max(
            0,
            safeNumber(
              capacityText,
              0
            )
          );

    const baseArmorClassText =
      $("ccNewItemBaseArmorClass")
        ?.value;

    const baseArmorClass =
      baseArmorClassText === "" ||
      baseArmorClassText === null ||
      baseArmorClassText === undefined
        ? null
        : Math.max(
            0,
            safeNumber(
              baseArmorClassText,
              10
            )
          );

    const dexterityCapText =
      $("ccNewItemDexterityCap")
        ?.value;

    const dexterityCap =
      dexterityCapText === "" ||
      dexterityCapText === null ||
      dexterityCapText === undefined
        ? null
        : safeNumber(
            dexterityCapText,
            2
          );

    const category =
      $("ccNewItemCategory")
        ?.value ||
      "miscellaneous";

    const isMagical =
      $("ccNewItemMagical")
        ?.checked === true ||
      category === "magic-item";

    const requiresAttunement =
      isMagical &&
      $("ccNewItemRequiresAttunement")
        ?.checked === true;

    const item =
      normalizeSection15Item(
        {
          id: makeSafeId(
            `${name}-${Date.now()}-${Math.random()}`,
            "custom-item"
          ),

          name,

          category,

          quantity,
          weight,
          capacityWeight,

          armorCategory:
            $("ccNewItemArmorCategory")
              ?.value || "",

          baseArmorClass,

          dexterityCap,

          isShield:
            $("ccNewItemShield")
              ?.checked === true ||
            category === "shield",

          magicalArmorClassBonus:
            safeNumber(
              $("ccNewItemMagicalArmorBonus")
                ?.value,
              0
            ),

          weaponType:
            $("ccNewItemWeaponType")
              ?.value || "",

          attackAbility:
            $("ccNewItemAttackAbility")
              ?.value || "",

          finesse:
            $("ccNewItemFinesse")
              ?.checked === true,

          ranged:
            $("ccNewItemRanged")
              ?.checked === true,

          thrown:
            $("ccNewItemThrown")
              ?.checked === true,

          proficient:
            $("ccNewItemProficient")
              ?.checked === true,

          damageDice:
            $("ccNewItemDamageDice")
              ?.value || "",

          versatileDamageDice:
            $("ccNewItemVersatileDamageDice")
              ?.value || "",

          magicalAttackBonus:
            safeNumber(
              $("ccNewItemMagicalAttackBonus")
                ?.value,
              0
            ),

          magicalDamageBonus:
            safeNumber(
              $("ccNewItemMagicalDamageBonus")
                ?.value,
              0
            ),

          source: "custom",

          notes:
            safeDisplayString(
              $("ccNewItemNotes")
                ?.value
            ),

          equipped:
            $("ccNewItemEquipped")
              ?.checked === true,

          isMagical,

          requiresAttunement,

          attuned:
            requiresAttunement &&
            $("ccNewItemAttuned")
              ?.checked === true
          ,

          isContainer:
            $("ccNewItemContainer")
              ?.checked === true
        },

        "custom"
      );

    getSection15Inventory()
      .push(item);

    markDraftChanged();

    return true;
  }

  function removeSection15Item(
    index,
    removalMode = ""
  ) {
    const inventory =
      getSection15Inventory();

    if (
      index < 0 ||
      index >= inventory.length
    ) {
      return false;
    }

    const item =
      inventory[index];

    if (item?.isContainer === true) {
      const contents =
        getContainerContents(
          inventory,
          item.id
        );

      if (contents.length) {
        const cleanChoice =
          cleanString(
            removalMode
          ).toLowerCase();

        if (!cleanChoice) {
          creatorState.pendingContainerRemovalId =
            item.id;

          return "pending";
        }

        if (cleanChoice === "cancel") {
          creatorState.pendingContainerRemovalId =
            "";

          return false;
        }

        if (cleanChoice === "delete") {
          creatorState.draft
            .equipment
            .items =
              removeContainerAndContents(
                inventory,
                item.id
              );

          creatorState.pendingContainerRemovalId =
            "";

          if (
            creatorState.openContainerId ===
            item.id
          ) {
            creatorState.openContainerId = "";
          }

          markDraftChanged();

          return true;
        }

        if (cleanChoice !== "inventory") {
          creatorState.pendingContainerRemovalId =
            item.id;

          return "pending";
        }
      }

      creatorState.draft
        .equipment
        .items =
          removeContainerPreserveContents(
            inventory,
            item.id
          );

      creatorState.pendingContainerRemovalId =
        "";

      if (
        creatorState.openContainerId ===
        item.id
      ) {
        creatorState.openContainerId = "";
      }
    } else {
      inventory.splice(
        index,
        1
      );
    }

    markDraftChanged();

    return true;
  }

  function parseSection15ItemEditValue(
    field,
    rawValue,
    valueType,
    checked = false
  ) {
    if (valueType === "boolean") {
      return checked === true;
    }

    if (valueType === "integer") {
      return Math.max(
        1,
        Math.round(
          safeNumber(
            rawValue,
            1
          )
        )
      );
    }

    if (valueType === "number") {
      const nullableFields =
        new Set([
          "weight",
          "baseArmorClass",
          "dexterityCap",
          "capacityWeight"
        ]);

      if (
        nullableFields.has(field) &&
        cleanString(rawValue) === ""
      ) {
        return null;
      }

      return safeNumber(
        rawValue,
        0
      );
    }

    return safeDisplayString(
      rawValue
    );
  }

  function updateSection15InventoryItem(
    index,
    field,
    rawValue,
    valueType = "string",
    checked = false
  ) {
    const inventory =
      getSection15Inventory();

    const item =
      inventory[index];

    if (!item) {
      return false;
    }

    const editableFields =
      new Set([
        "name",
        "category",
        "quantity",
        "weight",
        "notes",
        "equipped",
        "isMagical",
        "requiresAttunement",
        "attuned",
        "magicalBonus",
        "armorCategory",
        "baseArmorClass",
        "dexterityCap",
        "isShield",
        "magicalArmorClassBonus",
        "weaponType",
        "attackAbility",
        "finesse",
        "ranged",
        "thrown",
        "proficient",
        "damageDice",
        "versatileDamageDice",
        "magicalAttackBonus",
        "magicalDamageBonus",
        "isContainer",
        "capacityWeight"
      ]);

    if (!editableFields.has(field)) {
      return false;
    }

    const nextValue =
      parseSection15ItemEditValue(
        field,
        rawValue,
        valueType,
        checked
      );

    if (
      field === "attuned" &&
      nextValue === true &&
      item.attuned !== true &&
      getSection15AttunedItemCount() >= 3
    ) {
      alert(
        "A character can normally attune to no more than three items."
      );

      return false;
    }

    if (
      field === "isContainer" &&
      item.isContainer === true &&
      nextValue !== true
    ) {
      inventory.forEach((candidate) => {
        if (
          cleanString(candidate.containerId) ===
          cleanString(item.id)
        ) {
          candidate.containerId = "";
        }
      });

      creatorState.pendingContainerRemovalId =
        "";
    }

    item[field] =
      nextValue;

    if (
      field === "attuned" &&
      nextValue === true
    ) {
      item.isMagical = true;
      item.requiresAttunement = true;
    }

    if (
      field === "requiresAttunement" &&
      nextValue === true
    ) {
      item.isMagical = true;
    }

    if (
      field === "isMagical" &&
      nextValue !== true
    ) {
      item.requiresAttunement = false;
      item.attuned = false;
    }

    if (
      field === "requiresAttunement" &&
      nextValue !== true
    ) {
      item.attuned = false;
    }

    if (
      field === "isShield" &&
      nextValue === true
    ) {
      item.category =
        item.category || "shield";

      item.armorCategory = "shield";
    }

    inventory[index] =
      normalizeSection15Item(
        item,
        item.source || "custom"
      );

    markDraftChanged();

    return true;
  }

  function changeSection15Quantity(
    index,
    amount
  ) {
    const inventory =
      getSection15Inventory();

    const item =
      inventory[index];

    if (!item) {
      return false;
    }

    const nextQuantity =
      Math.max(
        0,
        Math.round(
          safeNumber(
            item.quantity,
            1
          )
        ) +
        amount
      );

    if (nextQuantity <= 0) {
      inventory.splice(
        index,
        1
      );
    } else {
      item.quantity =
        nextQuantity;
    }

    markDraftChanged();

    return true;
  }

  function moveSection15ItemToContainer(
    index,
    targetContainerId,
    quantity = null
  ) {
    const inventory =
      getSection15Inventory();

    const item =
      inventory[index];

    if (!item) {
      return false;
    }

    const cleanTargetId =
      cleanString(targetContainerId);

    const currentQuantity =
      Math.max(
        1,
        Math.round(
          safeNumber(item.quantity, 1)
        )
      );

    const moveQuantity =
      quantity === null ||
      quantity === undefined ||
      quantity === ""
        ? currentQuantity
        : Math.max(
            1,
            Math.min(
              currentQuantity,
              Math.round(
                safeNumber(
                  quantity,
                  currentQuantity
                )
              )
            )
          );

    if (cleanTargetId) {
      const targetContainer =
        inventory.find((candidate) => {
          return (
            candidate.id === cleanTargetId &&
            candidate.isContainer === true
          );
        });

      if (!targetContainer) {
        return false;
      }

      if (
        wouldCreateContainerCycle(
          inventory,
          item.id,
          cleanTargetId
        )
      ) {
        alert(
          "That container move would create an invalid loop."
        );

        return false;
      }
    }

    const nextInventory =
      splitInventoryStack(
        inventory,
        item.id,
        moveQuantity,
        cleanTargetId
      );

    const targetSummary =
      cleanTargetId
        ? getContainerSummaries(
            nextInventory
          ).find((container) => {
            return (
              container.id ===
              cleanTargetId
            );
          })
        : null;

    if (
      targetSummary?.overCapacity
    ) {
      alert(
        "That move would exceed the container's known capacity."
      );

      return false;
    }

    creatorState.draft
      .equipment
      .items = nextInventory;

    markDraftChanged();

    return true;
  }

  function toggleSection15ItemState(
    index,
    property
  ) {
    const inventory =
      getSection15Inventory();

    const item =
      inventory[index];

    if (
      !item ||
      ![
        "equipped",
        "attuned"
      ].includes(property)
    ) {
      return false;
    }

    if (property === "attuned") {
      if (
        !item.isMagical ||
        !item.requiresAttunement
      ) {
        item.attuned = false;
        markDraftChanged();
        return false;
      }

      if (item.attuned === true) {
        item.attuned = false;
        markDraftChanged();
        return true;
      }

      if (getSection15AttunedItemCount() >= 3) {
        alert(
          "A character can normally attune to no more than three items."
        );

        return false;
      }

      item.attuned = true;
      markDraftChanged();
      return true;
    }

    if (
      property === "equipped" &&
      item.equipped !== true
    ) {
      if (item.isContainer === true) {
        item.equipped = false;
        markDraftChanged();
        return false;
      }

      if (cleanString(item.containerId)) {
        alert(
          "Move the item out of its container before equipping it."
        );

        return false;
      }

      if (item.isShield === true) {
        const otherShield =
          getSection15Inventory()
            .some((candidate, candidateIndex) => {
              return (
                candidateIndex !== index &&
                candidate.equipped === true &&
                candidate.isShield === true &&
                !cleanString(
                  candidate.containerId
                )
              );
            });

        if (otherShield) {
          alert(
            "Only one shield can provide an armor class bonus."
          );

          return false;
        }
      }
    }

    item[property] =
      item[property] !== true;

    markDraftChanged();

    return true;
  }

  function getSection15TotalWeight() {
    return getSection15Inventory()
      .reduce((total, item) => {
        if (
          item.weight === null ||
          item.weight === undefined ||
          item.weight === ""
        ) {
          return total;
        }

        return (
          total +
          Math.max(
            0,
            safeNumber(
              item.weight,
              0
            )
          ) *
          Math.max(
            1,
            Math.round(
              safeNumber(
                item.quantity,
                1
              )
            )
          )
        );
      }, 0);
  }

  function getSection15InventoryCount() {
    return getSection15Inventory()
      .reduce((total, item) => {
        return (
          total +
          Math.max(
            1,
            Math.round(
              safeNumber(
                item.quantity,
                1
              )
            )
          )
        );
      }, 0);
  }

  function getSection15AttunedItemCount() {
    return getSection15Inventory()
      .filter((item) => {
        return (
          item.isMagical === true &&
          item.requiresAttunement === true &&
          item.attuned === true
        );
      })
      .length;
  }

  function getSection15UnknownWeightCount() {
    return getSection15Inventory()
      .filter((item) => {
        return (
          item.weight === null ||
          item.weight === undefined ||
          item.weight === ""
        );
      })
      .length;
  }

  function renderSection15Catalog() {
    const catalog =
      getSection15Catalog();

    if (!catalog.length) {
      return `
        <div class="hg-character-placeholder">
          No equipment catalog items are available.
        </div>
      `;
    }

    return catalog
      .map((item) => {
        return wizardChoiceCard(
          item.name,

          `
            <p>
              <b>Category:</b>

              ${escapeHtml(
                item.category
              )}

              <br>

              <b>Default Quantity:</b>

              ${Math.max(
                1,
                Math.round(
                  safeNumber(
                    item.quantity,
                    1
                  )
                )
              )}

              <br>

              <b>Weight:</b>

              ${
                item.weight === null
                  ? "Not set"
                  : `${safeNumber(
                      item.weight,
                      0
                    )} lb. each`
              }
            </p>

            <p class="small">
              ${escapeHtml(
                item.notes ||
                "No notes."
              )}
            </p>
          `,

          "Add to Inventory",

          "add-catalog-item",

          {
            "item-id":
              item.id
          },

          false
        );
      })
      .join("");
  }

  function renderSection15ItemEditInput(
    item,
    index,
    label,
    field,
    options = {}
  ) {
    const id =
      `ccItemEdit-${index}-${field}`;

    const value =
      item[field] === null ||
      item[field] === undefined
        ? ""
        : item[field];

    return `
      <div
        class="hg-character-field${
          options.wide === true
            ? " hg-character-wide-field"
            : ""
        }"
      >
        <label for="${id}">
          ${escapeHtml(label)}
        </label>

        <input
          id="${id}"
          type="${escapeHtml(
            options.type || "text"
          )}"
          value="${escapeHtml(value)}"
          data-cc-action-change="update-inventory-item"
          data-index="${index}"
          data-item-field="${escapeHtml(field)}"
          data-value-type="${escapeHtml(
            options.valueType || "string"
          )}"
          ${options.extra || ""}
        >
      </div>
    `;
  }

  function renderSection15ItemEditTextarea(
    item,
    index,
    label,
    field
  ) {
    const id =
      `ccItemEdit-${index}-${field}`;

    return `
      <div class="hg-character-field hg-character-wide-field">
        <label for="${id}">
          ${escapeHtml(label)}
        </label>

        <textarea
          id="${id}"
          data-cc-action-change="update-inventory-item"
          data-index="${index}"
          data-item-field="${escapeHtml(field)}"
          data-value-type="string"
        >${escapeHtml(item[field] || "")}</textarea>
      </div>
    `;
  }

  function renderSection15ItemEditCheckbox(
    item,
    index,
    label,
    field
  ) {
    const id =
      `ccItemEdit-${index}-${field}`;

    return `
      <label class="hg-character-field">
        <input
          id="${id}"
          type="checkbox"
          data-cc-action-change="update-inventory-item"
          data-index="${index}"
          data-item-field="${escapeHtml(field)}"
          data-value-type="boolean"
          ${
            item[field] === true
              ? "checked"
              : ""
          }
        >

        ${escapeHtml(label)}
      </label>
    `;
  }

